def _safe_call(fn, *args, **kwargs):
    """Ejecuta una función capturando excepciones (para uso en ThreadPoolExecutor)"""
    try:
        return fn(*args, **kwargs)
    except Exception as e:
        logger.warning(f"_safe_call {fn.__name__}: {e}")
        return None

