def _calcular_embedding_simple(texto):
    import hashlib
    palabras = texto.lower().split()
    ngrams = palabras[:]
    for i in range(len(palabras)-1): ngrams.append(palabras[i]+' '+palabras[i+1])
    for i in range(len(palabras)-2): ngrams.append(palabras[i]+' '+palabras[i+1]+' '+palabras[i+2])
    vector = [0.0]*100
    for ng in ngrams:
        idx = int(hashlib.md5(ng.encode()).hexdigest(), 16) % 100
        vector[idx] += 1.0
    norma = sum(v*v for v in vector)**0.5
    return [v/norma for v in vector] if norma > 0 else vector

def _similitud_coseno(v1, v2):
    dot = sum(a*b for a,b in zip(v1,v2))
    n1 = sum(a*a for a in v1)**0.5; n2 = sum(b*b for b in v2)**0.5
    return dot/(n1*n2) if n1 and n2 else 0.0


# ═══════════════════════════════════════════════════════════════════════════
# FASE 29: EMBEDDINGS SEMÁNTICOS REALES CON GEMINI
# Reemplaza el hash MD5 con embeddings vectoriales reales de 768 dimensiones.
# Modelo: gemini-embedding-001 (gratis hasta 1.500 req/min en Google AI Studio)
# Documentación: https://ai.google.dev/gemini-api/docs/embeddings
# ═══════════════════════════════════════════════════════════════════════════

_EMBEDDING_CACHE = {}  # cache LRU simple para queries frecuentes
_EMBEDDING_CACHE_MAX = 500  # máximo en RAM
_EMBEDDING_STATS = {'hits': 0, 'misses': 0, 'failures': 0}

def generar_embedding_gemini(texto: str, tipo: str = 'RETRIEVAL_DOCUMENT'):
    """Genera un embedding vectorial real de 768 dimensiones usando Gemini.
    
    Args:
        texto: texto a embebir (máximo ~8000 chars / 2048 tokens)
        tipo: 'RETRIEVAL_DOCUMENT' para chunks indexados, 
              'RETRIEVAL_QUERY' para consultas del usuario
    
    Returns:
        list[float] con 768 valores normalizados, o None si falla.
        En caso de fallo, el llamador debe usar _calcular_embedding_simple() como fallback.
    """
    if not texto or not texto.strip():
        return None
    
    # Truncar texto muy largo (Gemini soporta ~2048 tokens ≈ 8000 chars)
    texto = texto.strip()
    if len(texto) > 8000:
        texto = texto[:8000]
    
    # Cache: queries repetidas no consumen API
    cache_key = f"{tipo}::{hash(texto)}"
    if cache_key in _EMBEDDING_CACHE:
        _EMBEDDING_STATS['hits'] += 1
        return _EMBEDDING_CACHE[cache_key]
    
    _EMBEDDING_STATS['misses'] += 1
    
    if not GEMINI_API_KEY:
        logger.debug("FASE 29: GEMINI_API_KEY no configurada, no se puede generar embedding")
        return None
    
    try:
        url = (f"https://generativelanguage.googleapis.com/v1beta/models/"
               f"text-embedding-004:embedContent?key={GEMINI_API_KEY}")
        payload = {
            "model": "models/text-embedding-004",
            "content": {"parts": [{"text": texto}]},
            "taskType": tipo,
            "outputDimensionality": 768,
        }
        resp = requests.post(url, json=payload, timeout=5)  # FASE 30.1: timeout 5s (era 15s) — embeddings deben ser rápidos
        if resp.status_code != 200:
            _EMBEDDING_STATS['failures'] += 1
            logger.warning(f"FASE 29: Gemini embedding HTTP {resp.status_code}: {resp.text[:200]}")
            return None
        
        data = resp.json()
        embedding = data.get('embedding', {}).get('values')
        if not embedding or len(embedding) != 768:
            _EMBEDDING_STATS['failures'] += 1
            logger.warning(f"FASE 29: Gemini embedding inválido (len={len(embedding) if embedding else 0})")
            return None
        
        # Guardar en cache (LRU simple)
        if len(_EMBEDDING_CACHE) >= _EMBEDDING_CACHE_MAX:
            # Eliminar el primer elemento (LRU básico)
            _EMBEDDING_CACHE.pop(next(iter(_EMBEDDING_CACHE)))
        _EMBEDDING_CACHE[cache_key] = embedding
        
        return embedding
    
    except Exception as e:
        _EMBEDDING_STATS['failures'] += 1
        logger.warning(f"FASE 29: Error generando embedding Gemini: {e}")
        return None


def embedding_to_pgvector(emb):
    """Convierte una lista de floats a formato pgvector '[0.1,0.2,...]'."""
    if not emb:
        return None
    return '[' + ','.join(f'{v:.6f}' for v in emb) + ']'


def stats_embeddings():
    """Estadísticas de uso del cache de embeddings."""
    total = _EMBEDDING_STATS['hits'] + _EMBEDDING_STATS['misses']
    hit_rate = (_EMBEDDING_STATS['hits'] / total * 100) if total > 0 else 0
    return {
        'hits': _EMBEDDING_STATS['hits'],
        'misses': _EMBEDDING_STATS['misses'],
        'failures': _EMBEDDING_STATS['failures'],
        'cache_size': len(_EMBEDDING_CACHE),
        'hit_rate': f"{hit_rate:.1f}%",
    }


def actualizar_embedding_perfil(user_id: int, conn=None) -> bool:
    """FASE 30: Genera/actualiza el embedding semántico del perfil profesional.
    
    Llamar después de crear o editar una tarjeta para que /conectar pueda hacer
    matching semántico real. El embedding se construye combinando:
    nombre + profesión + empresa + servicios + ciudad.
    
    Args:
        user_id: ID del usuario cuyo perfil se va a embebir
        conn: conexión opcional reutilizable; si es None se abre y cierra una nueva
    
    Returns:
        True si se actualizó exitosamente, False en caso contrario.
    """
    if not DATABASE_URL:
        return False  # SQLite no soporta pgvector
    
    cerrar_conn = False
    try:
        if conn is None:
            conn = get_db_connection()
            if not conn:
                return False
            cerrar_conn = True
        
        c = conn.cursor()
        c.execute(
            "SELECT nombre_completo, profesion, empresa, servicios, ciudad FROM tarjetas_profesional WHERE user_id = %s",
            (user_id,)
        )
        row = c.fetchone()
        if not row:
            return False
        
        # Construir texto combinado para el embedding (representación profesional completa)
        partes = []
        for campo in ['nombre_completo', 'profesion', 'empresa', 'servicios', 'ciudad']:
            v = row[campo] if DATABASE_URL else row[['nombre_completo', 'profesion', 'empresa', 'servicios', 'ciudad'].index(campo)]
            if v and str(v).strip():
                partes.append(str(v).strip())
        
        if not partes:
            return False
        
        texto_perfil = " · ".join(partes)
        
        # Generar embedding con Gemini
        emb = generar_embedding_gemini(texto_perfil, tipo='RETRIEVAL_DOCUMENT')
        if not emb:
            return False
        
        # Guardar en BD
        try:
            c.execute(
                "UPDATE tarjetas_profesional SET embedding_perfil = %s::vector WHERE user_id = %s",
                (embedding_to_pgvector(emb), user_id)
            )
            conn.commit()
            return True
        except Exception as _e_upd:
            logger.debug(f"FASE 30: error actualizando embedding_perfil de {user_id}: {_e_upd}")
            return False
    
    except Exception as e:
        logger.warning(f"FASE 30: error en actualizar_embedding_perfil: {e}")
        return False
    finally:
        if cerrar_conn and conn:
            try: conn.close()
            except: pass


def buscar_cofrades_por_similitud(query: str, limit: int = 5, threshold: float = 0.55):
    """FASE 30: Busca cofrades semánticamente similares a una consulta.
    
    Usado por /conectar para matching profesional inteligente con IA.
    Devuelve los cofrades cuyo perfil (profesión + empresa + servicios + ciudad)
    es semánticamente similar a la necesidad del usuario.
    
    Args:
        query: necesidad/búsqueda del usuario (ej: "busco asesor previsional")
        limit: máximo de resultados (default 5)
        threshold: similitud mínima 0..1 (default 0.55)
    
    Returns:
        lista de dicts con {user_id, nombre, profesion, empresa, ciudad, score}
        o lista vacía si no hay coincidencias o si pgvector no está disponible.
    """
    if not DATABASE_URL or not query or len(query.strip()) < 3:
        return []
    
    try:
        # Generar embedding de la query
        q_emb = generar_embedding_gemini(query.strip(), tipo='RETRIEVAL_QUERY')
        if not q_emb:
            return []
        
        conn = get_db_connection()
        if not conn:
            return []
        c = conn.cursor()
        
        try:
            c.execute(
                """SELECT user_id, nombre_completo, profesion, empresa, ciudad, telefono, email,
                          1 - (embedding_perfil <=> %s::vector) AS similitud
                   FROM tarjetas_profesional
                   WHERE embedding_perfil IS NOT NULL
                   ORDER BY embedding_perfil <=> %s::vector
                   LIMIT %s""",
                (embedding_to_pgvector(q_emb), embedding_to_pgvector(q_emb), limit * 2)
            )
            rows = c.fetchall()
        except Exception as _e_q:
            # pgvector no instalado o columna no existe
            logger.debug(f"FASE 30: búsqueda por similitud falló (cayendo a fallback): {_e_q}")
            conn.close()
            return []
        
        conn.close()
        
        # Filtrar por threshold
        resultados = []
        for r in rows:
            sim = float(r['similitud'] if DATABASE_URL else r[7])
            if sim < threshold:
                continue
            resultados.append({
                'user_id': r['user_id'] if DATABASE_URL else r[0],
                'nombre': r['nombre_completo'] if DATABASE_URL else r[1],
                'profesion': r['profesion'] if DATABASE_URL else r[2],
                'empresa': r['empresa'] if DATABASE_URL else r[3],
                'ciudad': r['ciudad'] if DATABASE_URL else r[4],
                'telefono': r['telefono'] if DATABASE_URL else r[5],
                'email': r['email'] if DATABASE_URL else r[6],
                'score': sim,
            })
            if len(resultados) >= limit:
                break
        
        return resultados
    
    except Exception as e:
        logger.warning(f"FASE 30: error en buscar_cofrades_por_similitud: {e}")
        return []


