# Configuración de voz
VOZ_TTS = os.environ.get('VOZ_TTS', 'es-CL-CatalinaNeural')  # Voz chilena femenina
GROQ_WHISPER_URL = "https://api.groq.com/openai/v1/audio/transcriptions"
GROQ_WHISPER_MODEL = "whisper-large-v3-turbo"

def transcribir_audio_groq(audio_bytes: bytes, filename: str = "audio.ogg") -> str:
    """Transcribe audio a texto usando Groq Whisper API"""
    if not GROQ_API_KEY:
        logger.warning("GROQ_API_KEY no disponible para Whisper")
        return None
    
    try:
        headers = {"Authorization": f"Bearer {GROQ_API_KEY}"}
        files = {
            'file': (filename, audio_bytes, 'audio/ogg'),
        }
        data = {
            'model': GROQ_WHISPER_MODEL,
            'language': 'es',  # Español
            'response_format': 'json',
            'temperature': 0.0,
            'prompt': 'Transcripción de mensaje de voz en español chileno sobre networking profesional.'
        }
        
        response = requests.post(GROQ_WHISPER_URL, headers=headers, files=files, data=data, timeout=30)
        
        if response.status_code == 200:
            resultado = response.json()
            texto = resultado.get('text', '').strip()
            if texto:
                logger.info(f"🎤 Whisper transcribió: {texto[:80]}...")
                return texto
            else:
                logger.warning("Whisper devolvió texto vacío")
                return None
        else:
            logger.error(f"Error Whisper API: {response.status_code} - {response.text[:200]}")
            return None
    except Exception as e:
        logger.error(f"Error transcribiendo audio: {e}")
        return None


async def generar_audio_tts(texto: str, filename: str = "/tmp/respuesta_tts.mp3") -> str:
    """Genera audio con voz natural — usa Chatterbox (HF) con fallback a edge-TTS
    
    FASE 10 (CRÍTICO): Detecta si tts_chatterbox.py tiene SSML y lo loguea visiblemente.
    Si tts_chatterbox.py es la versión vieja sin SSML, mostrará warning para que sepas
    que hay que actualizar el archivo en Render.
    
    FASE 22: pre-procesa números grandes (millones, miles) y abreviaturas comunes
    para evitar lecturas robóticas como 'cinco mil pesos millones de pesos'.
    """
    import re

    # FASE 23: aumentar límite a 5000 chars (Google TTS soporta hasta ~5000 sin problema)
    # Antes era 2000 y truncaba respuestas largas, dejándolas incompletas en audio.
    if len(texto) > 5000:
        # Truncar en el último punto antes del límite para no cortar oraciones
        cortar_en = texto.rfind('.', 0, 4990)
        if cortar_en > 4000:
            texto = texto[:cortar_en + 1]
        else:
            texto = texto[:4997] + "..."

    # Limpiar emojis y símbolos
    texto_voz = re.sub(r'[📊📈📉💰🪙🏅🏆⭐🔵🟢⚪💬💡📱📧🔗📇💎📋📅🔔📢🎂🎉👤👥🎤🔍💼🏢📍🛠️✅❌⏰♾️✏️━═⚓]', '', texto)
    texto_voz = re.sub(r'[#*_~`|]', '', texto_voz)
    
    # ═══ FASE 22: NORMALIZACIÓN DE NÚMEROS PARA TTS ═══
    # Problema: "$5.000 millones de pesos" se leía como "cinco mil pesos millones de pesos"
    # porque el TTS de Google leía "$5.000" → "cinco mil pesos" (Chile usa . como separador
    # de miles), y luego "millones de pesos" se sumaba al final.
    # Solución: detectar patrones "$<num> millones/mil millones/billones" y reescribirlos
    # como "<num> millones/mil millones/billones de pesos" sin el símbolo $ confuso.
    
    # Patrón 1: $X[.XXX]+ millones/billones de pesos → "X millones de pesos"
    # Ejemplo: "$5.000 millones de pesos" → "5000 millones de pesos"
    def _limpiar_cifra(match):
        cifra = match.group(1)
        magnitud = match.group(2)
        sufijo = match.group(3) or ''
        # Quitar puntos separadores de miles (estilo CL/EU)
        # Pero conservar coma decimal si la hubiera
        cifra_limpia = cifra.replace('.', '')
        return f"{cifra_limpia} {magnitud}{sufijo}"
    
    # "$5.000 millones de pesos" o "$5 millones de USD" o "$5.000 mil millones de dólares"
    texto_voz = re.sub(
        r'\$\s*([\d.,]+)\s+(mil\s+millones|millones|billones|mil)(\s+de\s+(?:pesos|d[óo]lares|USD|UF|euros))?',
        _limpiar_cifra,
        texto_voz,
        flags=re.IGNORECASE
    )
    
    # Patrón 2: cifras con $ y separadores de miles SIN sufijo de magnitud
    # "$1.234.567" → "1234567 pesos"  (para que Google diga el número correcto)
    # "$50.000" → "50000 pesos"
    def _limpiar_cifra_simple(match):
        cifra = match.group(1)
        # Solo reemplazar si tiene múltiples puntos (separadores de miles) o solo dígitos
        # NO tocar decimales como "$50.5" (50 punto 5)
        partes = cifra.split('.')
        if len(partes) >= 2 and all(len(p) == 3 for p in partes[1:]):
            # Es separador de miles: "1.234.567" o "50.000"
            cifra_limpia = cifra.replace('.', '')
            return f"{cifra_limpia} pesos"
        return match.group(0)  # mantener original (decimal)
    
    texto_voz = re.sub(r'\$\s*([\d.]+)(?!\s*(?:mil|millones|billones))', _limpiar_cifra_simple, texto_voz)
    
    # Patrón 3: porcentajes con coma decimal: "4,50%" → "4 coma 50 por ciento"
    texto_voz = re.sub(r'(\d+),(\d+)\s*%', r'\1 coma \2 por ciento', texto_voz)
    texto_voz = re.sub(r'(\d+)\s*%', r'\1 por ciento', texto_voz)
    
    # Patrón 4: rangos de fechas y horas
    texto_voz = re.sub(r'(\d{4})-(\d{2})-(\d{2})', r'\3 del \2 del \1', texto_voz)
    
    # ═══ FASE 22: NORMALIZACIÓN DE ABREVIATURAS COMUNES ═══
    abreviaturas = {
        # Económicas / financieras
        r'\bUSD\b': 'dólares',
        r'\bUF\b': 'unidades de fomento',
        r'\bUTM\b': 'unidad tributaria mensual',
        r'\bIPC\b': 'índice de precios al consumidor',
        r'\bIPSA\b': 'I P S A',
        r'\bTPM\b': 'tasa de política monetaria',
        r'\bIMACEC\b': 'I M A C E C',
        r'\bPIB\b': 'producto interno bruto',
        r'\bROI\b': 'retorno de inversión',
        r'\bROE\b': 'retorno sobre capital',
        r'\bEBITDA\b': 'EBITDA',
        r'\bCMF\b': 'comisión para el mercado financiero',
        r'\bSII\b': 'S I I',
        r'\bAFP\b': 'A F P',
        r'\bBC\b': 'Banco Central',
        r'\bBCCh\b': 'Banco Central de Chile',
        r'\bBTC\b': 'bitcoin',
        r'\bETH\b': 'ethereum',
        r'\bSOL\b': 'solana',
        r'\bUSA\b': 'Estados Unidos',
        r'\bEEUU\b': 'Estados Unidos',
        r'\bEE\.UU\.': 'Estados Unidos',
        # Profesionales / militares
        r'\bKDT\b': 'cadete',
        r'\bMSc\b': 'magíster',
        r'\bPhD\b': 'doctor',
        r'\bMBA\b': 'M B A',
        r'\bRRHH\b': 'recursos humanos',
        r'\bTI\b': 'tecnologías de la información',
        r'\bCEO\b': 'C E O',
        r'\bCFO\b': 'C F O',
        r'\bCTO\b': 'C T O',
        r'\bCOO\b': 'C O O',
        # Cofradía-específicas
        r'\bIA\b': 'inteligencia artificial',
        r'\bRAG\b': 'R A G',
        r'\bAPI\b': 'A P I',
        r'\bLLM\b': 'L L M',
        # Comunes en español
        r'\bSr\.\s+': 'Señor ',
        r'\bSra\.\s+': 'Señora ',
        r'\bDr\.\s+': 'Doctor ',
        r'\bDra\.\s+': 'Doctora ',
        r'\bIng\.\s+': 'Ingeniero ',
        r'\bArq\.\s+': 'Arquitecto ',
        r'\bLic\.\s+': 'Licenciado ',
        r'\bAv\.\s+': 'Avenida ',
        r'\bN[°º]\s+': 'número ',
        r'\bnúm\.\s+': 'número ',
        r'\bp\.\s*ej\.': 'por ejemplo',
        r'\bp\.\s*ext\.': 'por extensión',
    }
    for patron, reemplazo in abreviaturas.items():
        texto_voz = re.sub(patron, reemplazo, texto_voz, flags=re.IGNORECASE if patron.startswith(r'\bSr') else 0)
    
    texto_voz = texto_voz.replace(' ej:', ', por ejemplo:')
    texto_voz = texto_voz.replace(' Ej:', ', por ejemplo:')
    texto_voz = texto_voz.replace(' etc.', ', etcétera.')
    texto_voz = texto_voz.replace(' vs ', ' versus ')
    texto_voz = re.sub(r'\s+', ' ', texto_voz).strip()

    # ── INTENTO 1: Google TTS via tts_chatterbox (Neural2-A + SSML, ÚNICA voz oficial) ──
    # FASE 12: ELIMINADO el fallback edge-tts/Catalina de bot.py.
    # Razón: cuando Google fallaba, edge-tts producía Catalina (voz robotizada).
    # Ahora el fallback edge-tts solo existe DENTRO de tts_chatterbox.py si
    # GOOGLE_TTS_KEY no está configurada. Como SÍ está configurada, NUNCA debería caer ahí.
    try:
        from tts_chatterbox import texto_a_voz
        # FASE 10: Detectar si el módulo tiene SSML y loguear (1 sola vez por proceso)
        global _FASE10_SSML_CHECK_DONE
        if not globals().get('_FASE10_SSML_CHECK_DONE'):
            try:
                import tts_chatterbox as _tts_mod
                _has_ssml = hasattr(_tts_mod, 'USE_SSML') or hasattr(_tts_mod, '_texto_a_ssml')
                _ssml_env = os.getenv('GOOGLE_TTS_SSML', '<no_set>')
                logger.warning(f"━━━ [FASE 10] TTS DIAGNOSTIC ━━━")
                logger.warning(f"  tts_chatterbox.py tiene código SSML: {_has_ssml}")
                logger.warning(f"  GOOGLE_TTS_SSML env var: '{_ssml_env}'")
                if not _has_ssml:
                    logger.warning(f"  ⚠️ ATENCIÓN: tts_chatterbox.py NO tiene SSML.")
                    logger.warning(f"  ⚠️ Hay que actualizar tts_chatterbox.py en Render para activar SSML.")
                else:
                    use_ssml_val = getattr(_tts_mod, 'USE_SSML', None)
                    logger.warning(f"  USE_SSML detectado en módulo: {use_ssml_val}")
                logger.warning(f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━")
                _FASE10_SSML_CHECK_DONE = True
                globals()['_FASE10_SSML_CHECK_DONE'] = True
            except Exception as _e_diag:
                logger.warning(f"FASE 10 diagnóstico TTS: {_e_diag}")
        
        audio_bytes = await texto_a_voz(texto_voz, estilo="normal")
        if audio_bytes:
            # Guardar bytes en archivo temporal
            ext = ".ogg" if audio_bytes[:4] == b'OggS' or audio_bytes[:4] != b'RIFF' else ".wav"
            fname = filename.replace(".mp3", ext)
            with open(fname, "wb") as f:
                f.write(audio_bytes)
            if os.path.getsize(fname) > 0:
                logger.info(f"🎙️ Audio generado: {os.path.getsize(fname)} bytes (Google TTS Neural2-A + SSML)")
                return fname
    except Exception as e:
        logger.error(f"❌ tts_chatterbox falló: {e}")
        # NO caer a edge-tts en bot.py: si tts_chatterbox falló, devolver None
        # para que el bot envíe respuesta SIN audio en lugar de audio robotizado
    
    # FASE 12: Si Google TTS falla, NO generar audio (evita Catalina robótica)
    logger.warning("⚠️ TTS no disponible — respuesta enviada sin audio")
    return None


