async def _enviar_respuesta_con_audio(update, texto_respuesta_completa, texto_para_audio=None, tag_tts='respuesta'):
    """
    Helper que envia una respuesta por TEXTO + AUDIO.
    
    Args:
        update: el objeto Update de Telegram
        texto_respuesta_completa: texto que se envia como mensaje de Telegram (puede ser largo)
        texto_para_audio: texto que se convierte a voz (si None, usa texto_respuesta_completa)
                          Debe ser mas corto para el audio (maximo 1500 chars recomendado)
        tag_tts: etiqueta identificadora para el archivo y logs
    
    Comportamiento:
        - Siempre envia el texto (no falla)
        - Genera y envia audio si es posible (silenciosamente falla si TTS no funciona)
        - Nunca rompe el flujo del comando aunque el TTS falle
    """
    # PASO 1: Enviar siempre el texto (esto es lo principal)
    try:
        await enviar_mensaje_largo(update, texto_respuesta_completa)
    except Exception as _e_txt:
        logger.warning(f"Error enviando texto de respuesta: {_e_txt}")
        # Si ni siquiera el texto pudo enviarse, no hay nada que hacer
        return
    
    # PASO 2: Generar y enviar audio (best-effort, silencioso si falla)
    if not texto_para_audio:
        texto_para_audio = texto_respuesta_completa
    
    # FASE 25: aumentar límite TTS a 5000 chars para audios COMPLETOS
    # (antes truncaba a 1500 dejando audios cortos vs respuesta texto)
    # Google Cloud TTS soporta hasta 5000 chars sin problema.
    if len(texto_para_audio) > 5000:
        # Cortar en último punto antes del límite
        corte = texto_para_audio.rfind('.', 0, 4990)
        if corte > 4000:
            texto_para_audio = texto_para_audio[:corte + 1]
        else:
            texto_para_audio = texto_para_audio[:4997] + "..."
    
    # No generar audio para respuestas muy cortas (<40 chars, no vale la pena)
    if len(texto_para_audio.strip()) < 40:
        return
    
    try:
        uid = update.effective_user.id if update.effective_user else 0
        filename = f"/tmp/{tag_tts}_{uid}.mp3"
        audio_path = await generar_audio_tts(texto_para_audio, filename)
        if audio_path and os.path.exists(audio_path):
            with open(audio_path, 'rb') as af:
                await update.message.reply_voice(voice=af)
            try: os.remove(audio_path)
            except: pass
    except Exception as _e_tts:
        # Silencioso: el usuario ya tiene el texto, no necesita saber que fallo el audio
        logger.debug(f"TTS {tag_tts}: {_e_tts}")


def detectar_comando_por_voz(texto_transcrito: str):
    """Detecta si el texto transcrito contiene 'comando [nombre]' y extrae argumentos.
    Whisper transcribe con puntuación: 'Cofradía Bot, Comando, Resumen, Mes.'
    Debemos limpiar comas, puntos, etc. antes de buscar.
    Returns: (nombre_comando, argumentos) o None"""
    
    # PASO 1: Limpiar TODA la puntuación que Whisper agrega
    texto_limpio = texto_transcrito.lower().strip()
    texto_limpio = re.sub(r'[,.:;!?¿¡\-–—\"\'()…]', ' ', texto_limpio)  # Reemplazar puntuación por espacios
    texto_limpio = re.sub(r'\s+', ' ', texto_limpio).strip()  # Colapsar espacios múltiples
    
    # PASO 2: Detectar la palabra "comando" en cualquier posición
    prefijos = [
        'cofradía bot comando ', 'cofradia bot comando ',
        'cofradía comando ', 'cofradia comando ',
        'bot comando ', 'comando ', 'commando ',
        'ejecuta comando ', 'ejecutar comando ',
        'ejecuta ', 'ejecutar '
    ]
    
    texto_sin_prefijo = None
    for prefijo in prefijos:
        if prefijo in texto_limpio:
            idx = texto_limpio.index(prefijo) + len(prefijo)
            texto_sin_prefijo = texto_limpio[idx:].strip()
            break
    
    if not texto_sin_prefijo:
        return None
    
    # PASO 3: Buscar el comando más largo que coincida (greedy match)
    mejor_match = None
    mejor_longitud = 0
    
    for voz_cmd, real_cmd in COMANDOS_VOZ.items():
        if texto_sin_prefijo.startswith(voz_cmd):
            if len(voz_cmd) > mejor_longitud:
                mejor_longitud = len(voz_cmd)
                argumentos = texto_sin_prefijo[len(voz_cmd):].strip()
                mejor_match = (real_cmd, argumentos)
    
    # PASO 4: Si no hubo match exacto, intentar match flexible (palabras individuales)
    if not mejor_match:
        palabras_restantes = texto_sin_prefijo.split()
        if palabras_restantes:
            # Intentar con 1 palabra, luego 2, luego 3
            for n_palabras in [3, 2, 1]:
                if len(palabras_restantes) >= n_palabras:
                    intento = ' '.join(palabras_restantes[:n_palabras])
                    if intento in COMANDOS_VOZ:
                        real_cmd = COMANDOS_VOZ[intento]
                        argumentos = ' '.join(palabras_restantes[n_palabras:]).strip()
                        mejor_match = (real_cmd, argumentos)
                        break
    
    if mejor_match:
        logger.info(f"🎤 Comando por voz detectado: /{mejor_match[0]} {mejor_match[1]} (de: '{texto_transcrito[:80]}')")
    
    return mejor_match


