# ═══════════════════════════════════════════════════════════════════════════
# FASE 29: COMANDO /rag_reindexar_embeddings
# Procesa los chunks existentes en rag_chunks y les genera embeddings con
# Gemini text-embedding-004 (768 dim). No re-indexa los PDFs, solo agrega
# los embeddings que faltan. Procesa en lotes de 50 con progreso visible.
# ═══════════════════════════════════════════════════════════════════════════
async def rag_reindexar_embeddings_comando(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Comando /rag_reindexar_embeddings - Genera embeddings Gemini para chunks existentes."""
    user_id = update.effective_user.id
    
    if user_id != OWNER_ID:
        await update.message.reply_text("❌ Solo el administrador puede re-indexar embeddings.")
        return
    
    if not DATABASE_URL:
        await update.message.reply_text("⚠️ Esta operación solo funciona con PostgreSQL (Supabase).")
        return
    
    if not GEMINI_API_KEY:
        await update.message.reply_text("⚠️ GEMINI_API_KEY no configurada. No se pueden generar embeddings.")
        return
    
    msg = await update.message.reply_text(
        "🔄 <b>Reprocesando embeddings semánticos</b>\n"
        "━━━━━━━━━━━━━━━━━━━━\n\n"
        "⏳ Contando chunks pendientes...",
        parse_mode='HTML'
    )
    
    try:
        conn = get_db_connection()
        c = conn.cursor()
        
        # Verificar que la columna embedding existe
        try:
            c.execute("SELECT COUNT(*) AS total FROM rag_chunks WHERE embedding IS NULL")
            total_pendientes = (c.fetchone()['total'] if DATABASE_URL else c.fetchone()[0])
        except Exception as _e_col:
            await msg.edit_text(
                "❌ <b>Columna embedding no encontrada</b>\n\n"
                "La extensión pgvector parece no estar habilitada. "
                "Verifica que en Supabase esté instalada la extensión 'vector' "
                "en Dashboard → Database → Extensions.\n\n"
                f"<code>Error: {str(_e_col)[:200]}</code>",
                parse_mode='HTML'
            )
            conn.close()
            return
        
        if total_pendientes == 0:
            c.execute("SELECT COUNT(*) AS total FROM rag_chunks WHERE embedding IS NOT NULL")
            total_con_emb = (c.fetchone()['total'] if DATABASE_URL else c.fetchone()[0])
            await msg.edit_text(
                f"✅ <b>Todos los chunks ya tienen embeddings</b>\n"
                f"━━━━━━━━━━━━━━━━━━━━\n\n"
                f"📊 Total con embedding: {total_con_emb}\n\n"
                f"<em>El sistema ya está optimizado para búsqueda semántica real.</em>",
                parse_mode='HTML'
            )
            conn.close()
            return
        
        await msg.edit_text(
            f"🔄 <b>Reprocesando embeddings</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"📊 Chunks pendientes: <b>{total_pendientes}</b>\n"
            f"⏱️ Tiempo estimado: ~{max(1, total_pendientes // 60)} min\n\n"
            f"<em>Procesando en lotes de 50...</em>",
            parse_mode='HTML'
        )
        
        # Procesar en lotes de 50
        procesados = 0
        fallidos = 0
        loop = asyncio.get_running_loop()
        ultimo_update_msg = time.time()
        
        while procesados + fallidos < total_pendientes:
            try:
                c.execute(
                    "SELECT id, chunk_text FROM rag_chunks WHERE embedding IS NULL LIMIT 50"
                )
                lote = c.fetchall()
                if not lote:
                    break
                
                for row in lote:
                    chunk_id = row['id'] if DATABASE_URL else row[0]
                    chunk_text = row['chunk_text'] if DATABASE_URL else row[1]
                    
                    if not chunk_text:
                        fallidos += 1
                        continue
                    
                    # Generar embedding (en thread pool para no bloquear)
                    emb = await loop.run_in_executor(
                        None,
                        generar_embedding_gemini,
                        chunk_text[:8000],
                        'RETRIEVAL_DOCUMENT'
                    )
                    
                    if emb:
                        try:
                            c.execute(
                                "UPDATE rag_chunks SET embedding = %s::vector WHERE id = %s",
                                (embedding_to_pgvector(emb), chunk_id)
                            )
                            procesados += 1
                        except Exception as _e_upd:
                            logger.warning(f"FASE 29: error update embedding chunk {chunk_id}: {_e_upd}")
                            fallidos += 1
                    else:
                        fallidos += 1
                    
                    # Pequeña pausa para no saturar Gemini (1500 req/min = ~40ms entre llamadas)
                    await asyncio.sleep(0.05)
                
                conn.commit()
                
                # Actualizar mensaje cada 5 segundos
                if time.time() - ultimo_update_msg > 5:
                    porcentaje = (procesados + fallidos) / total_pendientes * 100
                    await msg.edit_text(
                        f"🔄 <b>Reprocesando embeddings</b>\n"
                        f"━━━━━━━━━━━━━━━━━━━━\n\n"
                        f"📊 Progreso: <b>{procesados + fallidos} / {total_pendientes}</b> ({porcentaje:.1f}%)\n"
                        f"✅ Procesados: {procesados}\n"
                        f"⚠️ Fallidos: {fallidos}\n\n"
                        f"<em>Continuando...</em>",
                        parse_mode='HTML'
                    )
                    ultimo_update_msg = time.time()
            
            except Exception as _e_lote:
                logger.error(f"FASE 29: error procesando lote: {_e_lote}")
                fallidos += 50  # asumimos todo el lote falló
        
        # Crear/recrear índice HNSW ahora que hay datos
        try:
            c.execute("CREATE INDEX IF NOT EXISTS idx_rag_embedding ON rag_chunks USING hnsw (embedding vector_cosine_ops)")
            conn.commit()
            logger.info("FASE 29: índice HNSW creado/verificado")
        except Exception as _e_idx:
            logger.warning(f"FASE 29: índice HNSW: {_e_idx}")
        
        conn.close()
        
        # Estadísticas finales
        stats_emb = stats_embeddings()
        await msg.edit_text(
            f"✅ <b>Embeddings completados</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"✅ Procesados exitosos: <b>{procesados}</b>\n"
            f"⚠️ Fallidos: {fallidos}\n"
            f"📊 Cache hit rate: {stats_emb['hit_rate']}\n"
            f"🚀 Índice HNSW: creado\n\n"
            f"<em>El sistema ahora usa búsqueda semántica real. "
            f"Prueba /rag_consulta o /buscar_ia para ver la diferencia.</em>",
            parse_mode='HTML'
        )
    
    except Exception as e:
        logger.error(f"FASE 29: error en /rag_reindexar_embeddings: {e}", exc_info=True)
        await msg.edit_text(
            f"❌ <b>Error reprocesando embeddings</b>\n\n"
            f"<code>{str(e)[:300]}</code>",
            parse_mode='HTML'
        )


# ═══════════════════════════════════════════════════════════════════════════
# FASE 30: COMANDO /rag_reindexar_perfiles
# Genera embeddings semánticos para todos los perfiles existentes en
# tarjetas_profesional. Después de ejecutarlo, /conectar funcionará con
# matching semántico real.
# ═══════════════════════════════════════════════════════════════════════════
async def rag_reindexar_perfiles_comando(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Comando /rag_reindexar_perfiles - Genera embeddings semánticos de tarjetas profesionales."""
    user_id = update.effective_user.id
    
    if user_id != OWNER_ID:
        await update.message.reply_text("❌ Solo el administrador puede re-indexar perfiles.")
        return
    
    if not DATABASE_URL:
        await update.message.reply_text("⚠️ Esta operación solo funciona con PostgreSQL (Supabase).")
        return
    
    if not GEMINI_API_KEY:
        await update.message.reply_text("⚠️ GEMINI_API_KEY no configurada. No se pueden generar embeddings.")
        return
    
    msg = await update.message.reply_text(
        "🔄 <b>Generando embeddings de perfiles profesionales</b>\n"
        "━━━━━━━━━━━━━━━━━━━━\n\n"
        "⏳ Contando perfiles pendientes...",
        parse_mode='HTML'
    )
    
    try:
        conn = get_db_connection()
        c = conn.cursor()
        
        # Verificar columna embedding_perfil
        try:
            c.execute("SELECT COUNT(*) AS total FROM tarjetas_profesional WHERE embedding_perfil IS NULL")
            total_pendientes = (c.fetchone()['total']) or 0
        except Exception as _e_col:
            await msg.edit_text(
                "❌ <b>Columna embedding_perfil no encontrada</b>\n\n"
                "Posibles causas:\n"
                "1. La extensión pgvector no está habilitada en Supabase\n"
                "2. El bot no se ha redespliegado después de FASE 30\n\n"
                f"<code>Error: {str(_e_col)[:200]}</code>",
                parse_mode='HTML'
            )
            conn.close()
            return
        
        if total_pendientes == 0:
            c.execute("SELECT COUNT(*) AS total FROM tarjetas_profesional WHERE embedding_perfil IS NOT NULL")
            total_con_emb = (c.fetchone()['total']) or 0
            await msg.edit_text(
                f"✅ <b>Todos los perfiles ya tienen embeddings</b>\n"
                f"━━━━━━━━━━━━━━━━━━━━\n\n"
                f"📊 Total perfiles con embedding: {total_con_emb}\n\n"
                f"<em>El sistema /conectar ya usa matching semántico real con IA.</em>\n"
                f"<em>Prueba: <code>/conectar busco asesor previsional</code></em>",
                parse_mode='HTML'
            )
            conn.close()
            return
        
        await msg.edit_text(
            f"🔄 <b>Procesando perfiles</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"📊 Perfiles pendientes: <b>{total_pendientes}</b>\n"
            f"⏱️ Tiempo estimado: ~{max(1, total_pendientes // 60)} min\n\n"
            f"<em>Esto sucede una sola vez. Los nuevos perfiles se procesan al crearse.</em>",
            parse_mode='HTML'
        )
        
        # Procesar uno por uno (los perfiles son pocos en comparación a chunks)
        c.execute("SELECT user_id FROM tarjetas_profesional WHERE embedding_perfil IS NULL")
        usuarios_pendientes = [(r['user_id']) for r in c.fetchall()]
        
        procesados = 0
        fallidos = 0
        loop = asyncio.get_running_loop()
        ultimo_update_msg = time.time()
        
        for uid in usuarios_pendientes:
            try:
                # actualizar_embedding_perfil maneja todo: lectura BD, generación embedding, update
                exito = await loop.run_in_executor(None, actualizar_embedding_perfil, uid)
                if exito:
                    procesados += 1
                else:
                    fallidos += 1
                
                # Pausa pequeña para no saturar Gemini
                await asyncio.sleep(0.05)
                
                # Actualizar progreso cada 3 segundos
                if time.time() - ultimo_update_msg > 3:
                    pct = (procesados + fallidos) / total_pendientes * 100
                    await msg.edit_text(
                        f"🔄 <b>Procesando perfiles</b>\n"
                        f"━━━━━━━━━━━━━━━━━━━━\n\n"
                        f"📊 Progreso: <b>{procesados + fallidos} / {total_pendientes}</b> ({pct:.1f}%)\n"
                        f"✅ Procesados: {procesados}\n"
                        f"⚠️ Fallidos: {fallidos}\n",
                        parse_mode='HTML'
                    )
                    ultimo_update_msg = time.time()
            except Exception as _e_indv:
                logger.warning(f"FASE 30: error procesando perfil {uid}: {_e_indv}")
                fallidos += 1
        
        # Crear/recrear índice HNSW
        try:
            c.execute("CREATE INDEX IF NOT EXISTS idx_tarjetas_embedding ON tarjetas_profesional USING hnsw (embedding_perfil vector_cosine_ops)")
            conn.commit()
            logger.info("FASE 30: índice HNSW de perfiles creado/verificado")
        except Exception as _e_idx_p:
            logger.warning(f"FASE 30: índice HNSW perfiles: {_e_idx_p}")
        
        conn.close()
        
        await msg.edit_text(
            f"✅ <b>Embeddings de perfiles completados</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"✅ Procesados exitosos: <b>{procesados}</b>\n"
            f"⚠️ Fallidos: {fallidos}\n"
            f"🚀 Índice HNSW: creado\n\n"
            f"<b>¿Qué cambió?</b>\n"
            f"El comando /conectar ahora hace matching semántico real con IA.\n\n"
            f"<b>Prueba estos ejemplos:</b>\n"
            f"  • <code>/conectar busco asesor previsional</code>\n"
            f"  • <code>/conectar necesito experto en comercio exterior</code>\n"
            f"  • <code>/conectar quien sabe de gestión portuaria</code>",
            parse_mode='HTML'
        )
    
    except Exception as e:
        logger.error(f"FASE 30: error en /rag_reindexar_perfiles: {e}", exc_info=True)
        await msg.edit_text(
            f"❌ <b>Error reprocesando perfiles</b>\n\n"
            f"<code>{str(e)[:300]}</code>",
            parse_mode='HTML'
        )


async def eliminar_pdf_comando(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Comando /eliminar_pdf [nombre] - Elimina un PDF del RAG (solo owner)"""
    user_id = update.effective_user.id
    
    if user_id != OWNER_ID:
        await update.message.reply_text("❌ Solo el administrador puede eliminar PDFs.")
        return
    
    if not context.args:
        # Listar PDFs disponibles desde BD (paginado)
        pdfs = listar_pdfs_rag()
        if not pdfs:
            await update.message.reply_text("📁 No hay PDFs indexados en el sistema RAG")
            return
        
        # Construir lista paginada
        paginas = []
        pagina_actual = f"📁 PDFs indexados ({len(pdfs)} total)\n\n"
        
        for i, pdf in enumerate(pdfs, 1):
            chunks = pdf.get('chunks', '?')
            origen = pdf.get('origen', '')
            linea = f"{i}. {pdf['name']} ({chunks} ch) [{origen}]\n"
            
            if len(pagina_actual) + len(linea) > 3800:
                paginas.append(pagina_actual)
                pagina_actual = f"📁 PDFs (cont. pag {len(paginas)+1})\n\n"
            pagina_actual += linea
        
        pagina_actual += "\n💡 Uso: /eliminar_pdf [nombre exacto]"
        paginas.append(pagina_actual)
        
        for pagina in paginas:
            try:
                await update.message.reply_text(pagina)
            except Exception as e:
                logger.warning(f"Error enviando lista PDFs: {e}")
        return
    
    filename = ' '.join(context.args)
    
    try:
        chunks_eliminados = 0
        
        # PASO 1: Eliminar chunks del RAG en la BD (principal)
        conn = get_db_connection()
        if conn:
            c = conn.cursor()
            # Buscar con diferentes formatos de source
            for source_pattern in [filename, f"PDF:{filename}"]:
                if DATABASE_URL:
                    c.execute("DELETE FROM rag_chunks WHERE source = %s", (source_pattern,))
                else:
                    c.execute("DELETE FROM rag_chunks WHERE source = ?", (source_pattern,))
                chunks_eliminados += c.rowcount
            conn.commit()
            conn.close()
        
        if chunks_eliminados == 0:
            await update.message.reply_text(f"❌ No se encontró: {filename}\n\nUsa /eliminar_pdf sin argumentos para ver la lista.")
            return
        
        # PASO 2: Intentar eliminar de Drive (opcional)
        drive_status = ""
        try:
            headers = obtener_drive_auth_headers()
            if headers:
                rag_folder_id = obtener_carpeta_rag_pdf()
                if rag_folder_id:
                    query = f"name = '{filename}' and '{rag_folder_id}' in parents and trashed = false"
                    search_url = "https://www.googleapis.com/drive/v3/files"
                    params = {'q': query, 'fields': 'files(id, name)'}
                    resp = requests.get(search_url, headers=headers, params=params, timeout=30)
                    archivos = resp.json().get('files', [])
                    
                    if archivos:
                        file_id = archivos[0]['id']
                        delete_url = f"https://www.googleapis.com/drive/v3/files/{file_id}"
                        resp = requests.patch(delete_url, headers={**headers, 'Content-Type': 'application/json'},
                                            json={'trashed': True}, timeout=30)
                        if resp.status_code == 200:
                            drive_status = "\n☁️ También eliminado de Google Drive"
        except Exception as e:
            logger.warning(f"Error eliminando de Drive: {e}")
        
        await update.message.reply_text(
            f"✅ PDF eliminado: {filename}\n"
            f"🧩 {chunks_eliminados} chunks RAG eliminados{drive_status}"
        )
        
    except Exception as e:
        logger.error(f"Error eliminando PDF: {e}")
        await update.message.reply_text(f"❌ Error: {str(e)[:200]}")


# ==================== FUNCIÓN AUXILIAR: OBTENER DATOS EXCEL DRIVE ====================

def obtener_datos_excel_drive(sheet_name=0):
    """Obtiene DataFrame completo del Excel de Google Drive para análisis"""
    try:
        from oauth2client.service_account import ServiceAccountCredentials
        
        creds_json = os.environ.get('GOOGLE_DRIVE_CREDS')
        if not creds_json:
            return None
        
        creds_dict = json.loads(creds_json)
        scope = ['https://www.googleapis.com/auth/drive.readonly']
        creds = ServiceAccountCredentials.from_json_keyfile_dict(creds_dict, scope)
        access_token = creds.get_access_token().access_token
        headers = {'Authorization': f'Bearer {access_token}'}
        
        search_url = "https://www.googleapis.com/drive/v3/files"
        params = {
            'q': "name contains 'BD Grupo Laboral' and mimeType='application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' and trashed=false",
            'fields': 'files(id, name)'
        }
        
        response = requests.get(search_url, headers=headers, params=params, timeout=30)
        archivos = response.json().get('files', [])
        
        if not archivos:
            return None
        
        file_id = archivos[0]['id']
        download_url = f"https://www.googleapis.com/drive/v3/files/{file_id}?alt=media"
        response = requests.get(download_url, headers=headers, timeout=60)
        
        if response.status_code != 200:
            return None
        
        df = pd.read_excel(BytesIO(response.content), engine='openpyxl', header=0, sheet_name=sheet_name)
        return df
        
    except Exception as e:
        logger.error(f"Error obteniendo datos Excel Drive (sheet={sheet_name}): {e}")
        return None


# ==================== SISTEMA DE BACKUP BD A SUPABASE STORAGE ====================
# Hace backup diario de las 3 tablas criticas (mensajes + suscripciones + tarjetas_profesional)
# a un bucket de Supabase Storage. Mantiene TODOS los backups (no borra antiguos).
# Razon de elegir Supabase Storage sobre Google Drive: las cuentas de servicio de Google
# no tienen cuota propia y requieren Shared Drive (Workspace pagado). Supabase Storage
# es nativo, gratis hasta 1GB, misma red que la BD, sin problemas de cuota.

SUPABASE_BACKUP_BUCKET = os.environ.get('SUPABASE_BACKUP_BUCKET', 'backups-bd')


def _supabase_storage_base_url():
    """Construye la URL base del endpoint de Storage a partir de SUPABASE_URL.
    Ejemplo: https://abc.supabase.co -> https://abc.supabase.co/storage/v1
    Devuelve None si SUPABASE_URL no esta configurado."""
    url = os.environ.get('SUPABASE_URL', '').rstrip('/')
    if not url:
        return None
    return f"{url}/storage/v1"


def _supabase_storage_headers():
    """Devuelve los headers con el service_role key para peticiones autenticadas a Storage.
    El service_role key tiene permisos totales (bypassa RLS), necesario para escritura de backups.
    Devuelve None si SUPABASE_SERVICE_KEY no esta configurado."""
    key = os.environ.get('SUPABASE_SERVICE_KEY', '')
    if not key:
        return None
    return {
        'apikey': key,
        'Authorization': f'Bearer {key}'
    }


def _backup_tabla_a_df(conn, nombre_tabla):
    """Lee una tabla completa de Supabase/SQLite y devuelve (DataFrame, filas)."""
    try:
        if DATABASE_URL:
            import psycopg2.extras
            cur = conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor)
            cur.execute(f"SELECT * FROM {nombre_tabla}")
            rows = cur.fetchall()
            cur.close()
            df = pd.DataFrame([dict(r) for r in rows]) if rows else pd.DataFrame()
        else:
            df = pd.read_sql_query(f"SELECT * FROM {nombre_tabla}", conn)
        # Sanitizar: convertir columnas no compatibles con Excel (dicts/lists/timezone-aware)
        for col in df.columns:
            try:
                # Convertir datetime tz-aware a naive (Excel no soporta tz-aware)
                if pd.api.types.is_datetime64_any_dtype(df[col]):
                    try:
                        df[col] = df[col].dt.tz_localize(None)
                    except Exception:
                        try:
                            df[col] = df[col].dt.tz_convert(None)
                        except Exception:
                            pass
                # Convertir dicts/lists a string JSON para que Excel pueda guardarlos
                if df[col].dtype == 'object':
                    df[col] = df[col].apply(lambda x: json.dumps(x, default=str) if isinstance(x, (dict, list)) else x)
            except Exception as _e_col:
                logger.debug(f"Backup sanitize col {col}: {_e_col}")
        return df, len(df)
    except Exception as e:
        logger.error(f"Backup: error leyendo tabla {nombre_tabla}: {e}")
        return pd.DataFrame(), 0


def respaldo_bd_a_drive():
    """Hace backup de las 3 tablas criticas a un archivo Excel multi-hoja y lo sube a Supabase Storage.
    El nombre 'respaldo_bd_a_drive' se mantiene por compatibilidad con llamadas existentes,
    pero internamente usa Supabase Storage (no Google Drive).
    Devuelve dict con: success, filename, tamano_kb, duracion_seg, registros_por_tabla, error, storage_url."""
    import time as _t_bkp
    t_inicio = _t_bkp.time()
    resultado = {
        'success': False,
        'filename': None,
        'tamano_kb': 0,
        'duracion_seg': 0,
        'registros_por_tabla': {},
        'error': None,
        'storage_url': None
    }
    
    try:
        # PASO 1: Validar configuracion
        base_url = _supabase_storage_base_url()
        if not base_url:
            resultado['error'] = 'Variable SUPABASE_URL no configurada en Render'
            return resultado
        
        headers = _supabase_storage_headers()
        if not headers:
            resultado['error'] = 'Variable SUPABASE_SERVICE_KEY no configurada en Render'
            return resultado
        
        if not SUPABASE_BACKUP_BUCKET:
            resultado['error'] = 'Bucket de Supabase Storage no configurado (SUPABASE_BACKUP_BUCKET)'
            return resultado
        
        # PASO 2: Conectar a BD y extraer tablas
        conn = get_db_connection()
        if not conn:
            resultado['error'] = 'No se pudo conectar a la base de datos'
            return resultado
        
        tablas = ['mensajes', 'suscripciones', 'tarjetas_profesional']
        dfs = {}
        for tabla in tablas:
            df, n_rows = _backup_tabla_a_df(conn, tabla)
            dfs[tabla] = df
            resultado['registros_por_tabla'][tabla] = n_rows
        
        try: conn.close()
        except: pass
        
        # PASO 3: Generar Excel multi-hoja en memoria
        buf = BytesIO()
        with pd.ExcelWriter(buf, engine='openpyxl') as writer:
            for tabla, df in dfs.items():
                # Excel tiene limite de 31 caracteres en nombres de hoja
                sheet_name = tabla[:31]
                if df.empty:
                    # Hoja vacia con mensaje
                    pd.DataFrame({'info': [f'Tabla {tabla} sin datos']}).to_excel(writer, sheet_name=sheet_name, index=False)
                else:
                    df.to_excel(writer, sheet_name=sheet_name, index=False)
            # Hoja de metadatos
            meta_df = pd.DataFrame({
                'campo': ['fecha_backup', 'timezone', 'tablas_incluidas', 'total_registros', 'version_bot'],
                'valor': [
                    _ahora_chile().strftime('%Y-%m-%d %H:%M:%S'),
                    'America/Santiago',
                    ','.join(tablas),
                    sum(resultado['registros_por_tabla'].values()),
                    'Cofradia Premium v6+'
                ]
            })
            meta_df.to_excel(writer, sheet_name='_metadata', index=False)
        
        buf.seek(0)
        contenido = buf.getvalue()
        tamano_bytes = len(contenido)
        resultado['tamano_kb'] = round(tamano_bytes / 1024, 1)
        
        # PASO 4: Subir a Supabase Storage
        ahora = _ahora_chile()
        filename = f"Backup_Cofradia_{ahora.strftime('%Y%m%d_%H%M%S')}.xlsx"
        resultado['filename'] = filename
        
        # POST a /storage/v1/object/<bucket>/<path>
        # x-upsert: false significa "fallar si ya existe un archivo con el mismo nombre"
        # (deberia ser imposible porque el timestamp incluye segundos, pero por seguridad)
        upload_url = f"{base_url}/object/{SUPABASE_BACKUP_BUCKET}/{filename}"
        upload_headers = dict(headers)
        upload_headers['Content-Type'] = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
        upload_headers['x-upsert'] = 'false'
        upload_headers['Cache-Control'] = 'max-age=3600'
        
        resp = requests.post(upload_url, headers=upload_headers, data=contenido, timeout=180)
        
        if resp.status_code in (200, 201):
            resultado['success'] = True
            # Construir URL de acceso (requiere autenticacion, no es publica)
            resultado['storage_url'] = f"{SUPABASE_BACKUP_BUCKET}/{filename}"
            # Guardar contenido bytes para que el comando pueda enviarlo por Telegram sin re-descargar
            resultado['_contenido_bytes'] = contenido
        else:
            resultado['error'] = f'HTTP {resp.status_code}: {resp.text[:300]}'
        
    except Exception as e:
        import traceback
        resultado['error'] = f'{type(e).__name__}: {str(e)[:200]}'
        logger.error(f"Backup BD a Supabase Storage fallo: {e}\n{traceback.format_exc()}")
    
    resultado['duracion_seg'] = round(_t_bkp.time() - t_inicio, 1)
    return resultado


def _listar_backups_drive(max_resultados=20):
    """Lista los backups existentes en el bucket de Supabase Storage. Devuelve lista de dicts con
    name, size, created_at, updated_at. Ordenados por fecha descendente.
    El nombre '_listar_backups_drive' se mantiene por compatibilidad."""
    try:
        base_url = _supabase_storage_base_url()
        if not base_url:
            return []
        headers = _supabase_storage_headers()
        if not headers:
            return []
        
        # POST a /storage/v1/object/list/<bucket>
        list_url = f"{base_url}/object/list/{SUPABASE_BACKUP_BUCKET}"
        list_headers = dict(headers)
        list_headers['Content-Type'] = 'application/json'
        
        body = {
            'limit': max_resultados,
            'offset': 0,
            'sortBy': {'column': 'created_at', 'order': 'desc'},
            'prefix': ''
        }
        
        resp = requests.post(list_url, headers=list_headers, json=body, timeout=30)
        if resp.status_code != 200:
            logger.warning(f"Listar backups Supabase Storage: HTTP {resp.status_code}: {resp.text[:200]}")
            return []
        
        archivos = resp.json() or []
        # Filtrar solo los que empiezan con 'Backup_Cofradia' (por si hay otros archivos en el bucket)
        backups = [a for a in archivos if isinstance(a, dict) and str(a.get('name', '')).startswith('Backup_Cofradia')]
        return backups
    except Exception as e:
        logger.error(f"Listar backups Supabase Storage: {e}")
        return []


def _descargar_backup_de_supabase(nombre_archivo):
    """Descarga un archivo de backup desde Supabase Storage. Devuelve (bytes, error_msg).
    Si exito: (contenido_bytes, None). Si error: (None, 'mensaje error')."""
    try:
        base_url = _supabase_storage_base_url()
        if not base_url:
            return None, 'SUPABASE_URL no configurada'
        headers = _supabase_storage_headers()
        if not headers:
            return None, 'SUPABASE_SERVICE_KEY no configurada'
        
        # GET a /storage/v1/object/<bucket>/<filename>
        download_url = f"{base_url}/object/{SUPABASE_BACKUP_BUCKET}/{nombre_archivo}"
        resp = requests.get(download_url, headers=headers, timeout=60)
        
        if resp.status_code == 200:
            return resp.content, None
        else:
            return None, f'HTTP {resp.status_code}: {resp.text[:200]}'
    except Exception as e:
        logger.error(f"Descargar backup Supabase: {e}")
        return None, f'{type(e).__name__}: {str(e)[:200]}'


async def backup_ahora_comando(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Comando /backup_ahora - Ejecuta backup manual de la BD (solo admin)."""
    user_id = update.effective_user.id
    if user_id != OWNER_ID:
        await update.message.reply_text("❌ Comando exclusivo del administrador.")
        return
    
    msg = await update.message.reply_text("💾 Iniciando backup manual de BD...\n⏳ Extrayendo tablas...")
    try:
        loop = asyncio.get_running_loop()
        await msg.edit_text("💾 Generando Excel multi-hoja...\n⏳ Esto puede tardar 10-30 segundos.")
        resultado = await loop.run_in_executor(None, respaldo_bd_a_drive)
        
        if resultado['success']:
            regs_txt = "\n".join([f"  • {t}: {n:,} registros" for t, n in resultado['registros_por_tabla'].items()])
            total_regs = sum(resultado['registros_por_tabla'].values())
            texto = (
                f"✅ BACKUP COMPLETADO\n{'━'*30}\n\n"
                f"📁 Archivo: {resultado['filename']}\n"
                f"📊 Tamaño: {resultado['tamano_kb']} KB\n"
                f"⏱️ Duración: {resultado['duracion_seg']}s\n"
                f"📦 Total registros: {total_regs:,}\n\n"
                f"TABLAS RESPALDADAS:\n{regs_txt}\n\n"
                f"💾 Ubicación: Supabase Storage › {SUPABASE_BACKUP_BUCKET}\n"
                f"💡 Accede desde el dashboard de Supabase."
            )
            await msg.edit_text(texto)
            # Enviar el archivo Excel al admin por Telegram
            try:
                contenido_bytes = resultado.get('_contenido_bytes')
                if contenido_bytes and len(contenido_bytes) < 48 * 1024 * 1024:  # Telegram bot limit ~50MB
                    from io import BytesIO as _BIO
                    bio = _BIO(contenido_bytes)
                    bio.name = resultado['filename']
                    await update.message.reply_document(
                        document=bio,
                        filename=resultado['filename'],
                        caption=f"📥 {resultado['filename']}\n📊 {resultado['tamano_kb']} KB · {total_regs:,} registros"
                    )
                elif contenido_bytes:
                    await update.message.reply_text(
                        f"⚠️ Archivo muy grande para enviar por Telegram ({resultado['tamano_kb']} KB > 48 MB).\n"
                        f"Descárgalo desde Supabase Storage directamente."
                    )
            except Exception as _e_send:
                logger.warning(f"Backup envio Telegram fallo: {_e_send}")
                await update.message.reply_text(f"⚠️ No se pudo enviar el archivo por Telegram: {str(_e_send)[:100]}")
        else:
            await msg.edit_text(
                f"❌ BACKUP FALLÓ\n{'━'*30}\n\n"
                f"Error: {resultado.get('error', 'Desconocido')}\n"
                f"Duración: {resultado['duracion_seg']}s\n\n"
                f"💡 Verifica en Render:\n"
                f"  • SUPABASE_URL configurada\n"
                f"  • SUPABASE_SERVICE_KEY configurada\n"
                f"  • Bucket '{SUPABASE_BACKUP_BUCKET}' existe en Supabase Storage"
            )
    except Exception as e:
        await msg.edit_text(f"❌ Error inesperado: {str(e)[:200]}")


async def listar_backups_comando(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Comando /listar_backups - Lista los ultimos 20 backups en Supabase Storage (solo admin).
    Los 8 primeros tienen boton de descarga inline."""
    user_id = update.effective_user.id
    if user_id != OWNER_ID:
        await update.message.reply_text("❌ Comando exclusivo del administrador.")
        return
    
    msg = await update.message.reply_text("📋 Consultando backups en almacenamiento...")
    try:
        loop = asyncio.get_running_loop()
        archivos = await loop.run_in_executor(None, _listar_backups_drive, 20)
        
        if not archivos:
            await msg.edit_text(
                "📭 No se encontraron backups en Supabase Storage.\n\n"
                "💡 Posibles causas:\n"
                "  • Aún no se ha ejecutado ningún backup\n"
                "  • SUPABASE_URL o SUPABASE_SERVICE_KEY no configurados\n"
                f"  • Bucket '{SUPABASE_BACKUP_BUCKET}' no existe\n\n"
                "Usa /backup_ahora para crear el primero."
            )
            return
        
        # Guardar lista de archivos en context.user_data para callbacks posteriores
        # Telegram callback_data limite = 64 bytes, usamos indice corto en vez de nombre completo
        context.user_data['_backups_lista'] = [a.get('name', '') for a in archivos[:20]]
        
        # Calcular stats totales
        total_size_kb = 0
        for a in archivos:
            meta = a.get('metadata') or {}
            total_size_kb += int(meta.get('size', 0))
        total_size_kb = total_size_kb / 1024
        
        lineas = [f"📋 BACKUPS DISPONIBLES ({len(archivos)} recientes)\n{'━'*35}\n"]
        for i, arch in enumerate(archivos[:20], 1):
            nombre = arch.get('name', 'sin_nombre')
            meta = arch.get('metadata') or {}
            size_kb = round(int(meta.get('size', 0)) / 1024, 1)
            created = arch.get('created_at', '')[:16].replace('T', ' ')
            lineas.append(f"{i:2d}. {nombre}")
            lineas.append(f"    📅 {created} · 📊 {size_kb} KB")
        
        lineas.append(f"\n{'━'*35}")
        lineas.append(f"📦 Total mostrado: {round(total_size_kb,1)} KB")
        lineas.append(f"💾 Supabase Storage › {SUPABASE_BACKUP_BUCKET}")
        lineas.append(f"\n💡 Usa /descargar_backup [N] o los botones de abajo")
        
        texto = "\n".join(lineas)
        # Telegram limit 4096 chars
        if len(texto) > 4000:
            texto = texto[:3900] + "\n\n... (truncado)"
        
        # Botones inline: descargar los 8 mas recientes (2 columnas x 4 filas)
        keyboard = []
        max_botones = min(8, len(archivos))
        for row_start in range(0, max_botones, 2):
            row = []
            for offset in range(2):
                idx = row_start + offset
                if idx < max_botones:
                    # Extraer fecha del nombre del archivo para el boton (mas corto)
                    arch = archivos[idx]
                    nombre = arch.get('name', '')
                    # Nombre: Backup_Cofradia_20260417_045759.xlsx -> 17/04 04:57
                    fecha_corta = nombre.replace('Backup_Cofradia_', '').replace('.xlsx', '')
                    try:
                        # 20260417_045759 -> 17/04 04:57
                        if len(fecha_corta) >= 15:
                            fecha_corta = f"{fecha_corta[6:8]}/{fecha_corta[4:6]} {fecha_corta[9:11]}:{fecha_corta[11:13]}"
                    except: pass
                    row.append(InlineKeyboardButton(
                        f"⬇️ #{idx+1} {fecha_corta}",
                        callback_data=f"bkpdl_{idx}"
                    ))
            if row:
                keyboard.append(row)
        
        reply_markup = InlineKeyboardMarkup(keyboard) if keyboard else None
        await msg.edit_text(texto, reply_markup=reply_markup)
    except Exception as e:
        await msg.edit_text(f"❌ Error: {str(e)[:200]}")


async def descargar_backup_comando(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Comando /descargar_backup [n] - Descarga el n-esimo backup mas reciente (1=ultimo, 2=penultimo, etc).
    Sin argumento descarga el ultimo. Solo admin."""
    user_id = update.effective_user.id
    if user_id != OWNER_ID:
        await update.message.reply_text("❌ Comando exclusivo del administrador.")
        return
    
    # Parsear argumento opcional: numero (1=mas reciente)
    indice_usuario = 1  # default
    try:
        if context.args and len(context.args) > 0:
            indice_usuario = int(context.args[0])
            if indice_usuario < 1:
                await update.message.reply_text("❌ El número debe ser 1 o mayor (1 = más reciente).")
                return
    except ValueError:
        await update.message.reply_text(
            "❌ Argumento inválido. Usa /descargar_backup [numero]\n"
            "Ejemplo: /descargar_backup 1 (mas reciente)\n"
            "Ejemplo: /descargar_backup 3 (3er mas reciente)"
        )
        return
    
    msg = await update.message.reply_text(f"📋 Buscando backup #{indice_usuario} en almacenamiento de respaldo...")
    try:
        loop = asyncio.get_running_loop()
        # Pedir hasta 20 backups (limite practico)
        archivos = await loop.run_in_executor(None, _listar_backups_drive, 20)
        
        if not archivos:
            await msg.edit_text("📭 No hay backups disponibles.\nUsa /backup_ahora para crear uno.")
            return
        
        # Validar indice
        if indice_usuario > len(archivos):
            await msg.edit_text(
                f"❌ Solo hay {len(archivos)} backup(s) disponible(s).\n"
                f"Pediste el #{indice_usuario}, pero el máximo es #{len(archivos)}."
            )
            return
        
        # Obtener nombre del archivo solicitado (indice 1-based del usuario -> 0-based en la lista)
        archivo_target = archivos[indice_usuario - 1]
        nombre = archivo_target.get('name', '')
        meta = archivo_target.get('metadata') or {}
        size_kb = round(int(meta.get('size', 0)) / 1024, 1)
        created = archivo_target.get('created_at', '')[:16].replace('T', ' ')
        
        await msg.edit_text(f"⬇️ Descargando {nombre}...\n📊 {size_kb} KB · 📅 {created}")
        
        # Descargar contenido
        contenido, error = await loop.run_in_executor(None, _descargar_backup_de_supabase, nombre)
        
        if error or not contenido:
            await msg.edit_text(f"❌ Error descargando: {error or 'contenido vacio'}")
            return
        
        # Validar tamaño (Telegram limite 50MB para bots)
        if len(contenido) >= 48 * 1024 * 1024:
            await msg.edit_text(
                f"⚠️ Archivo muy grande para Telegram ({size_kb} KB > 48 MB).\n"
                f"Descárgalo desde Supabase Storage directamente."
            )
            return
        
        # Enviar como documento
        from io import BytesIO as _BIO
        bio = _BIO(contenido)
        bio.name = nombre
        await msg.edit_text(f"✅ Enviando {nombre}...")
        await update.message.reply_document(
            document=bio,
            filename=nombre,
            caption=(f"📥 Backup #{indice_usuario} de {len(archivos)}\n"
                     f"📁 {nombre}\n"
                     f"📊 {size_kb} KB · 📅 {created}")
        )
        await msg.delete()
    except Exception as e:
        await msg.edit_text(f"❌ Error: {str(e)[:200]}")


async def descargar_backup_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Callback de los botones ⬇️ inline de /listar_backups. Pattern: bkpdl_<indice>"""
    query = update.callback_query
    user_id = query.from_user.id
    if user_id != OWNER_ID:
        await query.answer("❌ Solo el administrador", show_alert=True)
        return
    
    await query.answer()
    
    try:
        # Parsear indice del callback_data
        data = query.data or ''
        if not data.startswith('bkpdl_'):
            return
        idx = int(data.replace('bkpdl_', ''))
        
        # Recuperar lista guardada de la sesion
        lista = context.user_data.get('_backups_lista', [])
        if not lista or idx >= len(lista):
            await query.message.reply_text(
                "⚠️ La lista de backups expiró.\n"
                "Ejecuta /listar_backups de nuevo para refrescar los botones."
            )
            return
        
        nombre = lista[idx]
        if not nombre:
            await query.message.reply_text("❌ Archivo no identificado en la lista.")
            return
        
        msg = await query.message.reply_text(f"⬇️ Descargando {nombre}...")
        
        loop = asyncio.get_running_loop()
        contenido, error = await loop.run_in_executor(None, _descargar_backup_de_supabase, nombre)
        
        if error or not contenido:
            await msg.edit_text(f"❌ Error descargando: {error or 'contenido vacio'}")
            return
        
        if len(contenido) >= 48 * 1024 * 1024:
            await msg.edit_text(
                f"⚠️ Archivo muy grande para Telegram ({round(len(contenido)/1024,1)} KB > 48 MB).\n"
                f"Descárgalo desde Supabase Storage directamente."
            )
            return
        
        from io import BytesIO as _BIO
        bio = _BIO(contenido)
        bio.name = nombre
        size_kb = round(len(contenido)/1024, 1)
        await msg.edit_text(f"✅ Enviando {nombre}...")
        await query.message.reply_document(
            document=bio,
            filename=nombre,
            caption=f"📥 {nombre}\n📊 {size_kb} KB"
        )
        await msg.delete()
    except Exception as e:
        try:
            await query.message.reply_text(f"❌ Error: {str(e)[:200]}")
        except: pass


def _purgar_backups_antiguos(dias_retencion=10):
    """FASE 8: Purga backups en Supabase Storage con antiguedad mayor a N dias.
    Mantiene solo los ultimos N backups (default: 10 dias) para optimizar storage
    y costos. Si por algun motivo no se ejecuta el backup un dia, se mantienen
    igualmente los ultimos N archivos (no exactamente N dias calendario).
    
    Returns: dict con resultado: {'eliminados': int, 'mantenidos': int, 'errores': list}
    """
    resultado = {'eliminados': 0, 'mantenidos': 0, 'errores': []}
    try:
        # Listar TODOS los backups (no limitar a 20 como _listar_backups_drive)
        base_url = _supabase_storage_base_url()
        if not base_url:
            resultado['errores'].append('SUPABASE_URL no configurada')
            return resultado
        headers = _supabase_storage_headers()
        if not headers:
            resultado['errores'].append('SUPABASE_SERVICE_KEY no configurada')
            return resultado
        
        list_url = f"{base_url}/object/list/{SUPABASE_BACKUP_BUCKET}"
        list_headers = dict(headers)
        list_headers['Content-Type'] = 'application/json'
        body = {
            'limit': 200,  # asume <200 backups historicos
            'offset': 0,
            'sortBy': {'column': 'created_at', 'order': 'desc'},
            'prefix': ''
        }
        resp = requests.post(list_url, headers=list_headers, json=body, timeout=30)
        if resp.status_code != 200:
            resultado['errores'].append(f'Listar backups HTTP {resp.status_code}')
            return resultado
        
        archivos = resp.json() or []
        backups = [a for a in archivos if isinstance(a, dict) and str(a.get('name', '')).startswith('Backup_Cofradia')]
        
        if len(backups) <= dias_retencion:
            resultado['mantenidos'] = len(backups)
            logger.info(f"🗑️ Purga backups: {len(backups)} backups en total, ninguno excede el limite de {dias_retencion}")
            return resultado
        
        # Los primeros N son los mas recientes (orden desc), los demas se eliminan
        a_mantener = backups[:dias_retencion]
        a_eliminar = backups[dias_retencion:]
        resultado['mantenidos'] = len(a_mantener)
        
        # Eliminar uno por uno via DELETE (Supabase Storage permite bulk delete via POST a /remove)
        # Usamos bulk delete que es atomico
        remove_url = f"{base_url}/object/{SUPABASE_BACKUP_BUCKET}"
        # Supabase Storage: DELETE individual es mas robusto para distintas versiones
        for arch in a_eliminar:
            nombre_arch = arch.get('name', '')
            if not nombre_arch:
                continue
            try:
                del_url = f"{base_url}/object/{SUPABASE_BACKUP_BUCKET}/{nombre_arch}"
                r_del = requests.delete(del_url, headers=headers, timeout=30)
                if r_del.status_code in (200, 204):
                    resultado['eliminados'] += 1
                    logger.info(f"🗑️ Purgado backup antiguo: {nombre_arch}")
                else:
                    err = f"DELETE {nombre_arch}: HTTP {r_del.status_code}"
                    resultado['errores'].append(err)
                    logger.warning(f"⚠️ {err}: {r_del.text[:120]}")
            except Exception as _e_del:
                err = f"DELETE {nombre_arch}: {_e_del}"
                resultado['errores'].append(err)
                logger.warning(f"⚠️ {err}")
        
        logger.info(
            f"🗑️ FASE 8 purga backups: {resultado['eliminados']} eliminados, "
            f"{resultado['mantenidos']} mantenidos (retencion={dias_retencion} dias)"
        )
        return resultado
    except Exception as e:
        resultado['errores'].append(f'Excepcion: {e}')
        logger.error(f"Error purgar_backups_antiguos: {e}")
        return resultado


async def _job_backup_bd_diario(context: ContextTypes.DEFAULT_TYPE):
    """Job automatico que ejecuta respaldo_bd_a_drive() diariamente a las 03:00 AM hora Chile
    y notifica al admin el resultado por mensaje privado."""
    try:
        logger.info("🔄 Job backup BD diario: iniciando...")
        loop = asyncio.get_running_loop()
        resultado = await loop.run_in_executor(None, respaldo_bd_a_drive)
        
        if resultado['success']:
            total_regs = sum(resultado['registros_por_tabla'].values())
            regs_txt = ", ".join([f"{t}={n}" for t, n in resultado['registros_por_tabla'].items()])
            logger.info(f"✅ Backup BD OK: {resultado['filename']} - {resultado['tamano_kb']}KB - {total_regs} registros - {resultado['duracion_seg']}s")
            
            # FASE 8: purgar backups antiguos (>10 dias) para mantener storage limpio
            try:
                purga = await loop.run_in_executor(None, _purgar_backups_antiguos, 10)
                if purga.get('eliminados', 0) > 0:
                    logger.info(f"🗑️ FASE 8: {purga['eliminados']} backups antiguos purgados, {purga['mantenidos']} mantenidos")
                purga_txt = ""
                if purga.get('eliminados', 0) > 0:
                    purga_txt = f"\n🗑️ Purga: {purga['eliminados']} antiguos eliminados, {purga['mantenidos']} mantenidos"
            except Exception as _e_purga:
                logger.warning(f"Purga backups falló (no critico): {_e_purga}")
                purga_txt = ""
            
            if OWNER_ID:
                try:
                    texto = (
                        f"✅ BACKUP AUTOMATICO COMPLETADO\n{'━'*30}\n\n"
                        f"📁 {resultado['filename']}\n"
                        f"📊 {resultado['tamano_kb']} KB · ⏱️ {resultado['duracion_seg']}s\n"
                        f"📦 {total_regs:,} registros totales\n\n"
                        f"TABLAS: {regs_txt}\n\n"
                        f"💾 Supabase Storage › {SUPABASE_BACKUP_BUCKET}"
                        f"{purga_txt}"
                    )
                    await context.bot.send_message(chat_id=OWNER_ID, text=texto)
                except Exception as _e_notif:
                    logger.warning(f"Backup notif admin falló: {_e_notif}")
        else:
            logger.error(f"❌ Backup BD fallo: {resultado.get('error')}")
            if OWNER_ID:
                try:
                    await context.bot.send_message(
                        chat_id=OWNER_ID,
                        text=(f"⚠️ BACKUP AUTOMATICO FALLÓ\n{'━'*30}\n\n"
                              f"Error: {resultado.get('error', 'Desconocido')}\n"
                              f"Duración: {resultado['duracion_seg']}s\n\n"
                              f"💡 Revisa logs o usa /backup_ahora")
                    )
                except Exception: pass
    except Exception as e:
        logger.error(f"Job backup BD exception: {e}")


async def _job_cierre_ranking_mensual(context: ContextTypes.DEFAULT_TYPE):
    """FASE 12: Job que se ejecuta el dia 1 de cada mes a las 00:05 AM Chile.
    1. Obtiene el top 10 del mes que recien termino
    2. Lo guarda en historico_ranking
    3. Otorga insignias top10_mes (top 10) y numero_uno_mes (#1)
    4. Resetea puntos_mes de todos los usuarios
    5. Anuncia ganador en el grupo (si hay)
    """
    try:
        from datetime import timedelta as _td_rk
        ahora = _ahora_chile()
        # El mes que recien termino es el anterior al actual
        mes_pasado_dt = (ahora.replace(day=1) - _td_rk(days=1))
        mes_pasado = mes_pasado_dt.strftime('%Y-%m')
        logger.info(f"🏆 Cerrando ranking mensual: {mes_pasado}")
        
        conn = get_db_connection()
        if not conn:
            logger.error("Job cierre ranking: BD no disponible")
            return
        c = conn.cursor()
        
        # Obtener top 10 del mes pasado
        if DATABASE_URL:
            c.execute("""SELECT user_id, puntos_mes, 
                        (SELECT first_name FROM mensajes WHERE user_id = pu.user_id LIMIT 1) as nombre
                        FROM puntos_usuario pu
                        WHERE mes_referencia = %s AND puntos_mes > 0
                        ORDER BY puntos_mes DESC LIMIT 10""", (mes_pasado,))
        else:
            c.execute("""SELECT user_id, puntos_mes,
                        (SELECT first_name FROM mensajes WHERE user_id = pu.user_id LIMIT 1) as nombre
                        FROM puntos_usuario pu
                        WHERE mes_referencia = ? AND puntos_mes > 0
                        ORDER BY puntos_mes DESC LIMIT 10""", (mes_pasado,))
        top_mes = c.fetchall()
        
        ganador_info = None
        top10_uids = []
        
        for i, fila in enumerate(top_mes, 1):
            if DATABASE_URL:
                uid = fila['user_id']; pts = fila['puntos_mes']; nom = fila['nombre'] or 'Usuario'
            else:
                uid, pts, nom = fila[0], fila[1], fila[2] or 'Usuario'
            
            top10_uids.append(uid)
            
            # Guardar en historico_ranking
            try:
                if DATABASE_URL:
                    c.execute("""INSERT INTO historico_ranking (mes_referencia, user_id, puntos, posicion)
                                VALUES (%s, %s, %s, %s)""", (mes_pasado, uid, pts, i))
                else:
                    c.execute("""INSERT INTO historico_ranking (mes_referencia, user_id, puntos, posicion)
                                VALUES (?, ?, ?, ?)""", (mes_pasado, uid, pts, i))
            except Exception as _e_h:
                logger.debug(f"Hist ranking: {_e_h}")
            
            # Otorgar insignias
            otorgar_insignia(uid, 'top10_mes')
            if i == 1:
                otorgar_insignia(uid, 'numero_uno_mes')
                ganador_info = {'user_id': uid, 'nombre': nom, 'puntos': pts}
        
        # Resetear puntos_mes de todos (nuevo mes empieza en 0)
        mes_actual = _mes_actual_str()
        if DATABASE_URL:
            c.execute("UPDATE puntos_usuario SET puntos_mes = 0, mes_referencia = %s",
                     (mes_actual,))
        else:
            c.execute("UPDATE puntos_usuario SET puntos_mes = 0, mes_referencia = ?",
                     (mes_actual,))
        conn.commit()
        conn.close()
        
        logger.info(f"✅ Ranking {mes_pasado} cerrado: {len(top10_uids)} usuarios en top 10")
        
        # Anunciar ganador al admin
        if OWNER_ID:
            try:
                if ganador_info:
                    texto_admin = (
                        f"🏆 CIERRE DE RANKING MENSUAL\n{'━'*30}\n\n"
                        f"📅 Mes cerrado: {mes_pasado}\n\n"
                        f"👑 GANADOR #{1}: {ganador_info['nombre']}\n"
                        f"   Puntos: {ganador_info['puntos']:,}\n\n"
                        f"🏅 Insignias otorgadas: {len(top10_uids)} miembros recibieron 'Top 10 del Mes'\n"
                        f"👑 1 miembro recibio '#1 del Mes'\n\n"
                        f"🔄 Puntos mensuales reseteados. Empieza {mes_actual}."
                    )
                else:
                    texto_admin = (
                        f"🏆 CIERRE DE RANKING MENSUAL\n{'━'*30}\n\n"
                        f"📅 Mes cerrado: {mes_pasado}\n"
                        f"⚠️ No hubo actividad suficiente para generar ranking."
                    )
                await context.bot.send_message(chat_id=OWNER_ID, text=texto_admin)
            except Exception as _e_n:
                logger.debug(f"Notif cierre ranking: {_e_n}")
    except Exception as e:
        logger.error(f"Job cierre ranking mensual: {e}")
        import traceback
        logger.error(traceback.format_exc())


def detectar_columna_anio_egreso(df):
    """Detecta automáticamente la columna que contiene años de egreso"""
    for col_idx in range(len(df.columns)):
        try:
            col_data = pd.to_numeric(df.iloc[:, col_idx], errors='coerce').dropna()
            # Verificar si la mayoría son años válidos (1960-2025)
            if len(col_data) > 10:
                years_valid = col_data[(col_data >= 1960) & (col_data <= 2026)]
                if len(years_valid) > len(col_data) * 0.5:  # >50% son años válidos
                    logger.info(f"Columna de año de egreso detectada: índice {col_idx}")
                    return col_idx
        except:
            continue
    return None


