def indexar_google_drive_rag():
    """Indexa datos del Excel de Google Drive en chunks para RAG.
    IMPORTANTE: Solo borra y re-crea chunks con source='BD_Grupo_Laboral'.
    NUNCA toca los chunks de PDFs (source LIKE 'PDF:%').
    """
    try:
        df = obtener_datos_excel_drive()
        if df is None or len(df) == 0:
            logger.info("RAG: No hay datos para indexar")
            return
        
        conn = get_db_connection()
        if not conn:
            return
        
        c = conn.cursor()
        
        # SOLO limpiar chunks del Excel (PRESERVAR PDFs y otros)
        if DATABASE_URL:
            c.execute("DELETE FROM rag_chunks WHERE source = %s", ('BD_Grupo_Laboral',))
        else:
            c.execute("DELETE FROM rag_chunks WHERE source = ?", ('BD_Grupo_Laboral',))
        
        logger.info("🔄 RAG: Chunks de Excel eliminados para re-indexar (PDFs preservados)")
        
        chunks_creados = 0
        
        def get_col(row, idx):
            try:
                val = row.iloc[idx] if idx < len(row) else ''
                val = str(val).strip()
                if val.lower() in ['nan', 'none', '', 'null', 'n/a', '-', 'nat']:
                    return ''
                return val
            except:
                return ''
        
        for idx, row in df.iterrows():
            nombre = get_col(row, 2)
            apellido = get_col(row, 3)
            telefono = get_col(row, 5)
            email = get_col(row, 6)
            situacion = get_col(row, 8)
            industria1 = get_col(row, 10)
            industria2 = get_col(row, 12)
            industria3 = get_col(row, 14)
            profesion = get_col(row, 24)
            
            nombre_completo = f"{nombre} {apellido}".strip()
            if not nombre_completo:
                continue
            
            # Crear chunk de texto
            chunk = f"Profesional: {nombre_completo}."
            if profesion:
                chunk += f" Profesion: {profesion}."
            if situacion:
                chunk += f" Situacion laboral: {situacion}."
            if industria1:
                chunk += f" Industria: {industria1}."
            if industria2:
                chunk += f" Tambien: {industria2}."
            if industria3:
                chunk += f" Ademas: {industria3}."
            if telefono:
                chunk += f" Telefono: {telefono}."
            if email:
                chunk += f" Email: {email}."
            
            # Keywords para búsqueda
            keywords = f"{nombre_completo} {profesion} {industria1} {industria2} {industria3} {situacion}".lower()
            
            metadata = json.dumps({
                'nombre': nombre_completo,
                'profesion': profesion,
                'situacion': situacion,
                'fila': idx
            })
            
            if DATABASE_URL:
                # FASE 29: embedding del chunk del grupo laboral
                emb_gl = generar_embedding_gemini(chunk, tipo='RETRIEVAL_DOCUMENT')
                if emb_gl:
                    try:
                        c.execute("""INSERT INTO rag_chunks (source, chunk_text, metadata, keywords, embedding) 
                                   VALUES (%s, %s, %s, %s, %s::vector)""",
                                 ('BD_Grupo_Laboral', chunk, metadata, keywords, embedding_to_pgvector(emb_gl)))
                    except Exception:
                        c.execute("""INSERT INTO rag_chunks (source, chunk_text, metadata, keywords) 
                                   VALUES (%s, %s, %s, %s)""",
                                 ('BD_Grupo_Laboral', chunk, metadata, keywords))
                else:
                    c.execute("""INSERT INTO rag_chunks (source, chunk_text, metadata, keywords) 
                               VALUES (%s, %s, %s, %s)""",
                             ('BD_Grupo_Laboral', chunk, metadata, keywords))
            else:
                c.execute("""INSERT INTO rag_chunks (source, chunk_text, metadata, keywords) 
                           VALUES (?, ?, ?, ?)""",
                         ('BD_Grupo_Laboral', chunk, metadata, keywords))
            
            chunks_creados += 1
        
        conn.commit()
        conn.close()
        logger.info(f"✅ RAG: {chunks_creados} chunks indexados desde Google Drive")
        
    except Exception as e:
        logger.error(f"Error indexando RAG: {e}")


def expandir_query_con_llm(query_original, timeout_sec=4):
    """FASE 3C: Query expansion con LLM ligero.
    
    Toma la consulta original del usuario y genera 2-3 reformulaciones que usen
    términos diferentes (sinónimos, nombres alternativos, etc.) para mejorar el
    recall de la búsqueda por keywords.
    
    Ejemplo:
        query_original: "qué dice Kiyosaki sobre activos"
        expansiones: ["robert kiyosaki inversiones patrimonio",
                      "padre rico padre pobre activos pasivos"]
    
    Devuelve una lista de strings: [query_original, expansion1, expansion2, ...]
    
    Si el LLM no está disponible o falla, devuelve solo [query_original].
    """
    if not query_original or len(query_original.strip()) < 3:
        return [query_original]
    
    if not GROQ_API_KEY:
        return [query_original]
    
    # No expandir consultas muy cortas (1 palabra) - probablemente nombres propios exactos
    if len(query_original.split()) <= 1:
        return [query_original]
    
    try:
        prompt_expand = f"""Genera 2 reformulaciones de esta consulta que usen palabras DIFERENTES (sinonimos, nombres alternativos, terminos relacionados).

CONSULTA: "{query_original}"

Responde en formato exacto (2 lineas, nada mas):
1. <primera reformulacion>
2. <segunda reformulacion>

NO expliques, NO agregues texto, SOLO las 2 lineas numeradas."""
        
        respuesta = llamar_groq(prompt_expand, max_tokens=120, temperature=0.4)
        
        if not respuesta:
            return [query_original]
        
        # Parsear: extraer las 2 lineas numeradas
        import re as _re_qe
        expansiones = []
        for linea in respuesta.split('\n'):
            linea = linea.strip()
            # Quitar prefijos "1.", "2.", "-", etc.
            m = _re_qe.match(r'^\s*[\d\-\*\.\)]+\s*(.+)$', linea)
            if m:
                exp = m.group(1).strip().strip('"\'')
                if len(exp) >= 3 and exp.lower() != query_original.lower().strip():
                    expansiones.append(exp)
        
        # Limitar a máximo 2 expansiones + original
        resultado_final = [query_original] + expansiones[:2]
        
        if len(resultado_final) > 1:
            logger.info(f"🔎 Query expansion: '{query_original[:40]}' → "
                        f"{len(resultado_final)-1} variantes")
        
        return resultado_final
    
    except Exception as e:
        logger.debug(f"Query expansion fallo: {e}")
        return [query_original]


def buscar_rag_expandido(query_original, limit=5):
    """FASE 3C: Wrapper sobre buscar_rag que usa query expansion.
    
    Busca con la consulta original Y con 2 reformulaciones generadas por LLM,
    luego combina resultados y deduplica. Esto aumenta el recall (encuentra más
    info relevante) sin perder precisión.
    
    La expansion se hace en paralelo con la primera búsqueda para no sumar latencia.
    """
    from concurrent.futures import ThreadPoolExecutor as _TPE_qe
    
    # PASO 1: Primera búsqueda directa con la query original (siempre se hace)
    # PASO 2: En paralelo, generar expansiones (si toma demasiado, no importa)
    try:
        with _TPE_qe(max_workers=2) as pool:
            fut_original = pool.submit(buscar_rag, query_original, limit * 2)
            fut_expansiones = pool.submit(expandir_query_con_llm, query_original)
            
            # La búsqueda original tiene prioridad (timeout más largo)
            try:
                chunks_original, score_orig = fut_original.result(timeout=10)
            except Exception as _e_o:
                logger.warning(f"Buscar original fallo: {_e_o}")
                chunks_original, score_orig = [], 0.0
            
            # Expansiones: si tardan más de 4s, se usan solo las chunks originales
            try:
                queries_expandidas = fut_expansiones.result(timeout=5)
            except Exception:
                queries_expandidas = [query_original]
        
        # PASO 3: Si hay expansiones distintas a la original, buscar con ellas
        if len(queries_expandidas) > 1:
            all_chunks = list(chunks_original)
            score_max = score_orig
            seen_keys = set(
                (c[0][:80] if isinstance(c, tuple) else c[:80])
                for c in chunks_original
            )
            
            # Búsqueda adicional solo con 1 expansion (la que parezca mas prometedora)
            # Para no saturar - suficiente con probar 1 variante
            for q_exp in queries_expandidas[1:2]:
                try:
                    chunks_exp, score_exp = buscar_rag(q_exp, limit)
                    for c in chunks_exp:
                        key = (c[0][:80] if isinstance(c, tuple) else c[:80])
                        if key and key not in seen_keys:
                            seen_keys.add(key)
                            all_chunks.append(c)
                    score_max = max(score_max, score_exp)
                except Exception as _e_exp:
                    logger.debug(f"Busqueda expandida fallo: {_e_exp}")
            
            # Devolver top limit después de deduplicar
            return all_chunks[:limit * 3], score_max
        
        return chunks_original, score_orig
    
    except Exception as e:
        logger.warning(f"buscar_rag_expandido fallo, fallback a buscar_rag: {e}")
        return buscar_rag(query_original, limit)


# ════════════════════════════════════════════════════════════════════════
# FASE 6 OPTIMIZADA — RAG INTELIGENTE: Caché LRU + sinónimos REACTIVOS
# 
# Filosofia: "no hacer trabajo extra a menos que sea necesario".
# - Caché LRU: queries idénticas repetidas en <5min responden instantáneamente
# - Sinónimos: solo se aplican si la búsqueda original devolvió <2 resultados
# - Fuzzy matching: solo si NADA matchea (fallback final)
# - Sources pre-cargados en módulo: una sola query SQL al iniciar
# 
# Resultado: queries comunes responden en milisegundos, queries dificiles
# triggers expansion automaticamente sin penalizar las búsquedas exitosas.
# ════════════════════════════════════════════════════════════════════════

# Cache LRU — almacena (query_norm) → (resultados, score, timestamp)
_FASE6_CACHE = {}
_FASE6_CACHE_MAX = 100  # max 100 queries cacheadas
_FASE6_CACHE_TTL = 300  # 5 minutos

# Sinónimos compactos — solo los más comunes para no inflar memoria
_FASE6_SINONIMOS_LIGHT = {
    'liderazgo': ['liderar', 'lider', 'gestion', 'management'],
    'liderar': ['liderazgo', 'gestion', 'dirigir'],
    'gestion': ['liderazgo', 'management', 'administracion'],
    'inflacion': ['ipc', 'precios'],
    'ipc': ['inflacion', 'precios'],
    'economia': ['finanzas', 'macroeconomia'],
    'inversion': ['inversiones', 'invertir', 'rentabilidad'],
    'estrategia': ['estrategico', 'plan', 'tactica'],
    'naval': ['armada', 'marina', 'oficial'],
    'armada': ['naval', 'marina'],
    'filosofia': ['pensamiento', 'reflexion'],
    'negocio': ['negocios', 'empresa', 'business'],
    'cliente': ['clientes', 'consumidor'],
    'aprender': ['aprendizaje', 'educar', 'estudio'],
    'autor': ['escritor', 'pensador'],
    'libro': ['libros', 'obra', 'texto'],
}


def _fase6_cache_get(query_norm):
    """Lookup en caché LRU. Devuelve (resultados, score) o None."""
    import time as _t_cache
    entry = _FASE6_CACHE.get(query_norm)
    if not entry:
        return None
    resultados, score, ts = entry
    if _t_cache.time() - ts > _FASE6_CACHE_TTL:
        del _FASE6_CACHE[query_norm]
        return None
    return resultados, score


def _fase6_cache_set(query_norm, resultados, score):
    """Guarda en caché. Si excede max, elimina la entrada mas antigua."""
    import time as _t_cache
    if len(_FASE6_CACHE) >= _FASE6_CACHE_MAX:
        # Eliminar el mas antiguo (LRU simple por timestamp)
        oldest = min(_FASE6_CACHE.items(), key=lambda x: x[1][2])[0]
        del _FASE6_CACHE[oldest]
    _FASE6_CACHE[query_norm] = (resultados, score, _t_cache.time())


def _fase6_expandir_palabras(palabras):
    """Expansion ligera con sinonimos selectivos. Devuelve lista expandida."""
    expandidas = list(palabras)
    seen = set(palabras)
    for p in palabras:
        for s in _FASE6_SINONIMOS_LIGHT.get(p, []):
            if s not in seen:
                expandidas.append(s)
                seen.add(s)
    return expandidas


def _fase6_fuzzy_match_simple(query_word, target_word, max_dist=2):
    """Levenshtein simple - retorna True si distancia <= max_dist.
    Solo ejecuta si las palabras tienen longitudes compatibles para evitar overhead."""
    if not query_word or not target_word:
        return False
    if abs(len(query_word) - len(target_word)) > max_dist:
        return False
    if query_word == target_word:
        return True
    m, n = len(query_word), len(target_word)
    if m < 5 or n < 5:
        return False
    prev = list(range(n + 1))
    for i in range(1, m + 1):
        cur = [i] + [0] * n
        for j in range(1, n + 1):
            cost = 0 if query_word[i-1] == target_word[j-1] else 1
            cur[j] = min(cur[j-1] + 1, prev[j] + 1, prev[j-1] + cost)
        if min(cur) > max_dist:
            return False
        prev = cur
    return prev[n] <= max_dist


def buscar_rag(query, limit=5, original=None):
    """
    Búsqueda RAG en CASCADA:
    Fase 0 — pgvector + Gemini embeddings (búsqueda SEMÁNTICA REAL) ← NUEVO FASE 29
    Fase 1 — Búsqueda por NOMBRE DE DOCUMENTO (nombres propios, títulos, autores)
    Fase 2 — Búsqueda semántica general balanceada (máx. 3 chunks por documento)
    
    FASE 29: pgvector con embeddings reales de 768 dimensiones (Gemini).
    Si pgvector falla o no hay resultados de calidad, cae automáticamente
    a las fases 1 y 2 (búsqueda por keywords, comportamiento original).
    
    Retorna: (lista de (texto, source), score_maximo)
    """
    try:
        # FASE 6: Cache lookup ANTES de cualquier query SQL — instant hit en queries repetidas
        import unicodedata as _uni_cache
        # FASE 31.7b: la clave de caché se computa sobre la pregunta ORIGINAL
        # del usuario (si viaja). La reescrita del LLM cambia en cada corrida
        # → claves distintas para la MISMA pregunta → el flip-flop de Germán.
        _base_cache = original if (original and original.strip()) else query
        _query_norm_cache = _uni_cache.normalize('NFKD', (_base_cache or '').lower().strip())
        _query_norm_cache = ''.join(ch for ch in _query_norm_cache if not _uni_cache.combining(ch))
        _query_norm_cache = ' '.join(_query_norm_cache.split()[:10])  # primeras 10 palabras
        if _query_norm_cache:
            cached = _fase6_cache_get(_query_norm_cache)
            if cached is not None:
                logger.info(f"⚡ FASE 6 RAG cache HIT: '{_query_norm_cache[:60]}'")
                return cached
        
        conn = get_db_connection()
        if not conn:
            return [], 0.0
        
        c = conn.cursor()
        
        # ═══════════════════════════════════════════════════════════════════
        # FASE 31 (FIX CRÍTICO "CASO MILEI") — REORDEN DE PRECEDENCIA:
        #
        # ANTES: pgvector GLOBAL corría PRIMERO. Una pregunta como
        # "de qué trata el libro de Milei sobre la inflación" traía chunks
        # genéricos sobre inflación de OTROS documentos (sim ≥ 0.65) y
        # retornaba SIN llegar nunca al match por nombre de documento.
        # Resultado: el bot divagaba con fragmentos del libro equivocado.
        #
        # AHORA (orden correcto de un RAG profesional):
        #   PASO A — Match por NOMBRE DE DOCUMENTO (in-memory, <5ms).
        #   PASO B — Si hay documento(s): pgvector RESTRINGIDO a esos
        #            documentos → ranking semántico DENTRO del libro
        #            (los chunks sobre "inflación" del libro de Milei
        #            quedan primeros). Fallback: chunks en orden.
        #   PASO C — Solo si NO hay match de nombre: pgvector GLOBAL
        #            (comportamiento FASE 29 original).
        # ═══════════════════════════════════════════════════════════════════
        import unicodedata
        def normalizar(texto):
            texto = unicodedata.normalize('NFKD', texto.lower())
            return ''.join(ch for ch in texto if not unicodedata.combining(ch))
        
        STOPWORDS = {'de', 'la', 'el', 'en', 'los', 'las', 'del', 'al', 'un', 'una',
                    'por', 'con', 'para', 'que', 'es', 'se', 'no', 'su', 'lo', 'como',
                    'mas', 'pero', 'sus', 'le', 'ya', 'este', 'si', 'ha', 'son',
                    'muy', 'hay', 'fue', 'ser', 'han', 'esta', 'tan', 'sin', 'sobre',
                    'trata', 'libro', 'libros', 'sobre', 'acerca', 'habla', 'dice',
                    'cuéntame', 'cuentame', 'cual', 'cuál', 'qué', 'que',
                    'respecto', 'segun', 'según', 'autor', 'escribio', 'escribió',
                    'a', 'y', 'o', 'e', 'u', 'the', 'of', 'and', 'to', 'in'}
        
        query_norm = normalizar(query)
        
        # Extraer términos relevantes — priorizar palabras largas (nombres propios, títulos)
        todas_palabras = [p for p in query_norm.split() if len(p) > 1 and p not in STOPWORDS]
        # FASE 31.2: NOMBRES PROPIOS PRIMERO. En "el libro de Milei de la
        # inflación", ordenar solo por longitud ponía "inflacion" y
        # "consiste" antes que "milei" → el autor quedaba fuera del top-2
        # del matching por contenido. Un token capitalizado a mitad de
        # oración es un nombre propio → máxima prioridad de búsqueda.
        nombres_propios_q = set()
        try:
            _toks_raw = query.split()
            for _i, _tk in enumerate(_toks_raw):
                _lp = _tk.strip('¿?¡!.,;:()"\'«»')
                if (len(_lp) >= 3 and _lp[0].isupper()
                        and _i > 0
                        and not _toks_raw[_i-1].rstrip().endswith(('.', '?', '!', ':'))):
                    _lpn = normalizar(_lp)
                    if _lpn not in STOPWORDS:
                        nombres_propios_q.add(_lpn)
        except Exception:
            pass
        _resto = [p for p in set(todas_palabras) if p not in nombres_propios_q]
        palabras_clave = (sorted(nombres_propios_q, key=len, reverse=True)
                          + sorted(_resto, key=len, reverse=True))
        
        if not palabras_clave:
            conn.close()
            return [], 0.0
        
        # ═══════════════════════════════════════════════════
        # PASO A — MATCH POR NOMBRE DE DOCUMENTO (antes que pgvector)
        # FIX FASE 9: normalización bidireccional de tildes en Python
        # (resuelve "inflacion"↔"inflación" en nombres de archivo).
        # ═══════════════════════════════════════════════════
        docs_fase1 = []    # sources encontrados por nombre
        chunks_fase1 = []  # (texto, score, source) con score alto
        
        # ═══════════════════════════════════════════════════
        # FASE 31.3 — PASO A0: MEMORIA DE APRENDIZAJE (botón "Útil")
        # Si un usuario marcó "Útil" una respuesta, la asociación
        # término→documentos quedó guardada en rag_aprendizaje. Antes de
        # cualquier matching, consultamos esa memoria: es la señal más
        # confiable (validada por humanos) y la más rápida (tabla diminuta).
        # ═══════════════════════════════════════════════════
        try:
            # FASE 31.8 BLINDAJE A0:
            # (a) Si la pregunta ORIGINAL trae un título entre comillas, la
            #     evidencia explícita del usuario MANDA sobre lo aprendido →
            #     A0 se salta y decide el matching por frases.
            # (b) votos >= 2: un solo voto (posible auto-guardado erróneo de
            #     versiones previas) ya NO puede dictar los documentos. El
            #     veneno "inflación→feriados+Cardalda" queda inerte.
            _tiene_comillas_a0 = any(_q in f"{original or ''}{query}"
                                     for _q in ('"', '\u201c', '\u00ab'))
            _terms_a0 = ([] if _tiene_comillas_a0
                         else [p for p in palabras_clave[:3] if len(p) >= 4])
            if _tiene_comillas_a0:
                logger.info("🛡️ FASE 31.8: título entre comillas → A0 cede al matching por frases")
            for _t_a0 in _terms_a0:
                if DATABASE_URL:
                    c.execute("""SELECT docs FROM rag_aprendizaje
                                 WHERE votos >= 2 AND terminos ILIKE %s
                                 ORDER BY votos DESC LIMIT 1""", (f'%{_t_a0}%',))
                else:
                    c.execute("""SELECT docs FROM rag_aprendizaje
                                 WHERE votos >= 2 AND LOWER(terminos) LIKE ?
                                 ORDER BY votos DESC LIMIT 1""", (f'%{_t_a0}%',))
                _row_a0 = c.fetchone()
                if _row_a0:
                    _docs_raw = (_row_a0['docs'] if DATABASE_URL else _row_a0[0]) or ''
                    for _d in _docs_raw.split('||'):
                        if _d and _d not in docs_fase1:
                            docs_fase1.append(_d)
                    if docs_fase1:
                        logger.info(f"🧠 FASE 31.3 A0-APRENDIZAJE: '{_t_a0}' → "
                                    f"{docs_fase1} (validado por usuarios)")
                        break
        except Exception as _e_a0:
            logger.debug(f"A0 aprendizaje (tabla puede no existir aún): {_e_a0}")
            # FASE 31.4 CRÍTICO: en PostgreSQL una consulta fallida ABORTA la
            # transacción y TODAS las consultas siguientes de buscar_rag
            # (nombres, A3, ¡pgvector!) morirían en cascada → "libro no está
            # en la biblioteca" aunque sí esté. Rollback inmediato lo sana.
            try:
                conn.rollback()
            except Exception:
                pass
        
        try:
            c.execute("SELECT DISTINCT source FROM rag_chunks WHERE source IS NOT NULL")
            todos_sources_db = [(row['source'] if DATABASE_URL else row[0]) for row in c.fetchall()]
            sources_normalizados = [(normalizar(s), s) for s in todos_sources_db if s]
            logger.info(f"🔎 RAG: {len(sources_normalizados)} sources cargados para matching normalizado")
        except Exception as _e_load:
            logger.warning(f"Error cargando sources: {_e_load}")
            sources_normalizados = []
            try:
                conn.rollback()
            except Exception:
                pass
        
        # ═══ FASE 31.7 MATCH 0 — FRASES (el fix del caso "El fin de la inflación") ═══
        # ANTES: "lista" (de "Lista los puntos...") matcheaba por substring el
        # doc "feriados...lista completa", y "fin" matcheaba "FINanciera" de
        # van horne → pgvector se restringía a los libros EQUIVOCADOS con
        # "confianza alta". AHORA: primero se buscan FRASES del query (título
        # entre comillas o n-gramas de 3-6 palabras) dentro del nombre del
        # doc. Una frase que calza es evidencia fortísima y EXCLUYENTE.
        # FASE 31.7b: los términos genéricos se definen ANTES del MATCH 0
        # porque también vetan FRASES compuestas solo de genéricos
        # ("lista completa" venía en la reescrita del LLM y matcheaba el
        # doc de feriados; "de forma educada" matcheó el libro de Cardalda).
        _GENERICAS_NOMBRE = {'lista', 'libro', 'libros', 'completa', 'completo',
                             'guia', 'guía', 'manual', 'curso', 'texto', 'tema',
                             'temas', 'punto', 'puntos', 'resumen', 'capitulo',
                             'fin', 'introduccion', 'principales', 'basico',
                             'basica', 'general', 'nueva', 'nuevo', 'web',
                             'pdf', 'chile', 'chileno', 'chilena', 'forma',
                             'educada', 'facil', 'practica', 'practico',
                             # FASE 31.8: verbos de petición y muletillas que
                             # NO identifican ningún documento
                             'dame', 'dime', 'quiero', 'necesito', 'muestrame',
                             'entregame', 'indicame', 'ayudame', 'cuales',
                             'sirve', 'sirven', 'favor', 'gracias', 'ahora',
                             'hacer', 'saber', 'conocer', 'explica',
                             'explicame', 'detalla', 'detallame', 'describe',
                             'contenido', 'informacion', 'detalle', 'detalles'}

        def _frase_valida(fr):
            """Una frase solo cuenta si aporta ≥1 token con CONTENIDO real
            (≥4 letras, ni stopword ni genérico). 'lista completa' → NO;
            'el fin de la inflacion' → SÍ (inflacion)."""
            for _t in fr.split():
                if len(_t) >= 4 and _t not in STOPWORDS and _t not in _GENERICAS_NOMBRE:
                    return True
            return False

        try:
            _frases_q = []
            # (a) texto entre comillas = título literal → máxima prioridad.
            # FASE 31.7b: se lee de la pregunta ORIGINAL del usuario (la
            # reescrita del LLM ELIMINA las comillas → el título nunca
            # llegaba a este matching).
            _texto_frases = f"{original or ''} {query}"
            for _m in re.findall(r'["\u201c\u00ab\u2018\']([^"\u201d\u00bb\u2019\']{6,80})["\u201d\u00bb\u2019\']', _texto_frases):
                _frases_q.append(normalizar(_m))
            # (b) n-gramas de 6→3 palabras de la ORIGINAL primero, luego la reescrita
            _orig_norm = normalizar(original) if original else ''
            for _fuente_ng in (_orig_norm, query_norm):
                if not _fuente_ng:
                    continue
                _tq = [w for w in _fuente_ng.split() if len(w) > 1]
                for _n in (6, 5, 4, 3):
                    for _i in range(len(_tq) - _n + 1):
                        _frases_q.append(' '.join(_tq[_i:_i + _n]))
            _vistos_f = set()
            for _fr in _frases_q:
                if len(_fr) < 8 or _fr in _vistos_f or not _frase_valida(_fr):
                    continue
                _vistos_f.add(_fr)
                for src_norm, src_orig in sources_normalizados:
                    if _fr in src_norm and src_orig not in docs_fase1:
                        docs_fase1.append(src_orig)
                        logger.info(f"🎯 FASE 31.7 MATCH-FRASE: '{_fr}' → '{src_orig}'")
                if docs_fase1:
                    break  # la frase más larga que calza manda; no diluir
        except Exception as _e_fr:
            logger.debug(f"match frase: {_e_fr}")

        # ═══ FASE 31.8 MATCH 0.5 — FRASE EN CONTENIDO ═══
        # Si la frase fuerte (título entre comillas o n-grama con contenido)
        # NO calza con ningún NOMBRE de archivo (el PDF puede llamarse
        # "milei_2023.pdf" o tener el nombre con tildes/guiones distintos),
        # se busca la frase DENTRO del texto de los chunks: un libro menciona
        # su propio título decenas de veces (portada, encabezados, prólogo).
        # Usa las frases CRUDAS (con tildes) porque chunk_text las conserva.
        if not docs_fase1:
            try:
                _frases_raw = []
                # (a) comillas de la pregunta ORIGINAL (crudas, prioridad)
                for _m in re.findall(r'["\u201c\u00ab\u2018\']([^"\u201d\u00bb\u2019\']{10,80})["\u201d\u00bb\u2019\']', _texto_frases):
                    _frases_raw.append(_m.strip().lower())
                # (b) n-gramas crudos 6→4 de la ORIGINAL con contenido real
                if original:
                    _tor = [w.strip('¿?¡!.,;:()[]"\'\u00ab\u00bb\u201c\u201d\u2018\u2019')
                            for w in original.lower().split()]
                    _tor = [w for w in _tor if len(w) > 1]
                    for _n in (6, 5, 4):
                        for _i in range(len(_tor) - _n + 1):
                            _ng_raw = ' '.join(_tor[_i:_i + _n])
                            if len(_ng_raw) >= 14 and _frase_valida(normalizar(_ng_raw)):
                                _frases_raw.append(_ng_raw)
                _vistas_fc = set()
                _intentos_fc = 0
                try:
                    if DATABASE_URL:
                        c.execute("SET LOCAL statement_timeout = 4000")
                except Exception:
                    pass
                for _fr_raw in _frases_raw:
                    if _fr_raw in _vistas_fc or _intentos_fc >= 3:
                        continue
                    _vistas_fc.add(_fr_raw)
                    _intentos_fc += 1
                    try:
                        if DATABASE_URL:
                            c.execute("""SELECT source, COUNT(*) AS n FROM rag_chunks
                                         WHERE chunk_text ILIKE %s AND source IS NOT NULL
                                         GROUP BY source ORDER BY n DESC LIMIT 2""",
                                      (f'%{_fr_raw}%',))
                        else:
                            c.execute("""SELECT source, COUNT(*) AS n FROM rag_chunks
                                         WHERE LOWER(chunk_text) LIKE ? AND source IS NOT NULL
                                         GROUP BY source ORDER BY n DESC LIMIT 2""",
                                      (f'%{_fr_raw}%',))
                        for _row_fc in (c.fetchall() or []):
                            _src_fc = _row_fc['source'] if DATABASE_URL else _row_fc[0]
                            if _src_fc and _src_fc not in docs_fase1:
                                docs_fase1.append(_src_fc)
                                logger.info(f"🎯 FASE 31.8 FRASE-CONTENIDO: "
                                            f"«{_fr_raw[:50]}» → '{_src_fc}'")
                    except Exception as _e_fc1:
                        logger.debug(f"frase-contenido «{_fr_raw[:30]}»: {_e_fc1}")
                        try:
                            conn.rollback()  # FASE 31.4: jamás abortar la transacción
                        except Exception:
                            pass
                    if docs_fase1:
                        break  # la primera frase que identifica documento MANDA
                try:
                    if DATABASE_URL:
                        c.execute("SET LOCAL statement_timeout = DEFAULT")
                except Exception:
                    pass
            except Exception as _e_fc:
                logger.debug(f"match frase-contenido: {_e_fc}")
                try:
                    conn.rollback()
                except Exception:
                    pass

        # MATCH 1: palabra clave en el nombre del doc — AHORA con LÍMITE DE
        # PALABRA (no substring: "fin" ya no matchea "FINanciera") y VETO de
        # términos genéricos que producían falsos positivos.
        if not docs_fase1:
            _palabras_m1 = list(palabras_clave)
            if original:  # FASE 31.7b: sumar términos de la pregunta original
                for _w in (normalizar(original)).split():
                    if len(_w) >= 4 and _w not in STOPWORDS and _w not in _palabras_m1:
                        _palabras_m1.append(_w)
            for palabra in _palabras_m1:
                if len(palabra) < 4 or palabra in _GENERICAS_NOMBRE:
                    continue
                _patron_wb = re.compile(r'(?<![a-z0-9])' + re.escape(palabra) + r'(?![a-z0-9])')
                for src_norm, src_orig in sources_normalizados:
                    if src_orig in docs_fase1:
                        continue
                    if _patron_wb.search(src_norm):
                        docs_fase1.append(src_orig)
                        logger.info(f"🎯 Fase 1 RAG: '{palabra}' → documento '{src_orig}' (match normalizado)")
        
        # MATCH 2 (fuzzy reactivo): solo si el exacto no encontró nada
        if not docs_fase1:
            palabras_largas_fuzzy = [p for p in palabras_clave if len(p) >= 5][:3]
            if palabras_largas_fuzzy and sources_normalizados:
                for palabra in palabras_largas_fuzzy:
                    for src_norm, src_orig in sources_normalizados[:200]:
                        if src_orig in docs_fase1:
                            continue
                        for token_src in src_norm.split():
                            if len(token_src) >= 5 and _fase6_fuzzy_match_simple(palabra, token_src, max_dist=2):
                                docs_fase1.append(src_orig)
                                logger.info(f"🎯 FASE 6 FUZZY: '{palabra}' ≈ '{token_src}' → '{src_orig}'")
                                break
                        if src_orig in docs_fase1:
                            break
        
        # MATCH 3 (FASE 31.1 — por CONTENIDO): si el nombre del archivo no
        # contiene el término (p.ej. el libro de Milei se llama "El fin de
        # la inflación.pdf" SIN el apellido), identificar el documento por
        # FRECUENCIA del término dentro de sus chunks: un libro DE un autor
        # lo menciona decenas de veces (portada, prólogo, biografía).
        # Solo se ejecuta si A1+A2 fallaron; 1 query SQL por término (máx 2).
        if not docs_fase1:
            # FASE 31.2: nombres propios primero; umbral bajado a 2 menciones
            _np_orden = [p for p in palabras_clave if p in nombres_propios_q and len(p) >= 4]
            _otros_orden = [p for p in palabras_clave if p not in nombres_propios_q and len(p) >= 5]
            terminos_contenido = (_np_orden + _otros_orden)[:3]
            # FASE 31.3 VELOCIDAD: el COUNT(*)+GROUP BY anterior escaneaba
            # la tabla COMPLETA (decenas de miles de chunks) por cada término
            # → minutos en Supabase. Ahora: (a) statement_timeout 4s como
            # tope duro, (b) keywords primero (columna pequeña), (c) LIMIT 80
            # que DETIENE el escaneo apenas encuentra coincidencias, y el
            # conteo por documento se hace en Python sobre esa muestra.
            from collections import Counter as _Cnt_a3
            try:
                if DATABASE_URL:
                    c.execute("SET LOCAL statement_timeout = 4000")
            except Exception:
                pass
            for palabra in terminos_contenido:
                try:
                    patron_like = f"%{palabra}%"
                    filas_a3 = []
                    # FASE 31.4: metadata::text agregado (título/autor suelen
                    # vivir ahí); rollback por intento para que una columna
                    # inexistente jamás aborte la transacción de las demás.
                    _cols_a3 = (('keywords', 'metadata::text', 'chunk_text')
                                if DATABASE_URL else
                                ('keywords', 'metadata', 'chunk_text'))
                    for col_a3 in _cols_a3:
                        try:
                            if DATABASE_URL:
                                c.execute(
                                    f"""SELECT source FROM rag_chunks
                                        WHERE {col_a3} ILIKE %s AND source IS NOT NULL
                                        LIMIT 80""", (patron_like,))
                            else:
                                c.execute(
                                    f"""SELECT source FROM rag_chunks
                                        WHERE LOWER({col_a3}) LIKE ? AND source IS NOT NULL
                                        LIMIT 80""", (patron_like,))
                            filas_a3 = [(r['source'] if DATABASE_URL else r[0])
                                        for r in c.fetchall()]
                        except Exception as _e_col:
                            logger.warning(f"A3 col {col_a3}: {_e_col}")
                            filas_a3 = []
                            try:
                                conn.rollback()
                            except Exception:
                                pass
                        if filas_a3:
                            break
                    for src_c, cnt_c in _Cnt_a3(filas_a3).most_common(2):
                        # Umbral: ≥2 menciones en la muestra = término central
                        if src_c and cnt_c >= 2 and src_c not in docs_fase1:
                            docs_fase1.append(src_c)
                            logger.info(f"🎯 FASE 31 A3-CONTENIDO: '{palabra}' aparece "
                                        f"{cnt_c}+ veces en '{src_c}' → documento identificado")
                except Exception as _e_a3:
                    logger.debug(f"A3 contenido '{palabra}' error: {_e_a3}")
                if docs_fase1:
                    break  # con un documento identificado basta
            if not docs_fase1 and terminos_contenido:
                # FASE 31.4 DIAGNÓSTICO: si ni nombre ni contenido matchean,
                # loggear los títulos más parecidos → el LOG dirá de una vez
                # si el libro está indexado o no (y con qué nombre).
                try:
                    _frag = terminos_contenido[0][:4]
                    _parecidos = [orig for nrm, orig in sources_normalizados
                                  if _frag in nrm][:3]
                    logger.warning(
                        f"📚 FASE 31.4 SIN MATCH para {terminos_contenido} en "
                        f"{len(sources_normalizados)} docs. "
                        f"Títulos con '{_frag}': {_parecidos or 'NINGUNO'}")
                except Exception:
                    pass
            try:
                if DATABASE_URL:
                    c.execute("SET LOCAL statement_timeout = DEFAULT")
            except Exception:
                pass

        
        # ═══════════════════════════════════════════════════
        # PASO B — pgvector RESTRINGIDO al/los documento(s) matcheado(s)
        # Ranking semántico DENTRO del libro: para "libro de Milei sobre
        # inflación" ordena primero los pasajes del libro que hablan de
        # inflación. Si pgvector no está disponible → fallback: chunks
        # del documento en orden natural (comportamiento previo).
        # ═══════════════════════════════════════════════════
        if docs_fase1:
            docs_foco = docs_fase1[:3]  # máximo 3 documentos
            pgvec_in_doc_ok = False
            
            if DATABASE_URL:
                try:
                    query_emb = generar_embedding_gemini(query, tipo='RETRIEVAL_QUERY')
                    if query_emb:
                        pgvec_query = embedding_to_pgvector(query_emb)
                        c.execute(
                            """SELECT chunk_text, source,
                                      1 - (embedding <=> %s::vector) AS similitud
                               FROM rag_chunks
                               WHERE source = ANY(%s) AND embedding IS NOT NULL
                               ORDER BY embedding <=> %s::vector
                               LIMIT %s""",
                            (pgvec_query, docs_foco, pgvec_query, max(limit, 12))
                        )
                        rows_doc = c.fetchall()
                        for row in rows_doc:
                            texto = row['chunk_text'] or ''
                            source = row['source'] or ''
                            sim = float(row['similitud'] or 0.0)
                            # Score ≥ 50 garantiza tratamiento Fase 1 (auto-relevante)
                            # + componente semántico para ordenar por afinidad al query
                            chunks_fase1.append((texto, 50.0 + sim * 10.0, source))
                        if len(chunks_fase1) >= 2:
                            pgvec_in_doc_ok = True
                            logger.info(
                                f"🎯 FASE 31 pgvector-EN-DOC: {len(chunks_fase1)} chunks "
                                f"rankeados semánticamente dentro de {docs_foco}"
                            )
                except Exception as _e_pgdoc:
                    logger.debug(f"FASE 31 pgvector-en-doc falló (fallback a orden natural): {_e_pgdoc}")
            
            if not pgvec_in_doc_ok:
                # Fallback: traer TODOS los chunks del documento en orden natural
                chunks_fase1 = []
                for src in docs_foco:
                    try:
                        if DATABASE_URL:
                            c.execute("SELECT chunk_text, keywords, source FROM rag_chunks WHERE source = %s ORDER BY id ASC",
                                     (src,))
                        else:
                            c.execute("SELECT chunk_text, keywords, source FROM rag_chunks WHERE source = ? ORDER BY id ASC",
                                     (src,))
                        filas_doc = c.fetchall()
                        for fila in filas_doc:
                            if DATABASE_URL:
                                texto = fila['chunk_text'] or ''
                                source = fila['source'] or ''
                            else:
                                texto, _, source = fila[0] or '', fila[1] or '', fila[2] or ''
                            score = 50.0 + len(texto) / 100
                            chunks_fase1.append((texto, score, source))
                    except Exception as e:
                        logger.debug(f"Error trayendo chunks de '{src}': {e}")
        
        # ═══════════════════════════════════════════════════════════════════
        # PASO C — pgvector GLOBAL (FASE 29 original) — SOLO si no hubo
        # match por nombre de documento. Evita que temas genéricos ahoguen
        # a documentos específicamente mencionados por el usuario.
        # ═══════════════════════════════════════════════════════════════════
        if not docs_fase1 and DATABASE_URL and query and len(query.strip()) > 2:
            try:
                query_emb = generar_embedding_gemini(query, tipo='RETRIEVAL_QUERY')
                if query_emb:
                    pgvec_query = embedding_to_pgvector(query_emb)
                    c.execute(
                        """SELECT chunk_text, source, 
                                  1 - (embedding <=> %s::vector) AS similitud
                           FROM rag_chunks 
                           WHERE embedding IS NOT NULL
                           ORDER BY embedding <=> %s::vector 
                           LIMIT %s""",
                        (pgvec_query, pgvec_query, limit * 2)
                    )
                    rows_pgvec = c.fetchall()
                    
                    if rows_pgvec:
                        resultados_pgvec = []
                        max_sim = 0.0
                        for row in rows_pgvec:
                            chunk_text = row['chunk_text'] if DATABASE_URL else row[0]
                            source = row['source'] if DATABASE_URL else row[1]
                            sim = float(row['similitud'] if DATABASE_URL else row[2])
                            if sim >= 0.55:
                                resultados_pgvec.append((chunk_text, source))
                                if sim > max_sim:
                                    max_sim = sim
                            if len(resultados_pgvec) >= limit:
                                break
                        
                        if len(resultados_pgvec) >= 3 and max_sim >= 0.65:
                            logger.info(f"🎯 FASE 29 pgvector HIT: {len(resultados_pgvec)} resultados, sim_max={max_sim:.3f}")
                            conn.close()
                            if _query_norm_cache and len(resultados_pgvec) >= 2 and max_sim >= 0.55:
                                _fase6_cache_set(_query_norm_cache, resultados_pgvec, max_sim)
                            return resultados_pgvec, max_sim
                        elif resultados_pgvec:
                            logger.info(f"FASE 29 pgvector PARCIAL: {len(resultados_pgvec)} resultados (sim_max={max_sim:.3f}), complementando con keywords...")
                else:
                    logger.debug("FASE 29: no se pudo generar embedding de la query, usando keywords")
            except Exception as _e_pgvec:
                logger.debug(f"FASE 29 pgvector falló (cayendo a keywords): {_e_pgvec}")
        
        # ═══════════════════════════════════════════════════
        # FASE 2: BÚSQUEDA SEMÁNTICA GENERAL BALANCEADA
        # Busca por keywords/texto, pero limita chunks por documento
        # ═══════════════════════════════════════════════════
        # Solo términos que no sean stopwords contextuales
        terminos_semanticos = [p for p in palabras_clave if len(p) >= 3][:8]
        
        chunks_fase2 = []
        
        if terminos_semanticos:
            condiciones = []
            params = []
            for term in terminos_semanticos:
                if DATABASE_URL:
                    condiciones.append("(LOWER(keywords) LIKE %s OR LOWER(chunk_text) LIKE %s)")
                    params.extend([f'%{term}%', f'%{term}%'])
                else:
                    condiciones.append("(LOWER(keywords) LIKE ? OR LOWER(chunk_text) LIKE ?)")
                    params.extend([f'%{term}%', f'%{term}%'])
            
            where_clause = " OR ".join(condiciones)
            max_candidates = limit * 20
            
            # Excluir documentos ya encontrados en fase 1
            if docs_fase1:
                exclusion = " AND source NOT IN ({})".format(
                    ','.join(['%s'] * len(docs_fase1) if DATABASE_URL else ['?'] * len(docs_fase1))
                )
                where_clause_f2 = f"({where_clause}){exclusion}"
                params_f2 = params + docs_fase1
            else:
                where_clause_f2 = where_clause
                params_f2 = params
            
            try:
                if DATABASE_URL:
                    c.execute(f"""SELECT chunk_text, keywords, metadata, source FROM rag_chunks 
                                WHERE {where_clause_f2} LIMIT %s""", params_f2 + [max_candidates])
                else:
                    c.execute(f"""SELECT chunk_text, keywords, metadata, source FROM rag_chunks 
                                WHERE {where_clause_f2} LIMIT ?""", params_f2 + [max_candidates])
                filas_f2 = c.fetchall()
                
                # Scoring semántico
                for fila in filas_f2:
                    if DATABASE_URL:
                        texto = fila['chunk_text'] or ''
                        keywords = fila['keywords'] or ''
                        source = fila['source'] or ''
                    else:
                        texto = fila[0] or ''
                        keywords = fila[1] or ''
                        source = fila[3] if len(fila) > 3 else ''
                    
                    texto_n = normalizar(texto)
                    kw_n = normalizar(keywords)
                    
                    score = 0.0
                    for p in terminos_semanticos:
                        if p in kw_n:
                            score += 3.0
                        if p in texto_n:
                            score += 2.0 + min(texto_n.count(p) * 0.3, 2.0)
                    
                    if len(texto) < 100:
                        score *= 0.4
                    elif len(texto) < 200:
                        score *= 0.7
                    if len(texto) > 500:
                        score *= 1.1
                    if source.startswith('PDF:'):
                        score *= 1.1
                    
                    if score > 0:
                        chunks_fase2.append((texto, score, source))
                        
            except Exception as e:
                logger.warning(f"Error fase2 RAG: {e}")
        
        conn.close()
        
        # ═══════════════════════════════════════════════════
        # COMBINAR RESULTADOS
        # ═══════════════════════════════════════════════════
        resultados = []
        seen = set()
        score_maximo = 0.0
        
        # Primero: todos los chunks de documentos fase 1 (en orden del documento)
        for texto, score, source in chunks_fase1:
            key = texto[:80]
            if key not in seen and texto.strip():
                seen.add(key)
                resultados.append((texto, source))
                score_maximo = max(score_maximo, score)
                if len(resultados) >= limit:
                    break
        
        # FASE 2 con promoción automática:
        # Si un documento domina los mejores resultados semánticos → promoverlo como Fase 1
        # (esto resuelve el caso de PDFs con nombre sin el término buscado, ej: "El_fin_de_la_inflacion.pdf" para query "milei")
        if chunks_fase2:
            chunks_fase2.sort(key=lambda x: x[1], reverse=True)
            
            # Analizar distribución en los TOP-20 chunks por score
            top_chunks = chunks_fase2[:20]
            score_por_doc = {}
            count_por_doc = {}
            for txt, sc, src in top_chunks:
                score_por_doc[src] = score_por_doc.get(src, 0) + sc
                count_por_doc[src] = count_por_doc.get(src, 0) + 1
            
            # Identificar documento dominante: > 40% de los top chunks O score acumulado > 2x el segundo
            docs_ordenados = sorted(score_por_doc.items(), key=lambda x: -x[1])
            doc_dominante = None
            
            if docs_ordenados:
                top_doc, top_score = docs_ordenados[0]
                top_count = count_por_doc.get(top_doc, 0)
                
                segundo_score = docs_ordenados[1][1] if len(docs_ordenados) > 1 else 0
                
                # Criterio de dominancia: muchos chunks del mismo doc en top resultados
                if (top_count >= 5 or  # 5+ chunks en top-20
                    (top_count >= 3 and top_score > segundo_score * 2) or  # 3+ chunks y doble score
                    (top_count / max(len(top_chunks), 1)) >= 0.4):  # 40%+ del top son del mismo doc
                    doc_dominante = top_doc
                    logger.info(f"🚀 RAG Fase2→Fase1 promoción: '{top_doc}' "
                               f"(count={top_count}, score={top_score:.1f}, ratio={top_count/max(len(top_chunks),1):.0%})")
            
            # Si hay documento dominante NO encontrado en fase 1, traer TODOS sus chunks
            if doc_dominante and doc_dominante not in docs_fase1:
                try:
                    conn2 = get_db_connection()
                    if conn2:
                        c2 = conn2.cursor()
                        if DATABASE_URL:
                            c2.execute("SELECT chunk_text, source FROM rag_chunks WHERE source = %s ORDER BY id ASC",
                                      (doc_dominante,))
                        else:
                            c2.execute("SELECT chunk_text, source FROM rag_chunks WHERE source = ? ORDER BY id ASC",
                                      (doc_dominante,))
                        filas_dom = c2.fetchall()
                        conn2.close()
                        
                        for fila in filas_dom:
                            if len(resultados) >= limit:
                                break
                            txt = fila['chunk_text'] if DATABASE_URL else fila[0]
                            src = fila['source'] if DATABASE_URL else fila[1]
                            key = txt[:80] if txt else ''
                            if key and key not in seen and txt.strip():
                                seen.add(key)
                                resultados.append((txt, src))
                                score_maximo = max(score_maximo, 50.0)  # Promovido = score alto
                        
                        docs_fase1.append(doc_dominante)  # Marcar como ya procesado
                except Exception as e_dom:
                    logger.debug(f"Error promoviendo doc dominante: {e_dom}")
            
            # Chunks restantes de fase 2: máximo 3 por documento (excluir ya procesados)
            if len(resultados) < limit:
                conteo_por_doc = {}
                MAX_POR_DOC = 3
                
                for texto, score, source in chunks_fase2:
                    if len(resultados) >= limit:
                        break
                    if source in docs_fase1:  # Ya procesado (fase 1 o promovido)
                        continue
                    key = texto[:80]
                    if key in seen or not texto.strip():
                        continue
                    doc_count = conteo_por_doc.get(source, 0)
                    if doc_count >= MAX_POR_DOC:
                        continue
                    seen.add(key)
                    conteo_por_doc[source] = doc_count + 1
                    resultados.append((texto, source))
                    score_maximo = max(score_maximo, score)
        
        logger.info(f"🔍 RAG resultado final: {len(resultados)} chunks "
                   f"(fase1_docs={len(docs_fase1)}, f2_candidates={len(chunks_fase2)}), "
                   f"score_max={score_maximo:.1f}")
        
        # ═══════════════════════════════════════════════════
        # FASE 6 OPTIMIZADA: SI HAY POCOS RESULTADOS → expandir con sinónimos
        # Solo se ejecuta si hay <2 resultados, evitando overhead en busquedas exitosas
        # ═══════════════════════════════════════════════════
        if len(resultados) < 2 and palabras_clave:
            palabras_expandidas = _fase6_expandir_palabras(palabras_clave[:5])
            sinonimos_extra = [p for p in palabras_expandidas if p not in palabras_clave]
            if sinonimos_extra:
                logger.info(f"📚 FASE 6: pocos resultados ({len(resultados)}), expandiendo con sinónimos: {sinonimos_extra[:5]}")
                try:
                    conn3 = get_db_connection()
                    if conn3:
                        c3 = conn3.cursor()
                        # Buscar chunks con sinónimos (limit pequeño para no saturar)
                        condiciones3 = []
                        params3 = []
                        for term in sinonimos_extra[:5]:  # máx 5 sinónimos
                            if DATABASE_URL:
                                condiciones3.append("(LOWER(keywords) LIKE %s OR LOWER(chunk_text) LIKE %s)")
                                params3.extend([f'%{term}%', f'%{term}%'])
                            else:
                                condiciones3.append("(LOWER(keywords) LIKE ? OR LOWER(chunk_text) LIKE ?)")
                                params3.extend([f'%{term}%', f'%{term}%'])
                        where_extra = " OR ".join(condiciones3)
                        # Excluir docs ya en resultados
                        sources_ya = list(set([r[1] for r in resultados]))
                        if sources_ya:
                            placeholder = ','.join(['%s']*len(sources_ya) if DATABASE_URL else ['?']*len(sources_ya))
                            where_extra = f"({where_extra}) AND source NOT IN ({placeholder})"
                            params3 += sources_ya
                        if DATABASE_URL:
                            c3.execute(f"SELECT chunk_text, source FROM rag_chunks WHERE {where_extra} LIMIT 30", params3)
                        else:
                            c3.execute(f"SELECT chunk_text, source FROM rag_chunks WHERE {where_extra} LIMIT 30", params3)
                        for fila3 in c3.fetchall():
                            if len(resultados) >= limit:
                                break
                            txt3 = fila3['chunk_text'] if DATABASE_URL else fila3[0]
                            src3 = fila3['source'] if DATABASE_URL else fila3[1]
                            if txt3 and len(txt3) > 50:
                                k = txt3[:80]
                                if k not in seen:
                                    seen.add(k)
                                    resultados.append((txt3, src3))
                                    score_maximo = max(score_maximo, 1.5)
                        conn3.close()
                        logger.info(f"📚 FASE 6 expansion: ahora {len(resultados)} resultados totales")
                except Exception as _e_exp:
                    logger.debug(f"FASE 6 expansion fallo (no crítico): {_e_exp}")
        
        # FASE 31.6 ANTI-ENVENENAMIENTO: solo cachear respuestas CON sustancia.
        # Un resultado vacío o de score bajo NO se cachea → la próxima vez que
        # el usuario repita la pregunta, el bot REINTENTA de verdad en lugar de
        # servir un fracaso guardado. Esta era la causa del flip-flop: bien con
        # "Mejorar", mal al repetir (se servía el vacío cacheado).
        if _query_norm_cache and len(resultados) >= 2 and score_maximo >= 40:
            _fase6_cache_set(_query_norm_cache, resultados, score_maximo)
        elif _query_norm_cache:
            # Purga cualquier entrada envenenada previa de esta misma query
            _FASE6_CACHE.pop(_query_norm_cache, None)
        
        return resultados, score_maximo
        
    except Exception as e:
        logger.error(f"Error en buscar_rag: {e}")
        import traceback
        logger.error(traceback.format_exc())
        return [], 0.0


def rerank_chunks_con_llm(query, chunks_con_score, top_k=5, timeout_sec=6):
    """FASE 3B: Re-ranking de chunks con LLM ligero.
    
    Toma los chunks encontrados por buscar_rag (keyword-match) y le pide al LLM que
    evalúe rápidamente cuáles son los MÁS relevantes para la consulta.
    Devuelve los top_k más relevantes en orden, preservando la tupla (texto, source).
    
    Si el re-ranking falla (timeout, error, etc.), devuelve los primeros top_k tal cual.
    Esto garantiza que nunca se rompa el flujo principal.
    
    Args:
        query: la consulta del usuario
        chunks_con_score: lista de (texto, source) ya rankeada por buscar_rag
        top_k: cuantos chunks devolver (default 5)
        timeout_sec: timeout para la llamada al LLM (default 6s)
    
    Returns:
        lista de (texto, source) reordenada por relevancia real
    """
    # Si hay pocos chunks, no vale la pena llamar al LLM - devolver tal cual
    if not chunks_con_score or len(chunks_con_score) <= top_k:
        return chunks_con_score[:top_k] if chunks_con_score else []
    
    # Si no hay LLM disponible, devolver los primeros top_k (ya ordenados por score keyword)
    if not GROQ_API_KEY:
        return chunks_con_score[:top_k]
    
    try:
        # Construir prompt compacto: numerar chunks y pedir ranking
        # Solo primeros 15 chunks (más que eso satura el LLM)
        candidatos = chunks_con_score[:15]
        resumen_chunks = ""
        for i, item in enumerate(candidatos, 1):
            txt = (item[0] if isinstance(item, tuple) else item)
            # Solo primeros 200 chars de cada chunk para el rerank (es preview)
            resumen_chunks += f"[{i}] {txt[:200]}...\n\n"
        
        prompt_rerank = f"""Evalua cual de los fragmentos responde mejor esta consulta.

CONSULTA: "{query}"

FRAGMENTOS:
{resumen_chunks}

Responde SOLO con los numeros de los {top_k} fragmentos mas relevantes, separados por comas, en orden de mejor a peor.
Formato exacto: 3,7,1,12,5
NO agregues texto ni explicacion, SOLO los numeros."""
        
        respuesta = llamar_groq(prompt_rerank, max_tokens=50, temperature=0.0)
        
        if not respuesta:
            logger.debug("Rerank: sin respuesta LLM, fallback a orden original")
            return chunks_con_score[:top_k]
        
        # Parsear respuesta: extraer números
        import re as _re_rr
        numeros = _re_rr.findall(r'\b(\d+)\b', respuesta)
        if not numeros:
            logger.debug(f"Rerank: no se extrajeron numeros de '{respuesta[:100]}'")
            return chunks_con_score[:top_k]
        
        # Convertir a índices 0-based, filtrar rango válido, deduplicar
        indices = []
        vistos = set()
        for n_str in numeros:
            try:
                idx = int(n_str) - 1  # 1-based → 0-based
                if 0 <= idx < len(candidatos) and idx not in vistos:
                    indices.append(idx)
                    vistos.add(idx)
                    if len(indices) >= top_k:
                        break
            except ValueError:
                continue
        
        if not indices:
            return chunks_con_score[:top_k]
        
        # Reordenar según el ranking del LLM
        reranked = [candidatos[i] for i in indices]
        
        # Si el LLM devolvió menos de top_k, completar con los primeros no usados
        if len(reranked) < top_k:
            for i, c in enumerate(candidatos):
                if i not in vistos and len(reranked) < top_k:
                    reranked.append(c)
        
        logger.info(f"✅ Rerank LLM: {len(candidatos)} candidatos → top {len(reranked)} "
                    f"(indices elegidos: {indices[:top_k]})")
        return reranked
    
    except Exception as e:
        logger.warning(f"Rerank LLM fallo, usando orden original: {e}")
        return chunks_con_score[:top_k]


def busqueda_unificada(query, limit_historial=10, limit_rag=25, original=None):
    """Busca en TODAS las fuentes de conocimiento simultáneamente.
    Incluye verificación de relevancia temática: si los docs no tratan el tema
    consultado, marca rag_confianza='irrelevante' para que el LLM use su conocimiento.
    """
    resultados = {
        'historial': [],
        'rag': [],
        'fuentes_usadas': [],
        'rag_score_max': 0.0,
        'rag_confianza': 'ninguna',
        'rag_tematica': 'desconocida',   # 'relevante' | 'irrelevante' | 'desconocida'
    }
    
    # ═══════════════════════════════════════════════════════════════
    # FASE 31.2: MOTORES EN PARALELO (pedido de Germán)
    # Antes: historial → RAG en SECUENCIA (los tiempos se sumaban).
    # Ahora: ambos motores se lanzan A LA VEZ; el tiempo total es el del
    # motor más lento, no la suma. Con timeouts por motor y degradación
    # automática al modo secuencial clásico si el pool fallara.
    # ═══════════════════════════════════════════════════════════════
    from concurrent.futures import ThreadPoolExecutor as _TPE_bu
    _hist_res, _rag_res, _rag_err = [], None, None

    def _motor_historial():
        return buscar_en_historial(query, limit=limit_historial) if limit_historial > 0 else []

    def _motor_rag():
        return buscar_rag(query, limit=limit_rag, original=original)

    try:
        with _TPE_bu(max_workers=2) as _pool_bu:
            _f_h = _pool_bu.submit(_motor_historial)
            _f_r = _pool_bu.submit(_motor_rag)
            try:
                _hist_res = _f_h.result(timeout=12) or []
            except Exception as e:
                logger.warning(f"Error buscando historial unificado: {e}")
            try:
                _rag_res = _f_r.result(timeout=25)
            except Exception as e:
                _rag_err = e
    except Exception as _e_pool:
        logger.warning(f"FASE 31.2 pool paralelo falló, modo secuencial: {_e_pool}")
        try:
            _hist_res = _motor_historial() or []
        except Exception as e:
            logger.warning(f"Error buscando historial unificado: {e}")
        try:
            _rag_res = _motor_rag()
        except Exception as e:
            _rag_err = e

    # 1. Historial del grupo (mensajes de usuarios)
    if _hist_res:
        resultados['historial'] = _hist_res
        resultados['fuentes_usadas'].append(f"Historial ({len(_hist_res)} msgs)")
    
    # 2. RAG (PDFs indexados + Excel indexado en BD)
    try:
        if _rag_err is not None:
            raise _rag_err
        chunks_rag, score_max = _rag_res if _rag_res is not None else ([], 0.0)
        resultados['rag_score_max'] = score_max
        
        # ═══════════════════════════════════════════════════════════════
        # FIX FASE 9: PRE-FILTRO ESPECIFICIDAD DEL QUERY
        # Si el query tiene NOMBRES PROPIOS o términos muy específicos (>= 5 letras
        # capitalizadas o palabras únicas) que NO aparecen en NINGUN source de los
        # chunks retornados, los chunks son IRRELEVANTES — el LLM debe responder
        # desde su conocimiento propio, no inventar respuestas con fragmentos no relacionados.
        #
        # Ejemplo: query "libro de Javier Milei sobre inflación" trae chunks con
        # "inflación" pero ningún source dice "milei" → marcamos irrelevante.
        # ═══════════════════════════════════════════════════════════════
        if chunks_rag and score_max < 45.0:  # solo aplicar si NO es Fase 1 hit
            import unicodedata as _uni_pre, re as _re_pre
            def _np(t):
                t = _uni_pre.normalize('NFKD', (t or '').lower())
                return ''.join(c for c in t if not _uni_pre.combining(c))
            
            # Detectar términos específicos del query: palabras de 5+ letras NO comunes
            STOP_PRE = {'libro','libros','sobre','acerca','habla','dice','cuentame','cuál','cual',
                        'como','que','del','para','con','este','esta','estos','estas','muy',
                        'libro','autor','escritor','tema','sobre','tratan','trata','hacer'}
            query_norm_pre = _np(query)
            terminos_especificos = [
                w for w in _re_pre.findall(r'\b\w{5,}\b', query_norm_pre)
                if w not in STOP_PRE
            ]
            
            if terminos_especificos:
                # Verificar si AL MENOS UN término específico aparece en algún source
                sources_chunks = set()
                for item in chunks_rag:
                    src = (item[1] if isinstance(item, tuple) else '')
                    src_norm = _np(src.replace('PDF:', '').replace('EXCEL:', '').replace('_', ' '))
                    sources_chunks.update(w for w in src_norm.split() if len(w) >= 4)
                
                # Match exacto + fuzzy (prefijo 5 chars para términos mas largos)
                hay_match_source = False
                for t in terminos_especificos:
                    for s in sources_chunks:
                        if t == s:
                            hay_match_source = True
                            break
                        # fuzzy: si comparten 5+ chars iniciales
                        if len(t) >= 5 and len(s) >= 5 and (t.startswith(s[:5]) or s.startswith(t[:5])):
                            hay_match_source = True
                            break
                    if hay_match_source:
                        break
                
                if not hay_match_source:
                    # Query menciona algo específico (ej: "Milei") pero NO está en sources
                    # → marcar irrelevante para que LLM use su conocimiento
                    logger.info(
                        f"⚠️ FASE 9 PRE-FILTRO: query menciona {terminos_especificos[:3]} "
                        f"pero NINGÚN source lo contiene → marcando RAG irrelevante "
                        f"(sources disponibles: {list(sources_chunks)[:5]})"
                    )
                    chunks_rag = []  # vaciar chunks irrelevantes
                    score_max = 0.0
                    resultados['rag_score_max'] = 0.0
                    resultados['rag_confianza'] = 'irrelevante'
                    resultados['rag_tematica'] = 'irrelevante_pre_filtro'
        
        if score_max >= 45.0:
            resultados['rag_confianza'] = 'alta'
        elif score_max >= 8.0:
            resultados['rag_confianza'] = 'alta'
        elif score_max >= 4.0:
            resultados['rag_confianza'] = 'media'
        elif score_max >= 1.5:
            resultados['rag_confianza'] = 'baja'
        else:
            resultados['rag_confianza'] = 'ninguna'
        
        if chunks_rag:
            # ── VERIFICACIÓN DE RELEVANCIA TEMÁTICA ──────────────────────────────
            # Comparar términos clave del query contra términos clave del contenido
            # Si no hay overlap significativo → los docs no son sobre el tema consultado
            import unicodedata as _ud, re as _re
            def _norm(t):
                t = _ud.normalize('NFKD', t.lower())
                return ''.join(c for c in t if not _ud.combining(c))
            
            # STOPWORDS_TEMA: NO incluir 'libro','libros' ni verbos temáticos —
            # esas palabras son señales útiles para detectar relevancia de contenido
            STOPWORDS_TEMA = {
                'de','la','el','en','los','las','del','al','un','una','por','con','para',
                'que','es','se','no','su','lo','como','mas','pero','sus','le','ya','este',
                'si','ha','son','muy','hay','fue','ser','han','esta','tan','sin','sobre',
                'cual','como','esto','a','y','o','e','u','the','of','and','to','in','me','te','le','nos'
            }
            
            # Si score_max >= 45 es un hit de Fase 1 (documento encontrado por nombre)
            # → SIEMPRE relevante, sin necesidad de calcular overlap
            if score_max >= 45.0:
                resultados['rag_tematica'] = 'relevante'
                logger.info(f"✅ RAG temática AUTO-RELEVANTE (Fase 1 hit, score={score_max:.1f})")
            else:
                # Términos clave del query (palabras significativas de 3+ letras)
                query_norm = _norm(query)
                terminos_query = set(
                    w for w in _re.findall(r'\b\w{3,}\b', query_norm)
                    if w not in STOPWORDS_TEMA
                )
                
                # Términos del contenido de los chunks retornados
                texto_chunks = ' '.join(
                    (item[0] if isinstance(item, tuple) else item)
                    for item in chunks_rag[:10]
                )
                terminos_chunks = set(
                    w for w in _re.findall(r'\b\w{3,}\b', _norm(texto_chunks))
                    if w not in STOPWORDS_TEMA
                )
                
                # Nombres de documentos retornados
                sources_retornados = set()
                for item in chunks_rag:
                    src = (item[1] if isinstance(item, tuple) else '')
                    src_norm = _norm(src.replace('PDF:', '').replace('EXCEL:', '').replace('_', ' '))
                    sources_retornados.update(w for w in src_norm.split() if len(w) >= 3)
                
                # ── Match EXACTO + FUZZY (prefijo 4 chars) ──────────────────────────
                # Cubre: "milley"↔"milei", "kiyosk"↔"kiyosaki", abreviaturas, etc.
                def _fuzzy_overlap(a_set, b_set):
                    matches = set()
                    for a in a_set:
                        for b in b_set:
                            if a == b:
                                matches.add(a)
                                break
                            if len(a) >= 4 and len(b) >= 4:
                                if a.startswith(b[:4]) or b.startswith(a[:4]):
                                    matches.add(a)
                                    break
                    return matches
                
                terminos_en_contenido = _fuzzy_overlap(terminos_query, terminos_chunks)
                terminos_en_sources   = _fuzzy_overlap(terminos_query, sources_retornados)
                overlap_total = terminos_en_contenido | terminos_en_sources
                
                ratio_overlap = len(overlap_total) / max(len(terminos_query), 1)
                
                if ratio_overlap >= 0.3 or len(terminos_en_contenido) >= 2:
                    resultados['rag_tematica'] = 'relevante'
                elif ratio_overlap >= 0.1 or len(terminos_en_sources) >= 1:
                    resultados['rag_tematica'] = 'posible'
                else:
                    resultados['rag_tematica'] = 'irrelevante'
                    resultados['rag_confianza'] = 'irrelevante'
                    logger.info(f"⚠️ RAG temática IRRELEVANTE para '{query[:50]}': "
                               f"overlap={ratio_overlap:.0%}, términos_query={terminos_query}, "
                               f"en_chunks={terminos_en_contenido}, en_sources={terminos_en_sources}")
                
                logger.info(f"📊 RAG temática: {resultados['rag_tematica']} "
                           f"(overlap={ratio_overlap:.0%}, query_terms={terminos_query}, "
                           f"en_contenido={terminos_en_contenido})")
            # ── FIN VERIFICACIÓN ──────────────────────────────────────────────────
            
            resultados['rag'] = chunks_rag
            confianza_str = resultados['rag_confianza']
            resultados['fuentes_usadas'].append(
                f"RAG/Documentos ({len(chunks_rag)} fragmentos, confianza: {confianza_str})"
            )
    except Exception as e:
        logger.warning(f"Error buscando RAG unificado: {e}")
    
    return resultados


def formatear_contexto_unificado(resultados, query):
    """Formatea resultados de búsqueda unificada en contexto para el LLM.
    Incluye el máximo de información posible para respuestas completas."""
    contexto = ""
    
    # RAG (PDFs y documentos) - PRIMERO y con fuente MUY VISIBLE, agrupado por documento
    if resultados.get('rag'):
        # Agrupar chunks por documento fuente
        docs_agrupados = {}
        for item in resultados['rag']:
            if isinstance(item, tuple):
                chunk_texto, chunk_source = item[0], item[1]
            else:
                chunk_texto, chunk_source = item, "documento"
            fuente_key = chunk_source.replace('PDF:', '').replace('EXCEL:', '').strip()
            if fuente_key not in docs_agrupados:
                docs_agrupados[fuente_key] = []
            docs_agrupados[fuente_key].append(chunk_texto)
        
        contexto += "\n\n╔══════════════════════════════════════════════════╗\n"
        contexto += "║  FRAGMENTOS DE DOCUMENTOS INDEXADOS              ║\n"
        contexto += "╚══════════════════════════════════════════════════╝\n\n"
        
        # FASE 3A: instrucción clara y simple (antes: múltiples líneas confusas y negativas)
        nombres_docs = list(docs_agrupados.keys())
        contexto += "Los siguientes fragmentos provienen de estos documentos:\n"
        for nd in nombres_docs:
            contexto += f"  • {nd}\n"
        contexto += "\nLee los fragmentos y extrae la información que responda la consulta.\n\n"
        
        for doc_nombre, chunks in docs_agrupados.items():
            # Título del documento con nombre limpio y visible
            titulo_limpio = doc_nombre.replace('_', ' ').replace('-', ' ')
            # Quitar extensión para mejor legibilidad
            import re as _re
            titulo_limpio = _re.sub(r'\.(pdf|docx?|txt)$', '', titulo_limpio, flags=_re.IGNORECASE)
            contexto += f"{'═'*50}\n"
            contexto += f"📄 DOCUMENTO: \"{titulo_limpio}\"\n"
            contexto += f"   (archivo: {doc_nombre})\n"
            contexto += f"{'─'*50}\n"
            # FASE 9 (revertido): 10 chunks × 700 chars — mantiene contexto completo.
            # Usuario pidió NO reducir chunks porque podría dejar fuera info relevante.
            for i, chunk in enumerate(chunks[:10], 1):
                contexto += f"[Fragmento {i}]:\n{chunk[:700]}\n\n"
            contexto += "\n"
    
    # Historial del grupo (al final, menos prioritario)
    if resultados.get('historial'):
        contexto += "\n\n── CONVERSACIONES DEL GRUPO (referencia) ──\n"
        # FASE 3 FIX: 6 msgs × 350 chars (antes 5×250, muy poco)
        for i, (nombre, texto, fecha) in enumerate(resultados['historial'][:6], 1):
            nombre_limpio = limpiar_nombre_display(nombre) if callable(limpiar_nombre_display) else nombre
            fecha_str = fecha.strftime("%d/%m/%Y") if hasattr(fecha, 'strftime') else str(fecha)[:10]
            contexto += f"{i}. {nombre_limpio} ({fecha_str}): {texto[:350]}\n"
    
    return contexto


# ══════════════════════════════════════════════════════════════════════════════
# BÚSQUEDA MULTI-AGENTE PARALELA — 5 motores simultáneos
# ══════════════════════════════════════════════════════════════════════════════

# ═══════════════════════════════════════════════════════════════════
# FASE 31.7c — WEB → MARKDOWN LIMPIO (pedido de Germán)
# Potencia el motor web: en vez de solo títulos+snippets de DuckDuckGo,
# se descarga el CONTENIDO real de las mejores páginas como markdown
# sin menús/publicidad/scripts.
# MOTORES en cascada:
#   1) crawl4ai — solo si está instalado (INCOMPATIBLE hoy: sus versiones
#      con modo HTTP exigen httpx>=0.27 y python-telegram-bot 20.7 exige
#      httpx~=0.25.2 → ResolutionImpossible en Render). Queda el intento
#      por si en el futuro se actualiza PTB.
#   2) TRAFILATURA — motor PRIMARIO real: librería de referencia para
#      extracción de contenido web (la usan los pipelines de LLM), sin
#      conflicto de dependencias. Verificada: 19.858 chars de contenido
#      puro en la prueba, CERO navegación residual.
#   3) requests + BeautifulSoup — respaldo final (pseudo-markdown).
# ═══════════════════════════════════════════════════════════════════
def _crawl4ai_markdown(url: str, max_chars: int = 3500, timeout: int = 12) -> str:
    """Devuelve el contenido de una URL como markdown limpio ('' si falla).
    Seguro para llamar desde hilos del ThreadPoolExecutor."""
    if not url or not url.startswith('http'):
        return ''
    # ── Intento 1: crawl4ai (markdown de calidad, filtra boilerplate) ──
    try:
        import asyncio as _aio_c4
        from crawl4ai import AsyncWebCrawler, CrawlerRunConfig
        from crawl4ai.async_crawler_strategy import AsyncHTTPCrawlerStrategy

        # FASE 31.7b: filtro de PODA — elimina menús, navegación, footers y
        # publicidad del markdown (verificado con crawl4ai 0.9.0)
        _cfg_kwargs = {'page_timeout': timeout * 1000, 'verbose': False}
        try:
            from crawl4ai.content_filter_strategy import PruningContentFilter
            from crawl4ai.markdown_generation_strategy import DefaultMarkdownGenerator
            _cfg_kwargs['markdown_generator'] = DefaultMarkdownGenerator(
                content_filter=PruningContentFilter(threshold=0.45))
        except Exception:
            pass

        async def _run():
            strategy = AsyncHTTPCrawlerStrategy()
            async with AsyncWebCrawler(crawler_strategy=strategy) as crawler:
                r = await _aio_c4.wait_for(
                    crawler.arun(url=url, config=CrawlerRunConfig(**_cfg_kwargs)),
                    timeout=timeout + 3)
                _mdo = getattr(r, 'markdown', None)
                # Preferir fit_markdown (contenido podado) → raw → string plano
                md = (getattr(_mdo, 'fit_markdown', None)
                      or getattr(_mdo, 'raw_markdown', None)
                      or (_mdo if isinstance(_mdo, str) else ''))
                return (md or '').strip()

        _loop_c4 = _aio_c4.new_event_loop()
        try:
            md = _loop_c4.run_until_complete(_run())
        finally:
            _loop_c4.close()
        if md and len(md) > 120:
            # FASE 31.7b: post-limpieza — fuera banners/sesión/líneas solo-link
            _limpias = []
            for _ln in md.split('\n'):
                _s = _ln.strip()
                if any(_b in _s for _b in ('Skip to content', 'You signed',
                                           'Reload](', 'Toggle navigation',
                                           'Sign in](', 'cookies', 'Cookies')):
                    continue
                # línea que es SOLO un link sin texto útil
                if _s.startswith('[') and _s.endswith(')') and _s.count('](') == 1 \
                        and len(_s.split('](')[0]) <= 4:
                    continue
                _limpias.append(_ln)
            md = '\n'.join(_limpias).strip()
            logger.info(f"🕷️ FASE 31.7 CRAWL4AI: {url[:60]} → {len(md)} chars markdown")
            return md[:max_chars]
    except ImportError:
        logger.debug("crawl4ai no instalado — probando trafilatura")
    except Exception as _e_c4:
        logger.debug(f"crawl4ai {url[:50]}: {_e_c4}")
    # ── Motor 2 (PRIMARIO real): TRAFILATURA — FASE 31.7c ──
    # Descarga con requests (UA Chrome, evita bloqueos del fetcher nativo)
    # y extrae SOLO el contenido principal como markdown.
    try:
        import trafilatura as _traf
        _r_t = requests.get(url, timeout=timeout, headers={
            'User-Agent': ('Mozilla/5.0 (Windows NT 10.0; Win64; x64) '
                           'AppleWebKit/537.36 (KHTML, like Gecko) '
                           'Chrome/124.0.0.0 Safari/537.36'),
            'Accept-Language': 'es-CL,es;q=0.9'})
        if _r_t.status_code == 200 and _r_t.text:
            md_t = _traf.extract(_r_t.text, output_format='markdown',
                                 include_links=False, include_tables=True,
                                 url=url)
            if md_t and len(md_t) > 120:
                logger.info(f"🕷️ FASE 31.7c TRAFILATURA: {url[:60]} → "
                            f"{len(md_t)} chars markdown limpio")
                return md_t.strip()[:max_chars]
    except ImportError:
        logger.debug("trafilatura no instalada — usando fallback BeautifulSoup")
    except Exception as _e_tf:
        logger.debug(f"trafilatura {url[:50]}: {_e_tf}")
    # ── Fallback: requests + BeautifulSoup (pseudo-markdown) ──
    try:
        from bs4 import BeautifulSoup as _BS4f
        r = requests.get(url, timeout=timeout, headers={
            'User-Agent': ('Mozilla/5.0 (Windows NT 10.0; Win64; x64) '
                           'AppleWebKit/537.36 (KHTML, like Gecko) '
                           'Chrome/124.0.0.0 Safari/537.36'),
            'Accept-Language': 'es-CL,es;q=0.9'})
        if r.status_code != 200:
            return ''
        soup = _BS4f(r.text, 'html.parser')
        for tag in soup(['script', 'style', 'nav', 'header', 'footer',
                         'aside', 'form', 'iframe', 'noscript']):
            tag.decompose()
        partes = []
        for el in soup.find_all(['h1', 'h2', 'h3', 'p', 'li'])[:180]:
            t = el.get_text(' ', strip=True)
            if len(t) < 25:
                continue
            if el.name in ('h1', 'h2', 'h3'):
                partes.append('#' * int(el.name[1]) + ' ' + t)
            elif el.name == 'li':
                partes.append('- ' + t)
            else:
                partes.append(t)
        md = '\n\n'.join(partes).strip()
        return md[:max_chars] if len(md) > 120 else ''
    except Exception as _e_bs:
        logger.debug(f"fallback BS4 {url[:50]}: {_e_bs}")
        return ''


def _scrape_ddg_sync(q: str, n: int = 5) -> list:
    """Scraping DuckDuckGo HTML sincrónico para uso en ThreadPoolExecutor."""
    try:
        from bs4 import BeautifulSoup as _BS4
        import urllib.parse as _up
        r = requests.get(
            "https://html.duckduckgo.com/html/",
            params={"q": q, "kl": "cl-es"},
            headers={
                "User-Agent": ("Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
                               "AppleWebKit/537.36 (KHTML, like Gecko) "
                               "Chrome/124.0.0.0 Safari/537.36"),
                "Accept-Language": "es-CL,es;q=0.9,en;q=0.8",
                "Referer": "https://duckduckgo.com/",
            },
            timeout=12, allow_redirects=True,
        )
        if r.status_code != 200:
            return []
        soup = _BS4(r.text, "html.parser")
        resultados = []
        for div in soup.select(".result, .web-result")[:n]:
            a_tag = div.select_one(".result__a, a.result__url, h2 a")
            if not a_tag:
                continue
            titulo = a_tag.get_text(strip=True)
            # FASE 31.9: extraer también la URL real (decodificando uddg de DDG)
            href = a_tag.get("href", "")
            if "uddg=" in href or href.startswith("/l/"):
                _qs = _up.parse_qs(_up.urlparse(href).query)
                href = (_qs.get("uddg", [""])[0] or _qs.get("u", [""])[0] or href)
            snip_tag = div.select_one(".result__snippet")
            snippet = snip_tag.get_text(strip=True) if snip_tag else ""
            if titulo and len(titulo) > 3:
                resultados.append({"titulo": titulo[:120], "snippet": snippet[:350],
                                   "url": href[:300]})
        return resultados
    except Exception as _e:
        logger.debug(f"DDG sync scrape: {_e}")
        return []


# ═══════════════════════════════════════════════════════════════════
# FASE 31.9 — BÚSQUEDA WEB PROFUNDA + RESPALDO EN CONOCIMIENTOS
# (1) Cuando RAG + historial NO tienen la respuesta → buscar en Internet
#     (DuckDuckGo + Trafilatura markdown) para que el usuario SIEMPRE
#     reciba una respuesta completa.
# (2) Si el usuario marca "Útil" una respuesta web → se respalda como
#     markdown en rag_chunks (con embedding) y pasa a ser conocimiento
#     permanente del bot.
# (3) Archivos compartidos → referencia markdown (nombre, descripción,
#     quién y cuándo) consultable por el RAG.
# ═══════════════════════════════════════════════════════════════════
def _busqueda_web_profunda(query: str, max_paginas: int = 2) -> dict:
    """DDG → top resultados → Trafilatura sobre las mejores páginas.
    Devuelve {'items': [(markdown, 'WEB-LIVE:dominio')], 'urls': [...],
    'markdown': str_completo} o items vacíos si no hay red/resultados."""
    out = {'items': [], 'urls': [], 'markdown': ''}
    try:
        res = _scrape_ddg_sync(query, n=5)
        if not res:
            return out
        import urllib.parse as _up9
        partes_md = []
        for r in res:
            if len(out['items']) >= max_paginas:
                break
            _u = r.get('url', '')
            if not _u.startswith('http'):
                continue
            md = _crawl4ai_markdown(_u, max_chars=2600, timeout=9)
            if md and len(md) > 200:
                _dom = _up9.urlparse(_u).netloc.replace('www.', '')[:40]
                out['items'].append((md, f"WEB-LIVE:{_dom}"))
                out['urls'].append(_u)
                partes_md.append(f"### {r.get('titulo','')[:90]}\n"
                                 f"Fuente: {_u}\n\n{md}")
        # respaldo: si ninguna página dio contenido, usar los snippets DDG
        if not out['items']:
            _snips = "\n".join(f"- {r['titulo']}: {r['snippet']}"
                                for r in res[:4] if r.get('snippet'))
            if len(_snips) > 120:
                out['items'].append((_snips, "WEB-LIVE:duckduckgo"))
                partes_md.append(_snips)
        out['markdown'] = "\n\n".join(partes_md)[:9000]
        if out['items']:
            logger.info(f"🌐 FASE 31.9 WEB PROFUNDA: {len(out['items'])} fuentes "
                        f"para '{query[:50]}'")
    except Exception as e:
        logger.debug(f"web profunda: {e}")
    return out


def _guardar_web_en_rag(pregunta: str, respuesta: str, web_md: str,
                        urls: list) -> int:
    """FASE 31.9: transforma una respuesta web validada como "Útil" en
    conocimiento PERMANENTE: documento markdown → chunks con embedding en
    rag_chunks. La próxima vez el bot responde desde su propia base."""
    try:
        from datetime import datetime as _dt9
        _fecha = _dt9.now().strftime('%Y-%m-%d')
        _titulo = ' '.join(pregunta.split()[:8])[:70]
        source = f"WEB:{_titulo} ({_fecha})"
        doc_md = (f"# {pregunta.strip()[:200]}\n\n"
                  f"*Conocimiento validado por la comunidad el {_fecha} "
                  f"(botón Útil) — origen: búsqueda web en tiempo real.*\n\n"
                  f"## Respuesta validada\n\n{(respuesta or '').strip()}\n\n"
                  f"## Contenido de las fuentes\n\n{(web_md or '').strip()}\n\n"
                  f"## Fuentes\n" + "\n".join(f"- {u}" for u in (urls or [])[:4]))
        # chunks de ~900 chars (máx 6) con solape ligero
        chunks, _i = [], 0
        while _i < len(doc_md) and len(chunks) < 6:
            chunks.append(doc_md[_i:_i + 900])
            _i += 820
        _kw = ' '.join(sorted({w.lower() for w in pregunta.split()
                               if len(w) >= 4}))[:300]
        conn = get_db_connection()
        c = conn.cursor()
        creados = 0
        for idx, ch in enumerate(chunks):
            metadata = json.dumps({'tipo': 'web_util', 'fecha': _fecha,
                                   'urls': (urls or [])[:4],
                                   'chunk_index': idx,
                                   'total_chunks': len(chunks)})
            if DATABASE_URL:
                emb = generar_embedding_gemini(ch, tipo='RETRIEVAL_DOCUMENT')
                if emb:
                    try:
                        c.execute("""INSERT INTO rag_chunks
                                     (source, chunk_text, metadata, keywords, embedding)
                                     VALUES (%s, %s, %s, %s, %s::vector)""",
                                  (source, ch, metadata, _kw,
                                   embedding_to_pgvector(emb)))
                    except Exception:
                        conn.rollback()
                        c.execute("""INSERT INTO rag_chunks
                                     (source, chunk_text, metadata, keywords)
                                     VALUES (%s, %s, %s, %s)""",
                                  (source, ch, metadata, _kw))
                else:
                    c.execute("""INSERT INTO rag_chunks
                                 (source, chunk_text, metadata, keywords)
                                 VALUES (%s, %s, %s, %s)""",
                              (source, ch, metadata, _kw))
            else:
                c.execute("""INSERT INTO rag_chunks
                             (source, chunk_text, metadata, keywords)
                             VALUES (?, ?, ?, ?)""",
                          (source, ch, metadata, _kw))
            creados += 1
        conn.commit()
        conn.close()
        logger.info(f"💾 FASE 31.9 RESPALDO WEB→RAG: '{source}' "
                    f"({creados} chunks markdown)")
        return creados
    except Exception as e:
        logger.error(f"guardar web en rag: {e}")
        return 0


async def registrar_archivo_compartido(update, context):
    """FASE 31.9: cuando un usuario comparte un archivo, NO se respalda el
    archivo — se registra una REFERENCIA markdown (nombre, descripción,
    quién y fecha) consultable por el RAG: "¿quién compartió X?"."""
    try:
        m = update.effective_message
        doc = m.document if m else None
        if not doc or not doc.file_name:
            return
        filename = doc.file_name
        # Los PDF en privado ya tienen su propio flujo de indexación completa
        if (update.effective_chat and update.effective_chat.type == 'private'
                and filename.lower().endswith('.pdf')):
            return
        u = update.effective_user
        quien = (f"{u.first_name or ''} {u.last_name or ''}".strip()
                 or (u.username or 'desconocido')) if u else 'desconocido'
        from datetime import datetime as _dtA
        fecha = _dtA.now().strftime('%d-%m-%Y %H:%M')
        descripcion = (m.caption or '').strip() or 'sin descripción'
        ref_md = (f"## Archivo compartido: {filename}\n"
                  f"- **Descripción del usuario**: {descripcion[:500]}\n"
                  f"- **Compartido por**: {quien}\n"
                  f"- **Fecha**: {fecha}\n"
                  f"- **Formato**: {(filename.rsplit('.', 1)[-1] if '.' in filename else '?').upper()}")
        _kw = ' '.join(sorted({w.lower() for w in
                               f"{filename.replace('.', ' ').replace('_', ' ').replace('-', ' ')} {descripcion}".split()
                               if len(w) >= 4}))[:300]
        metadata = json.dumps({'tipo': 'referencia_archivo',
                               'filename': filename, 'usuario': quien,
                               'fecha': fecha})

        def _insertar_ref():
            conn = get_db_connection()
            c = conn.cursor()
            source = "REF:archivos compartidos por la comunidad"
            if DATABASE_URL:
                emb = generar_embedding_gemini(ref_md, tipo='RETRIEVAL_DOCUMENT')
                if emb:
                    try:
                        c.execute("""INSERT INTO rag_chunks
                                     (source, chunk_text, metadata, keywords, embedding)
                                     VALUES (%s, %s, %s, %s, %s::vector)""",
                                  (source, ref_md, metadata, _kw,
                                   embedding_to_pgvector(emb)))
                    except Exception:
                        conn.rollback()
                        c.execute("""INSERT INTO rag_chunks
                                     (source, chunk_text, metadata, keywords)
                                     VALUES (%s, %s, %s, %s)""",
                                  (source, ref_md, metadata, _kw))
                else:
                    c.execute("""INSERT INTO rag_chunks
                                 (source, chunk_text, metadata, keywords)
                                 VALUES (%s, %s, %s, %s)""",
                              (source, ref_md, metadata, _kw))
            else:
                c.execute("""INSERT INTO rag_chunks
                             (source, chunk_text, metadata, keywords)
                             VALUES (?, ?, ?, ?)""",
                          (source, ref_md, metadata, _kw))
            conn.commit()
            conn.close()

        await asyncio.to_thread(_insertar_ref)
        logger.info(f"📎 FASE 31.9 REFERENCIA: '{filename}' de {quien} registrada")
    except Exception as e:
        logger.debug(f"registrar archivo compartido: {e}")


def busqueda_multiagente_paralela(query: str, *, limit_rag: int = 20,
                                   limit_hist: int = 10) -> dict:
    """
    Ejecuta 4 motores de búsqueda en PARALELO (ThreadPoolExecutor) y combina
    los resultados en un dict enriquecido compatible con formatear_contexto_unificado.

    Motor 1 — RAG/vectorial  : documentos e‑books indexados en BD
    Motor 2 — Historial       : conversaciones del grupo
    Motor 3 — Directorio      : tarjetas profesionales Cofradía
    Motor 4 — Web DDG         : DuckDuckGo sin API key
    
    FASE 3A: eliminado Motor 5 (LLM-hint) porque duplicaba trabajo (Groq llamado 2 veces)
    y sumaba 12s al tiempo total sin aportar valor real.
    """
    from concurrent.futures import ThreadPoolExecutor as _TPE_ma

    resultado = {
        'historial': [], 'rag': [], 'tarjetas': [], 'web': [], 'llm_hint': '',
        'fuentes_usadas': [], 'rag_score_max': 0.0,
        'rag_confianza': 'ninguna', 'rag_tematica': 'desconocida',
        'agentes_ok': [],
    }

    # ── Motor 3: tarjetas profesionales (función interna) ──────────────────
    def _motor_tarjetas(q: str) -> list:
        try:
            conn_t = get_db_connection()
            if not conn_t:
                return []
            ct = conn_t.cursor()
            palabras = [p for p in q.lower().split() if len(p) > 3][:5]
            if not palabras:
                conn_t.close()
                return []
            partes_cond, params_t = [], []
            for p in palabras:
                if DATABASE_URL:
                    partes_cond.append(
                        "(LOWER(nombre_completo) LIKE %s OR LOWER(profesion) LIKE %s "
                        "OR LOWER(empresa) LIKE %s OR LOWER(servicios) LIKE %s)")
                    params_t.extend([f'%{p}%'] * 4)
                else:
                    partes_cond.append(
                        "(LOWER(nombre_completo) LIKE ? OR LOWER(profesion) LIKE ? "
                        "OR LOWER(empresa) LIKE ? OR LOWER(servicios) LIKE ?)")
                    params_t.extend([f'%{p}%'] * 4)
            ct.execute(
                f"SELECT nombre_completo, profesion, empresa, ciudad, servicios "
                f"FROM tarjetas_profesional WHERE {' OR '.join(partes_cond)} LIMIT 6",
                params_t)
            filas = ct.fetchall()
            conn_t.close()
            out = []
            for f in filas:
                if DATABASE_URL:
                    out.append(f"{f['nombre_completo']} — {f['profesion']} en "
                               f"{f['empresa']} ({f['ciudad']}): {f['servicios']}")
                else:
                    out.append(f"{f[0]} — {f[1]} en {f[2]} ({f[3]}): {f[4]}")
            return out
        except Exception as _e:
            logger.debug(f"Motor tarjetas MA: {_e}")
            return []

    # ── Motor 5: micro‑consulta LLM (ancla conocimiento propio) ───────────
    # FASE 3A: DESHABILITADO - duplicaba trabajo y sumaba 12s sin aporte real.
    # El LLM principal ya tiene conocimiento propio suficiente.
    def _motor_llm_hint(q: str) -> str:
        return ''  # Siempre vacío - deshabilitado en Fase 3A

    # ── Lanzar los motores en paralelo ────────────────────────────────────
    # FASE 3A: 4 motores (eliminado LLM-hint redundante)
    # FASE 3C: buscar_rag_expandido usa query expansion internamente para mejor recall
    with _TPE_ma(max_workers=4) as pool:
        fut_rag  = pool.submit(buscar_rag_expandido, query, limit_rag)
        fut_hist = pool.submit(buscar_en_historial, query, limit=limit_hist)
        fut_tar  = pool.submit(_motor_tarjetas, query)
        fut_web  = pool.submit(_scrape_ddg_sync, query, 5)

        # Recolectar — cada motor tiene su propio timeout
        try:
            chunks_rag, score_max = fut_rag.result(timeout=18)  # +4s para dar margen a query expansion
            resultado['rag'] = chunks_rag
            resultado['rag_score_max'] = score_max
            if chunks_rag:
                resultado['agentes_ok'].append('RAG')
        except Exception as _e:
            logger.debug(f"Motor RAG MA: {_e}")

        try:
            hist = fut_hist.result(timeout=10)
            if hist:
                resultado['historial'] = hist
                resultado['agentes_ok'].append('Historial')
        except Exception as _e:
            logger.debug(f"Motor Historial MA: {_e}")

        try:
            tar = fut_tar.result(timeout=8)
            if tar:
                resultado['tarjetas'] = tar
                resultado['agentes_ok'].append('Directorio')
        except Exception as _e:
            logger.debug(f"Motor Directorio MA: {_e}")

        try:
            web = fut_web.result(timeout=10)  # Reducido de 16 a 10s
            if web:
                resultado['web'] = web
                resultado['agentes_ok'].append('Web')
        except Exception as _e:
            logger.debug(f"Motor Web MA: {_e}")

    # ── FASE 3B: Re-ranking con LLM ──────────────────────────────────────
    # Toma los chunks del RAG y usa el LLM para identificar los más relevantes.
    # Esto resuelve el problema de que "encuentra info pero responde mal":
    # el LLM ya no recibe 20 chunks mezclados, recibe 8 chunks bien elegidos.
    # FASE 3 FIX: top_k aumentado de 5 a 8 para dar mas material de citacion
    if resultado['rag'] and len(resultado['rag']) > 8:
        try:
            rag_reranked = rerank_chunks_con_llm(query, resultado['rag'], top_k=8)
            if rag_reranked:
                resultado['rag'] = rag_reranked
                resultado['agentes_ok'].append('Rerank')
        except Exception as _e_rr:
            logger.warning(f"Rerank falló, usando orden original: {_e_rr}")

    # ── Calcular confianza RAG ─────────────────────────────────────────────
    sm = resultado['rag_score_max']
    if sm >= 45.0:
        resultado['rag_confianza'] = 'alta'
        resultado['rag_tematica']  = 'relevante'   # Fase 1 hit → siempre relevante
    elif sm >= 8.0:
        resultado['rag_confianza'] = 'alta'
    elif sm >= 4.0:
        resultado['rag_confianza'] = 'media'
    elif sm >= 1.5:
        resultado['rag_confianza'] = 'baja'

    # Verificación temática con fuzzy matching (solo si Fase 1 no ya determinó)
    if resultado['rag'] and resultado['rag_tematica'] == 'desconocida':
        import unicodedata as _ud_ma, re as _re_ma
        def _n(t):
            t = _ud_ma.normalize('NFKD', t.lower())
            return ''.join(c for c in t if not _ud_ma.combining(c))
        SW = {'de','la','el','en','los','las','del','al','un','una','por','con','para',
              'que','es','se','no','su','lo','como','mas','pero','sus','le','ya','este',
              'si','ha','son','muy','hay','fue','ser','han','esta','tan','sin','sobre',
              'cual','como','esto','a','y','o','e','u','the','of','and','to','in','me','te','nos'}
        terms_q = set(w for w in _re_ma.findall(r'\b\w{3,}\b', _n(query)) if w not in SW)
        txt_c = ' '.join((i[0] if isinstance(i, tuple) else i) for i in resultado['rag'][:10])
        terms_c = set(w for w in _re_ma.findall(r'\b\w{3,}\b', _n(txt_c)) if w not in SW)
        src_set = set()
        for item in resultado['rag']:
            src = (item[1] if isinstance(item, tuple) else '')
            src_n = _n(src.replace('PDF:', '').replace('EXCEL:', '').replace('_', ' '))
            src_set.update(w for w in src_n.split() if len(w) >= 3)

        def _fm(a_set, b_set):
            m = set()
            for a in a_set:
                for b in b_set:
                    if a == b or (len(a) >= 4 and len(b) >= 4 and
                                  (a.startswith(b[:4]) or b.startswith(a[:4]))):
                        m.add(a); break
            return m

        mc = _fm(terms_q, terms_c)
        ms = _fm(terms_q, src_set)
        ratio = len(mc | ms) / max(len(terms_q), 1)
        if ratio >= 0.3 or len(mc) >= 2:
            resultado['rag_tematica'] = 'relevante'
        elif ratio >= 0.1 or len(ms) >= 1:
            resultado['rag_tematica'] = 'posible'
        else:
            resultado['rag_tematica'] = 'irrelevante'
            resultado['rag_confianza'] = 'irrelevante'

    # ── Construir fuentes_usadas ───────────────────────────────────────────
    if resultado['historial']:
        resultado['fuentes_usadas'].append(f"Historial ({len(resultado['historial'])} msgs)")
    if resultado['rag']:
        resultado['fuentes_usadas'].append(
            f"RAG ({len(resultado['rag'])} fragmentos, confianza: {resultado['rag_confianza']})")
    if resultado['tarjetas']:
        resultado['fuentes_usadas'].append(f"Directorio ({len(resultado['tarjetas'])} profesionales)")
    if resultado['web']:
        resultado['fuentes_usadas'].append(f"Web DDG ({len(resultado['web'])} resultados)")
    if resultado['llm_hint']:
        resultado['fuentes_usadas'].append("Conocimiento LLM")

    logger.info(f"🤖 Multi-agente '{query[:45]}': motores={resultado['agentes_ok']}, "
                f"rag_conf={resultado['rag_confianza']}, rag_tema={resultado['rag_tematica']}")
    return resultado


def formatear_contexto_multiagente(res: dict, query: str) -> str:
    """
    Formatea el resultado de busqueda_multiagente_paralela en un bloque de contexto
    amplio y estructurado para el LLM. Incluye RAG, historial, tarjetas, web y hint.
    """
    ctx = formatear_contexto_unificado(res, query)  # RAG + historial base

    if res.get('tarjetas'):
        ctx += "\n\n── DIRECTORIO COFRADÍA (profesionales relacionados) ──\n"
        for t in res['tarjetas'][:5]:
            ctx += f"  • {t}\n"

    if res.get('web'):
        ctx += "\n\n── RESULTADOS WEB (DuckDuckGo) ──\n"
        for i, w in enumerate(res['web'][:4], 1):
            ctx += f"  [{i}] {w['titulo']}\n"
            if w.get('snippet'):
                ctx += f"      {w['snippet'][:280]}\n"

    if res.get('llm_hint'):
        ctx += f"\n\n── CONOCIMIENTO PROPIO LLM ──\n{res['llm_hint']}\n"

    return ctx


async def indexar_rag_job(context: ContextTypes.DEFAULT_TYPE):
    """Job programado para re-indexar RAG cada 6 horas.
    SOLO re-indexa Excel. Los PDFs se preservan en la BD.
    """
    logger.info("🔄 Ejecutando re-indexación RAG (solo Excel, PDFs preservados)...")
    
    # Contar PDFs antes para verificar que no se pierdan
    try:
        conn = get_db_connection()
        if conn:
            c = conn.cursor()
            if DATABASE_URL:
                c.execute("SELECT COUNT(*) as total FROM rag_chunks WHERE source LIKE 'PDF:%%'")
                pdfs_antes = int(c.fetchone()['total'] or 0)
            else:
                c.execute("SELECT COUNT(*) as total FROM rag_chunks WHERE source LIKE 'PDF:%'")
                pdfs_antes = c.fetchone()[0] if c.fetchone() else 0
            conn.close()
            logger.info(f"🔒 PDFs en BD antes de re-indexar Excel: {pdfs_antes} chunks")
    except:
        pdfs_antes = -1
    
    # 1. Re-indexar SOLO Excel de BD Grupo Laboral (NO borra PDFs)
    indexar_google_drive_rag()
    
    # 2. Verificar PDFs siguen intactos
    try:
        conn = get_db_connection()
        if conn:
            c = conn.cursor()
            if DATABASE_URL:
                c.execute("SELECT COUNT(*) as total FROM rag_chunks WHERE source LIKE 'PDF:%%'")
                pdfs_despues = int(c.fetchone()['total'] or 0)
            else:
                c.execute("SELECT COUNT(*) as total FROM rag_chunks WHERE source LIKE 'PDF:%'")
                pdfs_despues = c.fetchone()[0] if c.fetchone() else 0
            conn.close()
            logger.info(f"🔒 PDFs en BD después de re-indexar: {pdfs_despues} chunks (antes: {pdfs_antes})")
            if pdfs_antes > 0 and pdfs_despues < pdfs_antes:
                logger.error(f"⚠️ ALERTA: Se perdieron chunks de PDFs! Antes={pdfs_antes}, Después={pdfs_despues}")
    except Exception as e:
        logger.warning(f"Error verificando PDFs: {e}")


# ==================== SCRAPER SEC (SUPERINTENDENCIA ELECTRICIDAD Y COMBUSTIBLES) ====================

def buscar_especialista_sec(especialidad, ciudad=""):
    """
    Busca especialistas certificados en la SEC (Chile).
    Intenta scraping del buscador SEC, con fallback a links directos.
    """
    try:
        ESPECIALIDADES_SEC = {
            'electricista': ('E', 'Electrico'),
            'electrico': ('E', 'Electrico'),
            'electrica': ('E', 'Electrico'),
            'instalador electrico': ('E', 'Electrico'),
            'gas': ('G', 'Gas'),
            'gasfiter': ('G', 'Gas'),
            'gasfíter': ('G', 'Gas'),
            'instalador gas': ('G', 'Gas'),
            'combustible': ('E', 'Combustibles'),
            'combustibles': ('E', 'Combustibles'),
        }
        
        # Mapeo de ciudades/comunas a códigos de región SEC
        REGIONES_SEC = {
            'arica': ('15', 'Arica y Parinacota'),
            'iquique': ('01', 'Tarapaca'),
            'antofagasta': ('02', 'Antofagasta'),
            'copiapo': ('03', 'Atacama'),
            'la serena': ('04', 'Coquimbo'),
            'coquimbo': ('04', 'Coquimbo'),
            'valparaiso': ('05', 'Valparaiso'),
            'viña del mar': ('05', 'Valparaiso'),
            'viña': ('05', 'Valparaiso'),
            'rancagua': ('06', "O'Higgins"),
            'talca': ('07', 'Maule'),
            'concepcion': ('08', 'Biobio'),
            'chillan': ('16', 'Nuble'),
            'temuco': ('09', 'La Araucania'),
            'valdivia': ('14', 'Los Rios'),
            'puerto montt': ('10', 'Los Lagos'),
            'osorno': ('10', 'Los Lagos'),
            'coyhaique': ('11', 'Aysen'),
            'punta arenas': ('12', 'Magallanes'),
            'santiago': ('13', 'Metropolitana'),
            'providencia': ('13', 'Metropolitana'),
            'las condes': ('13', 'Metropolitana'),
            'maipu': ('13', 'Metropolitana'),
            'puente alto': ('13', 'Metropolitana'),
            'la florida': ('13', 'Metropolitana'),
            'ñuñoa': ('13', 'Metropolitana'),
            'nunoa': ('13', 'Metropolitana'),
            'san bernardo': ('13', 'Metropolitana'),
            'quilpue': ('05', 'Valparaiso'),
        }
        
        esp_lower = especialidad.lower().strip()
        tipo_inst = None
        tipo_nombre = ''
        for key, (code, nombre) in ESPECIALIDADES_SEC.items():
            if key in esp_lower:
                tipo_inst = code
                tipo_nombre = nombre
                break
        
        if not tipo_inst:
            tipo_inst = 'E'
            tipo_nombre = 'Electrico'
        
        # Detectar región
        region_code = None
        region_nombre = ''
        ciudad_lower = ciudad.lower().strip() if ciudad else ''
        for key, (code, nombre) in REGIONES_SEC.items():
            if key in ciudad_lower:
                region_code = code
                region_nombre = nombre
                break
        
        resultado = "━" * 30 + "\n"
        resultado += "🔍 BUSQUEDA SEC - Especialistas Certificados\n"
        resultado += "━" * 30 + "\n\n"
        resultado += f"📋 Especialidad: {especialidad}\n"
        if ciudad:
            resultado += f"📍 Ciudad/Comuna: {ciudad}\n"
        if region_nombre:
            resultado += f"🗺️ Region: {region_nombre}\n"
        resultado += "\n"
        
        # Intentar scraping real del buscador SEC
        especialistas_encontrados = []
        if bs4_disponible:
            try:
                session = requests.Session()
                session.headers.update({
                    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
                    'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
                    'Accept-Language': 'es-CL,es;q=0.9',
                })
                
                # Intentar el buscador avanzado con parámetros directos
                search_params = {
                    'tipoBusqueda': 'avanzada',
                    'tipoInstalacion': tipo_inst,
                }
                if region_code:
                    search_params['region'] = region_code
                
                buscador_url = "https://wlhttp.sec.cl/buscadorinstaladores/busqueda.do"
                resp = session.get(buscador_url, params=search_params, timeout=20)
                
                if resp.status_code == 200:
                    soup = BeautifulSoup(resp.text, 'html.parser')
                    
                    # Buscar tablas con resultados
                    tables = soup.find_all('table')
                    for table in tables:
                        rows = table.find_all('tr')
                        for row in rows[1:]:  # Saltar header
                            cols = row.find_all('td')
                            if len(cols) >= 3:
                                nombre = cols[0].get_text(strip=True)
                                rut = cols[1].get_text(strip=True) if len(cols) > 1 else ''
                                niveles = cols[2].get_text(strip=True) if len(cols) > 2 else ''
                                telefono = cols[3].get_text(strip=True) if len(cols) > 3 else ''
                                email_col = cols[4].get_text(strip=True) if len(cols) > 4 else ''
                                
                                if nombre and len(nombre) > 2 and nombre.lower() != 'nombre':
                                    especialistas_encontrados.append({
                                        'nombre': nombre,
                                        'rut': rut,
                                        'niveles': niveles,
                                        'telefono': telefono,
                                        'email': email_col
                                    })
                    
                    # Si no encontró tabla, intentar otro formato
                    if not especialistas_encontrados:
                        # Buscar divs o listas con resultados
                        divs = soup.find_all(['div', 'li'], class_=True)
                        for div in divs:
                            text = div.get_text(strip=True)
                            if 'rut' in text.lower() or 'instalador' in text.lower():
                                if len(text) > 10 and len(text) < 500:
                                    especialistas_encontrados.append({
                                        'nombre': text[:100],
                                        'rut': '',
                                        'niveles': '',
                                        'telefono': '',
                                        'email': ''
                                    })
                
                logger.info(f"SEC scraping: encontrados {len(especialistas_encontrados)} resultados")
                
            except Exception as e:
                logger.warning(f"Error scraping SEC: {e}")
        
        # Mostrar resultados encontrados
        if especialistas_encontrados:
            resultado += f"✅ RESULTADOS ENCONTRADOS: {len(especialistas_encontrados)}\n\n"
            for i, esp in enumerate(especialistas_encontrados[:15], 1):
                resultado += f"{i}. {esp['nombre']}\n"
                if esp['rut']:
                    resultado += f"   🆔 RUT: {esp['rut']}\n"
                if esp['niveles']:
                    resultado += f"   📜 Certificacion: {esp['niveles']}\n"
                if esp['telefono']:
                    resultado += f"   📞 Tel: {esp['telefono']}\n"
                if esp['email']:
                    resultado += f"   📧 Email: {esp['email']}\n"
                resultado += "\n"
        else:
            resultado += "⚠️ No se encontraron resultados via scraping.\n"
            resultado += "El buscador SEC requiere navegador web.\n\n"
        
        # Links directos siempre visibles
        resultado += "━" * 30 + "\n"
        resultado += "🌐 CONSULTA DIRECTA EN SEC:\n\n"
        
        resultado += "🔍 Buscador de Instaladores:\n"
        resultado += "   https://wlhttp.sec.cl/buscadorinstaladores/buscador.do\n\n"
        
        resultado += "📋 Validador de Instaladores (por RUT):\n"
        resultado += "   https://wlhttp.sec.cl/validadorInstaladores/\n\n"
        
        resultado += "🏛️ Registro Nacional de Instaladores:\n"
        resultado += "   https://wlhttp.sec.cl/rnii/home\n\n"
        
        resultado += "💡 COMO BUSCAR:\n"
        resultado += f"1. Ingresa a: wlhttp.sec.cl/buscadorinstaladores/buscador.do\n"
        resultado += f"2. Selecciona tipo: {tipo_nombre}\n"
        resultado += "3. Marca los trabajos que necesitas\n"
        if region_nombre:
            resultado += f"4. Region: {region_nombre}\n"
        else:
            resultado += "4. Selecciona tu region\n"
        if ciudad:
            resultado += f"5. Comuna: {ciudad}\n"
        else:
            resultado += "5. Selecciona tu comuna\n"
        resultado += "6. Clic en Buscar\n"
        resultado += "7. Obtendras: Nombre, RUT, Clase, Telefono, Email\n\n"
        
        resultado += "━" * 30 + "\n"
        resultado += "📞 Mesa de ayuda SEC: 600 6000 732\n"
        resultado += "🌐 Web: https://www.sec.cl/"
        
        return resultado
        
    except Exception as e:
        logger.error(f"Error buscando en SEC: {e}")
        return f"❌ Error consultando SEC: {str(e)[:100]}"


@requiere_suscripcion
async def buscar_especialista_sec_comando(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Comando /buscar_especialista_sec - Buscar especialistas certificados SEC"""
    if not context.args:
        await update.message.reply_text(
            "❌ Uso: /buscar_especialista_sec [especialidad], [ciudad]\n\n"
            "Ejemplos:\n"
            "  /buscar_especialista_sec electricista, Santiago\n"
            "  /buscar_especialista_sec gas, Valparaiso\n"
            "  /buscar_especialista_sec gasfiter, Concepcion\n\n"
            "Especialidades: electricista, gas, gasfiter, combustibles"
        )
        return
    
    texto = ' '.join(context.args)
    partes = [p.strip() for p in texto.split(',')]
    especialidad = partes[0]
    ciudad = partes[1] if len(partes) > 1 else ""
    
    msg = await update.message.reply_text(f"🔍 Buscando especialistas SEC: {especialidad}...")
    
    resultado = buscar_especialista_sec(especialidad, ciudad)
    
    await msg.delete()
    await enviar_mensaje_largo(update, resultado, parse_mode=None)
    registrar_servicio_usado(update.effective_user.id, 'buscar_sec')


