# ════════════════════════════════════════════════════════════════════════
# FASE 10 — VELOCIDAD: Caché de intents + llamada Groq rápida con modelo 8b-instant
# Para tareas simples como clasificación de intent, el modelo 8b-instant es 5-10x
# más rápido que 70b-versatile y suficiente. Caché LRU 50 entradas, 10 minutos TTL.
# Esto reduce ~3-5 segundos en la mayoría de respuestas conversacionales.
# ════════════════════════════════════════════════════════════════════════

_FASE10_INTENT_CACHE = {}  # query_norm → (resultado_intent, timestamp)
_FASE10_INTENT_CACHE_MAX = 50
_FASE10_INTENT_CACHE_TTL = 600  # 10 minutos


def _fase10_intent_cache_get(query_norm):
    import time as _t_ic
    e = _FASE10_INTENT_CACHE.get(query_norm)
    if not e:
        return None
    res, ts = e
    if _t_ic.time() - ts > _FASE10_INTENT_CACHE_TTL:
        del _FASE10_INTENT_CACHE[query_norm]
        return None
    return res


def _fase10_intent_cache_set(query_norm, resultado):
    import time as _t_ic
    if len(_FASE10_INTENT_CACHE) >= _FASE10_INTENT_CACHE_MAX:
        oldest = min(_FASE10_INTENT_CACHE.items(), key=lambda x: x[1][1])[0]
        del _FASE10_INTENT_CACHE[oldest]
    _FASE10_INTENT_CACHE[query_norm] = (resultado, _t_ic.time())


def llamar_groq_rapido(prompt: str, max_tokens: int = 300, temperature: float = 0.2) -> str:
    """FASE 10: Versión rápida con modelo 8b-instant. Para intent classification.
    NO reemplaza llamar_groq() — solo se usa en mejorar_intencion y similares."""
    if not GROQ_API_KEY:
        return None
    if not token_budget.can_call():
        return None
    
    headers = {
        "Authorization": f"Bearer {GROQ_API_KEY}",
        "Content-Type": "application/json"
    }
    payload = {
        "model": GROQ_MODEL_RAPIDO,  # 8b-instant: 5-10x más rápido
        "messages": [
            {"role": "system", "content": "Eres un clasificador de intent eficiente. Responde solo lo solicitado."},
            {"role": "user", "content": prompt}
        ],
        "max_tokens": max_tokens,
        "temperature": temperature,
        "frequency_penalty": 0.4
    }
    
    try:
        response = requests.post(GROQ_API_URL, headers=headers, json=payload, timeout=15)
        if response.status_code == 200:
            data = response.json()
            respuesta = data['choices'][0]['message']['content']
            if respuesta and respuesta.strip():
                token_budget.register_call('groq', max_tokens, 'groq')
                return respuesta.strip()
    except Exception as e:
        logger.warning(f"llamar_groq_rapido fallo (caera a llamar_groq normal): {e}")
    return None


def mejorar_intencion(mensaje_raw: str, user_name: str, user_id: int,
                       canal: str = 'texto') -> dict:
    """
    Motor de mejora de intención invisible.
    
    Recibe el mensaje crudo del usuario y retorna:
    {
      'query_mejorada': str,     — Query enriquecida para búsqueda RAG/LLM
      'comando': str | None,     — Comando del bot a ejecutar (o None)
      'args': str,               — Argumentos del comando
      'tipo': str,               — 'consulta' | 'comando' | 'ambos' | 'saludo'
      'ejecutar_comando': bool,  — Si ejecutar el comando automáticamente
      'razon': str,              — Logging interno (no se muestra al usuario)
    }
    
    Todo ocurre en el backend — el usuario solo ve la respuesta final enriquecida.
    """
    try:
        if not mensaje_raw or not mensaje_raw.strip():
            return _intencion_default(mensaje_raw)
        
        mensaje = mensaje_raw.strip()
        
        # Mensajes muy cortos o saludos simples — no procesar con IA
        if len(mensaje) < 8:
            return _intencion_default(mensaje)
        
        palabras = mensaje.lower().split()
        saludos = {'hola', 'hi', 'hey', 'buenas', 'buenos', 'buen', 'gracias', 'ok', 'perfecto'}
        if len(palabras) <= 3 and all(p in saludos for p in palabras):
            return _intencion_default(mensaje, tipo='saludo')
        
        # FASE 10: Cache HIT antes de llamar al LLM (ahorra 3-5s en queries repetidas)
        import unicodedata as _uni_int
        _q_norm = _uni_int.normalize('NFKD', mensaje[:200].lower())
        _q_norm = ''.join(c for c in _q_norm if not _uni_int.combining(c))
        _q_norm = ' '.join(_q_norm.split()[:15])
        cached_intent = _fase10_intent_cache_get(_q_norm)
        if cached_intent is not None:
            logger.info(f"⚡ FASE 10 INTENT cache HIT: '{_q_norm[:50]}'")
            # Devolver copia con el mensaje original (cambia el .original aunque sea mismo intent)
            cached_intent = dict(cached_intent)
            cached_intent['original'] = mensaje
            return cached_intent
        
        # Construir catálogo compacto para el prompt
        catalogo_str = "\n".join([f"  /{cmd}: {desc}" for cmd, desc in CATALOGO_COMANDOS_INTENCION.items()])
        
        # Contexto conversacional (si hay mensajes recientes en grupo)
        conv_context = ""
        try:
            hot = grupo_memory.get_hot_topics(3)
            if hot:
                conv_context = f"\nTEMAS TRENDING EN EL GRUPO: {', '.join([t[0] for t in hot])}"
            recent_users = grupo_memory.get_active_users()
            if recent_users:
                conv_context += f"\nUSUARIOS ACTIVOS: {', '.join([u[0] for u in recent_users[:5]])}"
        except Exception:
            pass
        
        # MCP tools disponibles
        mcp_tools_hint = ""
        try:
            tools = mcp_registry.list_tools()
            if tools:
                mcp_tools_hint = f"\nHERRAMIENTAS MCP DISPONIBLES: {', '.join(tools)}"
        except Exception:
            pass
        
        prompt_intencion = f"""Eres el motor de intención del bot de la Cofradía de Networking (comunidad de oficiales navales chilenos). Tu tarea es analizar el mensaje de un usuario y devolver SOLO un JSON (sin markdown, sin texto adicional).

MENSAJE DEL USUARIO ({canal}): "{mensaje}"
NOMBRE DEL USUARIO: {user_name}{conv_context}{mcp_tools_hint}

COMANDOS DISPONIBLES DEL BOT:
{catalogo_str}

INSTRUCCIONES:
1. "query_mejorada": Reescribe el mensaje en una consulta más específica, técnica y útil para búsqueda semántica. Expande siglas, agrega sinónimos relevantes, clarifica la intención. Mínimo 15 palabras. Usa contexto del grupo si aplica.
2. "comando": Si el mensaje claramente pide algo que un comando puede resolver mejor, pon el nombre del comando (sin /). Si no aplica, pon null. PRIORIZA comandos económicos (economia, indicadores, finanzas) para consultas financieras y empleo/generar_cv para consultas laborales.
3. "args": Argumentos para el comando (ej: para /buscar_profesional sería "finanzas" o "ingenieria"). Si no hay args útiles, pon "".
4. "tipo": "consulta" (quiere información/respuesta), "comando" (claramente quiere ejecutar algo), "ambos" (consulta + usar comando), "saludo" (saludo/chat casual).
5. "ejecutar_comando": true solo si el usuario CLARAMENTE pide una acción específica que el comando resuelve. Para consultas generales donde el comando complementa, pon false.
6. "razon": Una frase corta explicando tu razonamiento (solo para logs internos).
7. "temas_detectados": Lista de temas del mensaje entre: finanzas, empleo, networking, educacion, armada, tecnologia, bienestar. Si no detectas ninguno, lista vacía [].

CRITERIO PARA ejecutar_comando=true: Solo si el usuario dice explícitamente "muéstrame X", "ver X", "buscar X", "quiero saber X" donde X es exactamente lo que hace el comando.
CRITERIO PARA ejecutar_comando=false: Si el usuario hace una pregunta abierta, consulta general, o quiere una respuesta elaborada (aunque un comando aporte contexto).

RESPONDE SOLO EL JSON, sin bloques de código:
{{"query_mejorada": "...", "comando": "..." o null, "args": "...", "tipo": "...", "ejecutar_comando": true/false, "razon": "...", "temas_detectados": [...]}}"""

        # FASE 10: usar modelo 8b-instant (rápido) para clasificación de intent
        respuesta_raw = llamar_groq_rapido(
            prompt_intencion,
            max_tokens=300,
            temperature=0.2
        )
        # Fallback al modelo grande si el rápido falló
        if not respuesta_raw:
            respuesta_raw = llamar_groq(
                prompt_intencion,
                max_tokens=300,
                temperature=0.2
            )
        
        if not respuesta_raw:
            return _intencion_default(mensaje)
        
        # Parsear JSON de respuesta
        import json as _json
        # Limpiar posibles backticks o texto extra
        resp_limpia = respuesta_raw.strip()
        resp_limpia = resp_limpia.replace('```json', '').replace('```', '').strip()
        
        # Encontrar el JSON dentro de la respuesta
        inicio = resp_limpia.find('{')
        fin = resp_limpia.rfind('}')
        if inicio == -1 or fin == -1:
            logger.debug(f"Intent engine: no JSON encontrado en respuesta: {resp_limpia[:100]}")
            return _intencion_default(mensaje)
        
        json_str = resp_limpia[inicio:fin+1]
        datos = _json.loads(json_str)
        
        # Validar y sanear campos
        query_mejorada = datos.get('query_mejorada', mensaje)
        if not query_mejorada or len(query_mejorada.strip()) < 5:
            query_mejorada = mensaje
        
        # ═══════════════════════════════════════════════════════════════════
        # FASE 31.2 — GUARDIA ANTI-CORRUPCIÓN DE NOMBRES PROPIOS (CRÍTICO)
        # Bug real detectado: el LLM reescritor transformó "libro de Milei
        # sobre la inflación" en una consulta sobre "Martín Vizcarra... en
        # Chile" → el RAG buscó a la persona equivocada y toda la respuesta
        # se corrompió. Regla determinística: la reescritura DEBE conservar
        # TODOS los nombres propios del mensaje original y NO puede
        # introducir nombres propios nuevos. Si viola cualquiera de las dos
        # condiciones → se descarta y se usa el mensaje original tal cual.
        # ═══════════════════════════════════════════════════════════════════
        try:
            import unicodedata as _ud_np
            def _np_norm(t):
                t = _ud_np.normalize('NFKD', t.lower())
                return ''.join(c for c in t if not _ud_np.combining(c))
            _COMUNES_CAP = {'el', 'la', 'los', 'las', 'un', 'una', 'de', 'en',
                            'y', 'o', 'que', 'como', 'cuando', 'donde', 'por',
                            'para', 'segun', 'sobre', 'chile', 'cofradia',
                            'bot', 'telegram', 'hola', 'gracias'}
            def _nombres_propios(texto):
                # Palabras capitalizadas que NO inician oración → nombres propios
                nombres = set()
                tokens = texto.split()
                for i, tk in enumerate(tokens):
                    limpio = tk.strip('¿?¡!.,;:()"\'«»')
                    if len(limpio) < 3 or not limpio[0].isupper():
                        continue
                    if i == 0 or tokens[i-1].rstrip().endswith(('.', '?', '!', ':')):
                        continue  # inicio de oración: capital no confiable
                    if _np_norm(limpio) in _COMUNES_CAP:
                        continue
                    nombres.add(_np_norm(limpio))
                return nombres
            
            np_orig = _nombres_propios(mensaje)
            np_mejor = _nombres_propios(query_mejorada)
            q_mej_norm = _np_norm(query_mejorada)
            
            perdidos = {n for n in np_orig if n not in q_mej_norm}
            inventados = np_mejor - np_orig
            if perdidos or inventados:
                logger.warning(
                    f"🛡️ FASE 31.2 GUARDIA NOMBRES: reescritura descartada — "
                    f"perdidos={perdidos or '∅'} inventados={inventados or '∅'} | "
                    f"original='{mensaje[:60]}' | corrupta='{query_mejorada[:60]}'")
                query_mejorada = mensaje
        except Exception as _e_np:
            logger.debug(f"Guardia nombres propios: {_e_np}")
        
        comando = datos.get('comando')
        if comando and comando not in CATALOGO_COMANDOS_INTENCION:
            comando = None  # Ignorar comandos inventados
        
        args = str(datos.get('args', '') or '').strip()
        tipo = datos.get('tipo', 'consulta')
        ejecutar = bool(datos.get('ejecutar_comando', False))
        razon = datos.get('razon', '')
        
        # Seguridad: solo ejecutar automáticamente si hay comando válido
        if ejecutar and not comando:
            ejecutar = False
        
        resultado = {
            'query_mejorada': query_mejorada,
            'comando': comando,
            'args': args,
            'tipo': tipo,
            'ejecutar_comando': ejecutar,
            'razon': razon,
            'original': mensaje,
        }
        
        logger.info(f"🧠 IntentEngine [{user_name}] '{mensaje[:50]}' → "
                   f"tipo={tipo}, cmd={comando}, exec={ejecutar} | {razon}")
        
        # FASE 10: guardar en cache para queries similares futuras
        try:
            _fase10_intent_cache_set(_q_norm, dict(resultado))
        except Exception:
            pass
        
        return resultado
        
    except Exception as e:
        logger.debug(f"IntentEngine error (usando fallback): {e}")
        return _intencion_default(mensaje_raw)


def _intencion_default(mensaje: str, tipo: str = 'consulta') -> dict:
    """Retorna intención por defecto cuando el motor no puede procesar."""
    return {
        'query_mejorada': mensaje,
        'comando': None,
        'args': '',
        'tipo': tipo,
        'ejecutar_comando': False,
        'razon': 'fallback',
        'original': mensaje,
    }


async def ejecutar_comando_desde_intencion(
    comando: str, args: str, update: Update, context: ContextTypes.DEFAULT_TYPE
) -> bool:
    """
    Ejecuta un comando detectado por el motor de intención.
    Retorna True si se ejecutó con éxito, False si no.
    El usuario NO ve ningún mensaje previo - el comando simplemente "sucede".
    """
    try:
        # Mapa de comandos a funciones
        MAPA_FUNCIONES = {
            'buscar_profesional': 'buscar_profesional_comando',
            'buscar_apoyo': 'buscar_apoyo_comando',
            'buscar_especialista_sec': 'buscar_especialista_sec_comando',
            'buscar_ia': 'buscar_ia_comando',
            'rag_consulta': 'rag_consulta_comando',
            'empleo': 'empleo_comando',
            'mi_tarjeta': 'mi_tarjeta_comando',
            'directorio': 'directorio_comando',
            'conectar': 'conectar_comando',
            'mi_perfil': 'mi_perfil_comando',
            'mi_cuenta': 'mi_cuenta_comando',
            'eventos': 'eventos_comando',
            'anuncios': 'anuncios_comando',
            'consultas': 'consultas_comando',
            'consultar': 'consultar_comando',
            'recomendar': 'recomendar_comando',
            'publicar': 'publicar_comando',
            'resumen': 'resumen_comando',
            'resumen_semanal': 'resumen_semanal_comando',
            'resumen_mes': 'resumen_mes_comando',
            'estadisticas': 'estadisticas_comando',
            'graficos': 'graficos_comando',
            'top_usuarios': 'top_usuarios_comando',
            'top10': 'top10_comando',
            'dotacion': 'dotacion_comando',
            'cumpleanos_mes': 'cumpleanos_mes_comando',
            'generar_cv': 'generar_cv_comando',
            'entrevista': 'entrevista_comando',
            'analisis_linkedin': 'analisis_linkedin_comando',
            'finanzas': 'finanzas_comando',
            'mentor': 'mentor_comando',
            'mi_dashboard': 'mi_dashboard_comando',
            'agente': 'agente_networking_comando',
            'match': 'match_networking_comando',
            'briefing': 'briefing_networking_comando',
            'mi_agenda': 'mi_agenda_comando',
            'mis_tareas': 'mis_tareas_comando',
            'mis_coins': 'mis_coins_comando',
            'ayuda': 'ayuda',
        }
        
        nombre_func = MAPA_FUNCIONES.get(comando)
        if not nombre_func:
            return False
        
        # Buscar la función en el scope global
        func = globals().get(nombre_func)
        if not func or not callable(func):
            logger.debug(f"IntentEngine: función '{nombre_func}' no encontrada en globals")
            return False
        
        # Inyectar argumentos y ejecutar
        args_originales = context.args
        context.args = args.split() if args.strip() else []
        
        try:
            await func(update, context)
            logger.info(f"🎯 IntentEngine ejecutó /{comando} {args} automáticamente")
            return True
        finally:
            context.args = args_originales
            
    except Exception as e:
        logger.warning(f"IntentEngine: error ejecutando /{comando}: {e}")
        return False


