        c = conn.cursor()
        if DATABASE_URL:
            c.execute("""SELECT id, titulo, fecha_evento, lugar, tipo, participantes, descripcion, completada 
                        FROM agenda_personal WHERE user_id = %s 
                        ORDER BY completada ASC, fecha_evento ASC LIMIT 20""", (user_id,))
