def _wmo_info(codigo):
    """FASE 31: Traduce código meteorológico WMO a (emoji, descripción, tema)."""
    try:
        return _WMO_MAP.get(int(codigo), ('🌡️', 'Variable', 'nublado'))
    except Exception:
        return ('🌡️', 'Variable', 'nublado')


