async def _emer_interceptar_gps(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """INTERCEPTOR group=-1: captura GPS cuando hay emergencia activa"""
    if context.user_data.get('emer_step') != 'geo':
        return
    if not update.message or not update.message.location:
        return
    lat = update.message.location.latitude
    lon = update.message.location.longitude
    maps_url = f"https://www.google.com/maps?q={lat},{lon}"
    context.user_data['emer_direccion'] = f"📍 GPS: {lat:.6f}, {lon:.6f}"
    context.user_data['emer_maps'] = maps_url
    context.user_data['emer_step'] = None
    logger.info(f"🚨 GPS emergencia: {lat},{lon}")
    await _enviar_alerta_emergencia(update, context)
    raise ApplicationHandlerStop()

async def _emer_interceptar_texto(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """INTERCEPTOR group=-1: captura texto cuando hay emergencia activa"""
    step = context.user_data.get('emer_step')
    if not step or step == 'geo':
        return
    if not update.message or not update.message.text:
        return
    texto = update.message.text.strip()
    if texto.startswith('/'):
        return

    if step == 'descripcion':
        context.user_data['emer_desc'] = texto
        context.user_data['emer_step'] = 'elegir_ubi'
        await update.message.reply_text(
            "✅ Descripción registrada.\n\nAhora indica la ubicación del siniestro:",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton("📍 Geolocalización", callback_data="emer_geo"),
                 InlineKeyboardButton("🏠 Mi Dirección", callback_data="emer_dir")],
            ])
        )
        raise ApplicationHandlerStop()

    elif step == 'direccion':
        import urllib.parse as _up_emer
        dir_q = texto if 'chile' in texto.lower() else texto + ', Chile'
        maps_url = f"https://www.google.com/maps/search/{_up_emer.quote(dir_q)}"
        context.user_data['emer_direccion'] = f"📍 {texto}"
        context.user_data['emer_maps'] = maps_url
        context.user_data['emer_step'] = None
        logger.info(f"🚨 Dirección emergencia: {texto}")
        await _enviar_alerta_emergencia(update, context)
        raise ApplicationHandlerStop()

async def emergencia_tel_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """FASE 31: Callback 131-134 — envía CONTACTO nativo para llamar con 1 toque.

    Telegram no permite botones inline con enlaces tel: (BUTTON_URL_INVALID).
    La vía oficial es send_contact: al tocar la ficha del contacto, el
    teléfono abre su marcador nativo con el botón LLAMAR."""
    query = update.callback_query
    numeros = {
        'emer_tel_131': ('SAMU Ambulancia', '131', '🚑'),
        'emer_tel_132': ('Bomberos', '132', '🚒'),
        'emer_tel_133': ('Carabineros', '133', '🚔'),
        'emer_tel_134': ('PDI Investigaciones', '134', '🔍'),
    }
    info = numeros.get(query.data)
    if not info:
        await query.answer()
        return
    nombre_serv, numero, emoji_serv = info
    try:
        await query.answer(f'📞 Contacto {numero} enviado — tócalo y presiona LLAMAR')
    except Exception:
        pass
    _thread_id = getattr(query.message, 'message_thread_id', None)
    try:
        await context.bot.send_contact(
            chat_id=query.message.chat_id,
            phone_number=numero,
            first_name=f'{emoji_serv} {nombre_serv}',
            last_name=f'({numero})',
            message_thread_id=_thread_id,
        )
        await context.bot.send_message(
            chat_id=query.message.chat_id,
            text=(f'{emoji_serv} {nombre_serv} — {numero}\n'
                  '👆 Toca la ficha de contacto de arriba y presiona 📞 LLAMAR.'),
            message_thread_id=_thread_id,
        )
    except Exception as _et31:
        logger.debug(f'Contacto emergencia: {_et31}')
        try:
            await query.message.reply_text(
                f'📞 {emoji_serv} {nombre_serv}\n\n📱 Marca: {numero}')
        except Exception:
            pass

# FASE 31: _generar_sirena_ogg se CONSERVA como utilidad, pero YA NO se envía
# como nota de voz: Telegram no auto-reproduce audios en el receptor. La
# alarma real es _alarma_sonora_emergencia() (ráfaga de notificaciones).
def _generar_sirena_ogg() -> BytesIO:
    """Genera sirena de emergencia potente (5s, max volumen, oscilacion rapida).
    Intenta convertir a OGG OPUS via ffmpeg (requerido para push-up Telegram).
    Fallback: WAV valido si ffmpeg no esta disponible.
    """
    import struct, wave as _wave, math as _math, shutil as _shutil
    buf = BytesIO()
    sample_rate = 24000
    duration = 5  # 5 segundos para maxima atencion
    n_samples = sample_rate * duration
    w = _wave.open(buf, 'wb')
    w.setnchannels(1)
    w.setsampwidth(2)
    w.setframerate(sample_rate)
    frames = []
    for i in range(n_samples):
        t = i / sample_rate
        # Sirena urgente: oscila rapido entre 600Hz y 1600Hz (3 ciclos/seg)
        freq = 1100 + 500 * _math.sin(2 * _math.pi * 3 * t)
        # Segundo tono superpuesto para mas urgencia
        freq2 = 800 + 300 * _math.sin(2 * _math.pi * 5 * t)
        # Combinar ambos tonos a MAXIMO volumen
        val1 = _math.sin(2 * _math.pi * freq * t)
        val2 = 0.4 * _math.sin(2 * _math.pi * freq2 * t)
        # Envelope: sube rapido, se mantiene fuerte
        env = min(1.0, t * 4) if t < 0.25 else 1.0
        combined = int(32000 * env * (val1 + val2) / 1.4)
        frames.append(struct.pack('<h', max(-32768, min(32767, combined))))
    w.writeframes(b''.join(frames))
    w.close()
    buf.seek(0)
    wav_bytes = buf.read()

    # ── Intentar conversión a OGG OPUS (necesario para voice note Telegram) ──
    # Buscar ffmpeg en paths comunes de Linux/Render
    _ffmpeg_paths = [
        _shutil.which('ffmpeg'),          # PATH del sistema
        '/usr/bin/ffmpeg',
        '/usr/local/bin/ffmpeg',
        '/opt/render/project/bin/ffmpeg',
    ]
    ffmpeg_cmd = next((p for p in _ffmpeg_paths if p and __import__('os').path.isfile(p)), None)

    if ffmpeg_cmd:
        try:
            import subprocess as _sp
            ogg_buf = BytesIO()
            proc = _sp.run(
                [ffmpeg_cmd, '-y', '-i', 'pipe:0',
                 '-c:a', 'libopus', '-b:a', '48k',
                 '-ar', '48000', '-f', 'ogg', 'pipe:1'],
                input=wav_bytes, capture_output=True, timeout=12
            )
            if proc.returncode == 0 and len(proc.stdout) > 200:
                ogg_buf.write(proc.stdout)
                ogg_buf.seek(0)
                ogg_buf.name = "sirena_emergencia.ogg"
                logger.info(f"✅ Sirena OGG OPUS generada ({len(proc.stdout)} bytes) via {ffmpeg_cmd}")
                return ogg_buf
            else:
                logger.warning(f"ffmpeg retorno {proc.returncode}: {proc.stderr[:200]}")
        except Exception as _fe:
            logger.warning(f"ffmpeg sirena: {_fe}")

    # ── Fallback: intentar con pydub si esta disponible ───────────────────
    try:
        from pydub import AudioSegment as _AS
        buf2 = BytesIO(wav_bytes)
        seg = _AS.from_wav(buf2)
        ogg_buf2 = BytesIO()
        seg.export(ogg_buf2, format='ogg', codec='libopus', bitrate='48k')
        ogg_buf2.seek(0)
        if ogg_buf2.getbuffer().nbytes > 200:
            ogg_buf2.name = "sirena_emergencia.ogg"
            logger.info("✅ Sirena OGG generada via pydub")
            return ogg_buf2
    except Exception as _pe:
        logger.debug(f"pydub sirena: {_pe}")

    # ── Ultimo fallback: WAV (Telegram lo acepta como voice note) ─────────
    wav_buf = BytesIO(wav_bytes)
    wav_buf.name = "sirena_emergencia.ogg"   # nombre .ogg fuerza tratamiento como voice
    logger.warning("⚠️ Sirena: usando WAV como fallback (instalar ffmpeg en Render)")
    return wav_buf



async def _enviar_alerta_emergencia(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Envía alerta a grupo + topics + mensaje privado a CADA miembro + owner"""
    user = update.effective_user
    tipo = context.user_data.get('emer_tipo', 'EMERGENCIA')
    hora = context.user_data.get('emer_hora', _ahora_chile().strftime('%H:%M:%S'))
    direccion = context.user_data.get('emer_direccion', 'No especificada')
    maps_url = context.user_data.get('emer_maps', '')
    descripcion = context.user_data.get('emer_desc', '')
    nombre = f"{user.first_name or ''} {user.last_name or ''}".strip() or 'Usuario'

    # Buscar teléfono en Google Drive Excel
    telefono_usuario = ''
    try:
        from oauth2client.service_account import ServiceAccountCredentials
        creds_json = os.environ.get('GOOGLE_DRIVE_CREDS')
        if creds_json:
            creds_dict = json.loads(creds_json)
            scope = ['https://www.googleapis.com/auth/drive.readonly']
            creds = ServiceAccountCredentials.from_json_keyfile_dict(creds_dict, scope)
            headers_auth = {"Authorization": f"Bearer {creds.get_access_token().access_token}"}
            r_files = requests.get("https://www.googleapis.com/drive/v3/files",
                headers=headers_auth,
                params={'q': "name contains 'BD Grupo Laboral' and trashed=false",
                        'fields': 'files(id,name)'}, timeout=10)
            files = r_files.json().get('files', [])
            if files:
                r_dl = requests.get(
                    f"https://www.googleapis.com/drive/v3/files/{files[0]['id']}/export",
                    headers=headers_auth,
                    params={'mimeType': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'},
                    timeout=15)
                if r_dl.status_code == 200:
                    import io as _io_e
                    df = pd.read_excel(_io_e.BytesIO(r_dl.content), header=0)
                    for _, row in df.iterrows():
                        nom_e = str(row.iloc[2] if len(row) > 2 else '').strip().lower()
                        if nom_e and nom_e in nombre.lower():
                            tel = str(row.iloc[5] if len(row) > 5 else '').strip()
                            if tel and tel != 'nan':
                                telefono_usuario = tel
                                break
    except Exception as e:
        logger.debug(f"Error teléfono emergencia: {e}")

    ahora = _ahora_chile()
    try:
        hora_dt = datetime.strptime(hora, '%H:%M:%S').replace(
            year=ahora.year, month=ahora.month, day=ahora.day)
        mins = (ahora - hora_dt).seconds // 60
    except Exception:
        mins = 0

    # Construir alerta
    alerta = (
        f"🔊🔊🔊 ALERTA SONORA 🔊🔊🔊\n"
        f"🚨🚨🚨 EMERGENCIA COFRADÍA 🚨🚨🚨\n{'━' * 30}\n\n"
        f"⚠️ Tipo: {tipo}\n"
        f"👤 Reporta: {nombre}\n"
    )
    if telefono_usuario:
        alerta += f"📱 Teléfono: {telefono_usuario}\n"
    alerta += f"🕐 Hora: {hora} (hace {mins} min)\n\n{direccion}\n"
    if maps_url:
        alerta += f"\n🗺️ VER MAPA: {maps_url}\n"
    if descripcion:
        alerta += f"\n📝 Descripción: {descripcion}\n"
    alerta += (
        f"\n{'━' * 30}\n"
        "🆘 URGENTE!!! ACUDE EN AYUDA SI PUEDES,\n"
        "O PRESTA APOYO LLAMANDO A EMERGENCIAS:\n\n"
        "🚑 131 — Ambulancia (SAMU)\n"
        "🚒 132 — Bomberos\n"
        "🚔 133 — Carabineros\n"
        "🔍 134 — PDI (Investigaciones)\n"
        f"\n{'━' * 30}\n⚓ Cofradía de Networking — Red de Apoyo"
    )

    # Botones: mapa + teléfonos (callback, no tel: URL)
    botones = []
    if maps_url:
        botones.append([InlineKeyboardButton("🗺️ ABRIR MAPA EMERGENCIA", url=maps_url)])
    botones.append([
        InlineKeyboardButton("🚑 131 Ambulancia", callback_data="emer_tel_131"),
        InlineKeyboardButton("🚒 132 Bomberos", callback_data="emer_tel_132")
    ])
    botones.append([
        InlineKeyboardButton("🚔 133 Carabineros", callback_data="emer_tel_133"),
        InlineKeyboardButton("🔍 134 PDI", callback_data="emer_tel_134")
    ])
    tel_kb = InlineKeyboardMarkup(botones)

    # 0. FASE 31: ALARMA SONORA por notificaciones (reemplaza la nota de voz).
    # Telegram no permite auto-reproducir audio en el receptor: la alarma real
    # es la ráfaga de notificaciones + menciones invisibles (suenan incluso
    # con el grupo silenciado). Ver _alarma_sonora_emergencia().
    menciones_emergencia = _obtener_menciones_emergencia(max_usuarios=60)

    # 1. Enviar al grupo principal + topics
    enviados = 0
    if COFRADIA_GROUP_ID:
        # FASE 31: ALARMA SONORA — ráfaga de notificaciones + menciones que
        # rompen el silencio (suenan aunque el grupo esté silenciado)
        await _alarma_sonora_emergencia(
            context, COFRADIA_GROUP_ID, tipo,
            menciones=menciones_emergencia, rafagas=3)
        # Texto de alerta despues (+ PIN con notificación a todo el grupo)
        try:
            _msg_alerta31 = await context.bot.send_message(
                chat_id=COFRADIA_GROUP_ID, text=alerta, reply_markup=tel_kb,
                disable_notification=False)
            enviados += 1
            try:
                await context.bot.pin_chat_message(
                    chat_id=COFRADIA_GROUP_ID,
                    message_id=_msg_alerta31.message_id,
                    disable_notification=False)
            except Exception as _ep31:
                logger.debug(f"Pin emergencia: {_ep31}")
        except Exception as _eg:
            logger.warning(f"Emergencia grupo: {_eg}")
        try:
            conn_t = get_db_connection()
            if conn_t:
                ct = conn_t.cursor()
                ct.execute("SELECT topic_id FROM topics_grupo")
                topics = ct.fetchall()
                conn_t.close()
                for t in topics:
                    tid = t['topic_id'] if DATABASE_URL else t[0]
                    if tid:
                        try:
                            await context.bot.send_message(
                                chat_id=COFRADIA_GROUP_ID, text=alerta,
                                message_thread_id=tid, reply_markup=tel_kb,
                                disable_notification=False)
                            enviados += 1
                        except Exception:
                            pass
        except Exception:
            pass

    # 2. Notificar al owner
    if OWNER_ID:
        try:
            await context.bot.send_message(
                chat_id=OWNER_ID, text=f"🚨 EMERGENCIA REPORTADA\n\n{alerta}",
                reply_markup=tel_kb, disable_notification=False)
        except Exception:
            pass

    # 3. Enviar mensaje privado a CADA miembro activo
    miembros_notificados = 0
    try:
        conn_m = get_db_connection()
        if conn_m:
            cm = conn_m.cursor()
            cm.execute("SELECT user_id FROM suscripciones WHERE estado = 'activo'")
            miembros = cm.fetchall()
            conn_m.close()
            for m in miembros:
                mid = m['user_id'] if DATABASE_URL else m[0]
                if mid and mid != user.id and mid != OWNER_ID:
                    try:
                        # FASE 31: mini-ráfaga de alarma al privado (2 tonos)
                        await _alarma_sonora_emergencia(
                            context, mid, tipo, rafagas=2)
                        # Texto despues
                        await context.bot.send_message(
                            chat_id=mid,
                            text=f"🔊🔊🔊 ALERTA DE EMERGENCIA 🔊🔊🔊\n\n{alerta}",
                            reply_markup=tel_kb,
                            disable_notification=False)
                        miembros_notificados += 1
                    except Exception:
                        pass  # Usuario bloqueó al bot o nunca inició chat
    except Exception as _em:
        logger.debug(f"Error notificando miembros: {_em}")

    logger.info(f"🚨 EMERGENCIA: {tipo} — {nombre} — {enviados} canales, {miembros_notificados} privados")

    # 4. Confirmación al reportante
    confirm = (
        f"✅ ALERTA ENVIADA\n\n"
        f"📡 {enviados} canales del grupo\n"
        f"📱 {miembros_notificados} mensajes privados\n\n"
        f"⚠️ {tipo}\n👤 {nombre}\n🕐 {hora}\n{direccion}\n"
    )
    if maps_url:
        confirm += f"\n🗺️ Mapa: {maps_url}\n"
    confirm += "\n🆘 Números de emergencia:"
    try:
        if update.message:
            await update.message.reply_text(confirm, reply_markup=tel_kb)
        elif update.callback_query and update.callback_query.message:
            await update.callback_query.message.reply_text(confirm, reply_markup=tel_kb)
        else:
            await context.bot.send_message(
                chat_id=update.effective_chat.id, text=confirm, reply_markup=tel_kb)
    except Exception:
        try:
            await context.bot.send_message(
                chat_id=update.effective_user.id, text=confirm, reply_markup=tel_kb)
        except Exception:
            pass

    # Limpiar estado
    for k in ['emer_tipo','emer_hora','emer_direccion','emer_maps','emer_desc','emer_step']:
        context.user_data.pop(k, None)


